-- Poems batch 464
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-57','題春台觀','薛逢','唐','御定全唐诗','yuding','','[]','殿前松柏晦蒼蒼，杏繞仙壇水繞廊。垂露額題精思院，',40,'御定全唐詩/json/548.json','["殿前松柏晦蒼蒼，杏繞仙壇水繞廊。垂露額題精思院，", "便擬尋溪弄花去，洞天誰更待劉郎。"]'),
('yuding-58','春晚東園曉思','薛逢','唐','御定全唐诗','yuding','','[]','劍外春餘日更長，東園留醉樂高張。松杉露滴無情淚，',40,'御定全唐詩/json/548.json','["劍外春餘日更長，東園留醉樂高張。松杉露滴無情淚，", "也知留滯年華晚，爭那樽前樂未央。"]'),
('yuding-59','芙蓉溪送前資州裴使君歸京寧拜戶部裴侍郎','薛逢','唐','御定全唐诗','yuding','','[]','桑柘林枯蕎麥幹，欲分離袂百憂攢。臨溪莫話前途遠，',40,'御定全唐詩/json/548.json','["桑柘林枯蕎麥幹，欲分離袂百憂攢。臨溪莫話前途遠，", "遙知阮巷歸寧日，幾院兒童候馬看。"]'),
('yuding-60','伏聞令公疾愈對見延英，因有賀詩遠封投獻','薛逢','唐','御定全唐诗','yuding','','[]','吉語云云海外傳，令公疾愈起朝天。皇風再扇寰區內，',40,'御定全唐詩/json/548.json','["吉語云云海外傳，令公疾愈起朝天。皇風再扇寰區內，", "陪臣自訝迷津久，願識方舟濟巨川。"]'),
('yuding-61','題獨孤處士村居','薛逢','唐','御定全唐诗','yuding','','[]','江上園廬荊作扉，男驅耕犢婦鳴機。林巒當戶蔦蘿暗，',40,'御定全唐詩/json/548.json','["江上園廬荊作扉，男驅耕犢婦鳴機。林巒當戶蔦蘿暗，", "何如一被風塵染，到老云云相是非。"]'),
('yuding-62','題上皇觀','薛逢','唐','御定全唐诗','yuding','','[]','狂寇窮兵犯帝畿，上皇曾此振戎衣。門前衛士傳清警，',40,'御定全唐詩/json/548.json','["狂寇窮兵犯帝畿，上皇曾此振戎衣。門前衛士傳清警，", "當時丹鳳銜書處，老柏蒼蒼已合圍。"]'),
('yuding-63','奉和僕射相公送東川李支使歸使府夏侯相公','薛逢','唐','御定全唐诗','yuding','','[]','兩地交通布政和，上臺深喜使星過。歡留白日千鐘酒，',40,'御定全唐詩/json/548.json','["兩地交通布政和，上臺深喜使星過。歡留白日千鐘酒，", "平津萬一言卑散，莫忘高松寄女蘿。"]'),
('yuding-64','送封尚書節制興元','薛逢','唐','御定全唐诗','yuding','','[]','大封茅土鎮褒中，醉出都門殺氣雄。陌上晚花迎虎節，',40,'御定全唐詩/json/548.json','["大封茅土鎮褒中，醉出都門殺氣雄。陌上晚花迎虎節，", "欲識真心報天子，滿旗全是發生風。"]'),
('yuding-65','送西川梁常侍之新築龍山城並錫賚兩州刺史及部落酋長等','薛逢','唐','御定全唐诗','yuding','','[]','聖主憂夷貊，屯師剪束欽。皇家思眷佑，星使忽登臨。',168,'御定全唐詩/json/548.json','["聖主憂夷貊，屯師剪束欽。皇家思眷佑，星使忽登臨。", "用命期開國，違天必釁碪。化須均草樹，恩不間飛沈。", "束馬淩蒼壁，捫蘿上碧岑。瘴川風自熱，劍閣氣長陰。", "迅瀨從天急，喬松入地深。仰觀唯一徑，俯瞰即千尋。", "水作新城帶，山為故壘襟。東開洞君聽，南辟納蠻心。", "渥澤濡三部，衣冠化雨林。帶文雕白玉，符理篆黃金。", "鳥道經邛僰，星纏過觜參。回軒如睿獎，休作苦辛吟。"]'),
('yuding-66','河滿子','薛逢','唐','御定全唐诗','yuding','','[]','系馬宮槐老，持杯店菊黃。故交今不見，流恨滿川光。',24,'御定全唐詩/json/548.json','["系馬宮槐老，持杯店菊黃。故交今不見，流恨滿川光。"]'),
('yuding-67','題黃花驛','薛逢','唐','御定全唐诗','yuding','','[]','孤戍迢迢蜀路長，鳥鳴山館客思鄉。',32,'御定全唐詩/json/548.json','["孤戍迢迢蜀路長，鳥鳴山館客思鄉。", "更看絕頂煙霞外，數樹岩花照夕陽。"]'),
('yuding-68','涼州詞','薛逢','唐','御定全唐诗','yuding','','[]','昨夜蕃兵報國仇，沙州都護破涼州。',32,'御定全唐詩/json/548.json','["昨夜蕃兵報國仇，沙州都護破涼州。", "黃河九曲今歸漢，塞外縱橫戰血流。"]'),
('yuding-69','嘉陵江','薛逢','唐','御定全唐诗','yuding','','[]','備問嘉陵江水湄，百川東去爾西之。',32,'御定全唐詩/json/548.json','["備問嘉陵江水湄，百川東去爾西之。", "但教清淺源流在，天路朝宗會有期。"]'),
('yuding-70','觀獵','薛逢','唐','御定全唐诗','yuding','','[]','馬縮寒毛鷹落膘，角弓初暖箭新調。',32,'御定全唐詩/json/548.json','["馬縮寒毛鷹落膘，角弓初暖箭新調。", "平原踏盡無禽出，竟日翻身望碧霄。"]'),
('yuding-71','狼煙','薛逢','唐','御定全唐诗','yuding','','[]','三道狼煙過磧來，受降城上探旗開。',32,'御定全唐詩/json/548.json','["三道狼煙過磧來，受降城上探旗開。", "傳聲卻報邊無事，自是官軍入抄回。"]'),
('yuding-72','俠少年','薛逢','唐','御定全唐诗','yuding','','[]','綠眼胡鷹踏錦鞲，五花驄馬白貂裘。',32,'御定全唐詩/json/548.json','["綠眼胡鷹踏錦鞲，五花驄馬白貂裘。", "往來三市無人識，倒把金鞭上酒樓。"]'),
('yuding-73','感塞','薛逢','唐','御定全唐诗','yuding','','[]','滿塞旌旗鎮上游，各分天子一方憂。',32,'御定全唐詩/json/548.json','["滿塞旌旗鎮上游，各分天子一方憂。", "無因得見歌舒翰，可惜西山十八州。"]'),
('yuding-74','聽曹剛彈琵琶','薛逢','唐','御定全唐诗','yuding','','[]','禁曲新翻下玉都，四弦掁觸五音殊。',32,'御定全唐詩/json/548.json','["禁曲新翻下玉都，四弦掁觸五音殊。", "不知天上彈多少，金鳳銜花尾半無。"]'),
('yuding-75','定山寺','薛逢','唐','御定全唐诗','yuding','','[]','十裏松蘿映碧苔，一川晴色鏡中開。',32,'御定全唐詩/json/548.json','["十裏松蘿映碧苔，一川晴色鏡中開。", "遙聞上界翻經處，片片香雲出院來。"]'),
('yuding-76','越王樓送高梓州入朝','薛逢','唐','御定全唐诗','yuding','','[]','乘遞初登建外州，傾心喜事富人侯。讓當遊藝依仁日，',40,'御定全唐詩/json/548.json','["乘遞初登建外州，傾心喜事富人侯。讓當遊藝依仁日，", "欲知恨戀情深處，聽取長江旦暮流。"]'),
('yuding-77','《送李蘊赴鄭州因獻盧郎中','薛逢','唐','御定全唐诗','yuding','','[]','僕射陂西想到時，滿川晴色見旌旗。馬融閑臥笛聲遠，',40,'御定全唐詩/json/548.json','["僕射陂西想到時，滿川晴色見旌旗。馬融閑臥笛聲遠，", "唯君此去人多羨，卻是恩深自不知。"]'),
('yuding-78','送裴評事','薛逢','唐','御定全唐诗','yuding','','[]','塞垣從事識兵機，只擬平戎不擬歸。入夜笳聲含白髮，',40,'御定全唐詩/json/548.json','["塞垣從事識兵機，只擬平戎不擬歸。入夜笳聲含白髮，", "此別不應書斷絕，滿天霜雪有鴻飛。"]'),
('yuding-79','送沈單作尉江都','薛逢','唐','御定全唐诗','yuding','','[]','煬帝都城春水邊，笙歌夜上木蘭船。三千宮女自塗地，',40,'御定全唐詩/json/548.json','["煬帝都城春水邊，笙歌夜上木蘭船。三千宮女自塗地，", "少年作尉須矜慎，莫向樓前墜馬鞭。"]'),
('yuding-80','送薛耽先輩歸謁漢南','薛逢','唐','御定全唐诗','yuding','','[]','雲繞千峰驛路長，謝家聯句待檀郎。手持碧落新攀桂，',40,'御定全唐詩/json/548.json','["雲繞千峰驛路長，謝家聯句待檀郎。手持碧落新攀桂，", "孔門多少風流處，不遣顏回識醉鄉。"]'),
('yuding-81','送同年鄭祥先輩歸漢南','薛逢','唐','御定全唐诗','yuding','','[]','年來驚喜兩心知，高處同攀次第枝。人倚繡屏閑賞夜，',40,'御定全唐詩/json/548.json','["年來驚喜兩心知，高處同攀次第枝。人倚繡屏閑賞夜，", "家去恩門四千里，只應從此夢旌旗。"]'),
('yuding-82','李先輩擢第東歸有贈送','薛逢','唐','御定全唐诗','yuding','','[]','金榜前頭無是非，平人分得一枝歸。正憐日暖雲飄路，',40,'御定全唐詩/json/548.json','["金榜前頭無是非，平人分得一枝歸。正憐日暖雲飄路，", "茂陵自笑猶多病，空有書齋在翠微。"]'),
('yuding-83','送韓絳歸淮南寄韓綽先輩','薛逢','唐','御定全唐诗','yuding','','[]','島上花枝系釣船，隋家宮畔水連天。江帆自落鳥飛外，',40,'御定全唐詩/json/548.json','["島上花枝系釣船，隋家宮畔水連天。江帆自落鳥飛外，", "相逢且問昭州事，曾鼓莊盆對逝川。"]'),
('yuding-84','送盧緘歸揚州','薛逢','唐','御定全唐诗','yuding','','[]','曾向雷塘寄掩扉，荀家燈火有餘輝。關河日暮望空極，',40,'御定全唐詩/json/548.json','["曾向雷塘寄掩扉，荀家燈火有餘輝。關河日暮望空極，", "今年春色還相誤，為我江邊謝釣磯。"]'),
('yuding-85','送剡客','薛逢','唐','御定全唐诗','yuding','','[]','兩重江外片帆斜，數裏林塘繞一家。門掩右軍餘水石，',40,'御定全唐詩/json/548.json','["兩重江外片帆斜，數裏林塘繞一家。門掩右軍餘水石，", "若到天臺洞陽觀，葛洪丹井在雲涯。"]'),
('yuding-86','涼州詞','薛逢','唐','御定全唐诗','yuding','','[]','千里東歸客，無心憶舊遊。掛帆游□水，高枕到青州。',72,'御定全唐詩/json/548.json','["千里東歸客，無心憶舊遊。掛帆游□水，高枕到青州。", "君住孤山下，煙深夜徑長。轅門渡綠水，游苑繞垂楊。", "樹發花如錦，鶯啼柳若絲。更遊歡宴地，愁見別離時。"]'),
('yuding-87','送蕭俛相公歸山','薛逢','唐','御定全唐诗','yuding','','[]','眼前軒冕是鴻毛，天上人情謾自勞。',32,'御定全唐詩/json/548.json','["眼前軒冕是鴻毛，天上人情謾自勞。", "脫卻朝衣便東去，青雲不及白雲高。"]'),
('yuding-88','石膏枕','薛逢','唐','御定全唐诗','yuding','','[]','表裏通明不假雕，冷于春雪白於瑤。',32,'御定全唐詩/json/548.json','["表裏通明不假雕，冷于春雪白於瑤。", "朝來送在涼床上，只怕風吹日炙銷。"]'),
('yuding-89','句','薛逢','唐','御定全唐诗','yuding','','[]','草荒留客院，泥臥喂生台。（《遊廢寺》。',106,'御定全唐詩/json/548.json','["草荒留客院，泥臥喂生台。（《遊廢寺》。", "以下見《海錄碎事》）", "碧碎鴛鴦瓦，香埋菡萏壚。", "初日暉暉上彩旄。", "金鞍俯鞚塵開處，銀鏑離弦中處聲。。", "昨日鴻毛萬鈞重，今朝山嶽一朝輕。（《舊唐書》本傳：", "王鐸作相，逢有詩云云，鐸怨之）"]'),
('yuding-0','汾上宴別','趙嘏','唐','御定全唐诗','yuding','','[]','雲物如故鄉，山川知異路。年來未歸客，馬上春色暮。',48,'御定全唐詩/json/549.json','["雲物如故鄉，山川知異路。年來未歸客，馬上春色暮。", "一尊花下酒，殘日水西樹。不待管弦終，搖鞭背花去。"]'),
('yuding-1','書齋雪後','趙嘏','唐','御定全唐诗','yuding','','[]','擁褐坐茅簷，春晴喜初日。微風入桃徑，爽氣歸縹帙。',72,'御定全唐詩/json/549.json','["擁褐坐茅簷，春晴喜初日。微風入桃徑，爽氣歸縹帙。", "頻時苦風雪，就景理巾櫛。樹暖高鳥來，窗閑曙雲出。", "鄉遙路難越，道蹇時易失。欲靜又不能，東山負芝朮。"]'),
('yuding-2','寄道者','趙嘏','唐','御定全唐诗','yuding','','[]','洞庭先生歸路長，海雲望極春茫茫。',32,'御定全唐詩/json/549.json','["洞庭先生歸路長，海雲望極春茫茫。", "別來幾度向蓬島，自傍瑤台折靈草。"]'),
('yuding-3','虎丘寺贈漁處士','趙嘏','唐','御定全唐诗','yuding','','[]','蘭若雲深處，前年客重過。岩空秋色動，水闊夕陽多。',48,'御定全唐詩/json/549.json','["蘭若雲深處，前年客重過。岩空秋色動，水闊夕陽多。", "早負江湖志，今如鬢髮何。唯思閑勝我，釣艇在煙波。"]'),
('yuding-4','陪崔璞侍禦和崔gC春日有懷','趙嘏','唐','御定全唐诗','yuding','','[]','詩家本多感，況值廣陵春。暖駐含窗日，香餘醉袖塵。',48,'御定全唐詩/json/549.json','["詩家本多感，況值廣陵春。暖駐含窗日，香餘醉袖塵。", "浮名皆有分，一笑最關身。自此容依託，清才兩故人。"]'),
('yuding-5','昔昔鹽二十首：垂柳覆金堤','趙嘏','唐','御定全唐诗','yuding','','[]','新年垂柳色，嫋嫋對空閨。不畏芳菲好，自緣離別啼。',48,'御定全唐詩/json/549.json','["新年垂柳色，嫋嫋對空閨。不畏芳菲好，自緣離別啼。", "因風飄玉戶，向日映金堤。驛使何時度，還將贈隴西。"]'),
('yuding-6','昔昔鹽二十首：蘼蕪葉複齊','趙嘏','唐','御定全唐诗','yuding','','[]','提筐紅葉下，度日采蘼蕪。掬翠香盈袖，看花憶故夫。',48,'御定全唐詩/json/549.json','["提筐紅葉下，度日采蘼蕪。掬翠香盈袖，看花憶故夫。", "葉齊誰複見，風暖恨偏孤。一被春光累，容顏與昔殊。"]'),
('yuding-7','昔昔鹽二十首：水溢芙蓉沼','趙嘏','唐','御定全唐诗','yuding','','[]','淥沼春光後，青青草色濃。綺羅驚翡翠，暗粉妒芙蓉。',48,'御定全唐詩/json/549.json','["淥沼春光後，青青草色濃。綺羅驚翡翠，暗粉妒芙蓉。", "雲遍窗前見，荷翻鏡裏逢。將心托流水，終日渺無從。"]'),
('yuding-8','昔昔鹽二十首：花飛桃李蹊','趙嘏','唐','御定全唐诗','yuding','','[]','遠期難可托，桃李自依依。花徑無容跡，戎裘未下機。',48,'御定全唐詩/json/549.json','["遠期難可托，桃李自依依。花徑無容跡，戎裘未下機。", "隨風開又落，度日掃還飛。欲折枝枝贈，那知歸不歸。"]'),
('yuding-9','昔昔鹽二十首：采桑秦氏女','趙嘏','唐','御定全唐诗','yuding','','[]','南陌采桑出，誰知妾姓秦。獨憐傾國貌，不負早鶯春。',48,'御定全唐詩/json/549.json','["南陌采桑出，誰知妾姓秦。獨憐傾國貌，不負早鶯春。", "珠履蕩花濕，龍鉤折桂新。使君那駐馬，自有侍中人。"]'),
('yuding-10','昔昔鹽二十首：織錦竇家妻','趙嘏','唐','御定全唐诗','yuding','','[]','當年誰不羨，分作竇家妻。錦字行行苦，羅幃日日啼。',48,'御定全唐詩/json/549.json','["當年誰不羨，分作竇家妻。錦字行行苦，羅幃日日啼。", "豈知登隴遠，只恨下機迷。直候陽關使，殷勤寄海西。"]'),
('yuding-11','昔昔鹽二十首：關山別蕩子','趙嘏','唐','御定全唐诗','yuding','','[]','那堪聞蕩子，迢遞涉關山。腸為馬嘶斷，衣從淚滴斑。',48,'御定全唐詩/json/549.json','["那堪聞蕩子，迢遞涉關山。腸為馬嘶斷，衣從淚滴斑。", "愁看塞上路，詎惜鏡中顏。儻見征西雁，應傳一字還。"]'),
('yuding-12','昔昔鹽二十首：風月守空閨','趙嘏','唐','御定全唐诗','yuding','','[]','良人猶遠戍，耿耿夜閨空。繡戶流宵月，羅幃坐晚風。',48,'御定全唐詩/json/549.json','["良人猶遠戍，耿耿夜閨空。繡戶流宵月，羅幃坐晚風。", "魂飛沙帳北，腸斷玉關中。尚自無消息，錦衾那得同。"]'),
('yuding-13','昔昔鹽二十首：恒斂千金笑','趙嘏','唐','御定全唐诗','yuding','','[]','玉顏恒自斂，羞出鏡臺前。早惑陽城客，今悲華錦筵。',48,'御定全唐詩/json/549.json','["玉顏恒自斂，羞出鏡臺前。早惑陽城客，今悲華錦筵。", "從軍人更遠，投喜鵲空傳。夫婿交河北，迢迢路幾千。"]'),
('yuding-14','昔昔鹽二十首：長垂雙玉啼','趙嘏','唐','御定全唐诗','yuding','','[]','雙雙紅淚墮，度日暗中啼。雁出居延北，人猶遼海西。',48,'御定全唐詩/json/549.json','["雙雙紅淚墮，度日暗中啼。雁出居延北，人猶遼海西。", "向燈垂玉枕，對月灑金閨。不惜羅衣濕，惟愁歸意迷。"]'),
('yuding-15','昔昔鹽二十首：蟠龍隨鏡隱','趙嘏','唐','御定全唐诗','yuding','','[]','鸞鏡無由照，蛾眉豈忍看。不知愁發換，空見隱龍蟠。',48,'御定全唐詩/json/549.json','["鸞鏡無由照，蛾眉豈忍看。不知愁發換，空見隱龍蟠。", "那愜紅顏改，偏傷白日殘。今朝窺玉匣，雙淚落闌幹。"]'),
('yuding-16','昔昔鹽二十首：彩鳳逐帷低','趙嘏','唐','御定全唐诗','yuding','','[]','巧繡雙飛鳳，朝朝伴下帷。春花那見照，暮色已頻欺。',48,'御定全唐詩/json/549.json','["巧繡雙飛鳳，朝朝伴下帷。春花那見照，暮色已頻欺。", "欲卷思君處，將啼裛淚時。何年征戍客，傳語報佳期。"]'),
('yuding-17','昔昔鹽二十首：驚魂同夜鵲','趙嘏','唐','御定全唐诗','yuding','','[]','萬里無人見，眾情難與論。思君常入夢，同鵲屢驚魂。',48,'御定全唐詩/json/549.json','["萬里無人見，眾情難與論。思君常入夢，同鵲屢驚魂。", "孤寢紅羅帳，雙啼玉箸痕。妾心甘自保，豈複暫忘恩。"]'),
('yuding-18','昔昔鹽二十首：倦寢聽晨雞','趙嘏','唐','御定全唐诗','yuding','','[]','去去邊城騎，愁眠掩夜閨。披衣窺落月，拭淚待鳴雞。',48,'御定全唐詩/json/549.json','["去去邊城騎，愁眠掩夜閨。披衣窺落月，拭淚待鳴雞。", "不憤連年別，那看長夜啼。功成應自恨，早晚發遼西。"]'),
('yuding-19','昔昔鹽二十首：暗牖懸蛛網','趙嘏','唐','御定全唐诗','yuding','','[]','暗中蛛網織，曆亂綺窗前。萬里終無信，一條徒自懸。',48,'御定全唐詩/json/549.json','["暗中蛛網織，曆亂綺窗前。萬里終無信，一條徒自懸。", "分從珠露滴，愁見隙風牽。妾意何聊賴，看看劇斷弦。"]'),
('yuding-20','昔昔鹽二十首：空梁落燕泥','趙嘏','唐','御定全唐诗','yuding','','[]','春至今朝燕，花時伴獨啼。飛斜珠箔隔，語近畫梁低。',48,'御定全唐詩/json/549.json','["春至今朝燕，花時伴獨啼。飛斜珠箔隔，語近畫梁低。", "帷卷閑窺戶，床空暗落泥。誰能長對此，雙去複雙棲。"]'),
('yuding-21','昔昔鹽二十首：前年過代北','趙嘏','唐','御定全唐诗','yuding','','[]','代北幾千里，前年又複經。燕山雲自合，胡塞草應青。',48,'御定全唐詩/json/549.json','["代北幾千里，前年又複經。燕山雲自合，胡塞草應青。", "鐵馬喧鼙鼓，蛾眉怨錦屏。不知羌笛曲，掩淚若為聽。"]'),
('yuding-22','昔昔鹽二十首：今歲往遼西','趙嘏','唐','御定全唐诗','yuding','','[]','萬里飛書至，聞君已渡遼。只諳新別苦，忘卻舊時嬌。',48,'御定全唐詩/json/549.json','["萬里飛書至，聞君已渡遼。只諳新別苦，忘卻舊時嬌。", "烽戍年將老，紅顏日向凋。胡沙兼漢苑，相望幾迢迢。"]'),
('yuding-23','昔昔鹽二十首：一去無還意','趙嘏','唐','御定全唐诗','yuding','','[]','良人征絕域，一去不言還。百戰攻胡虜，三冬阻玉關。',48,'御定全唐詩/json/549.json','["良人征絕域，一去不言還。百戰攻胡虜，三冬阻玉關。", "蕭蕭邊馬思，獵獵戍旗閑。獨抱千重恨，連年未解顏。"]'),
('yuding-24','昔昔鹽二十首：那能惜馬蹄','趙嘏','唐','御定全唐诗','yuding','','[]','雲中路杳杳，江畔草淒淒。妾久垂珠淚，君何惜馬蹄。',48,'御定全唐詩/json/549.json','["雲中路杳杳，江畔草淒淒。妾久垂珠淚，君何惜馬蹄。", "邊風悲曉角，營月怨春鼙。未道休征戰，愁眉又複低。"]'),
('yuding-25','送韋處士歸省朔方','趙嘏','唐','御定全唐诗','yuding','','[]','映柳見行色，故山當落暉。青雲知已歿，白首一身歸。',48,'御定全唐詩/json/549.json','["映柳見行色，故山當落暉。青雲知已歿，白首一身歸。", "滿袖蕭關雨，連沙塞雁飛。到家翻有喜，借取老萊衣。"]'),
('yuding-26','送權先輩歸覲信安','趙嘏','唐','御定全唐诗','yuding','','[]','衣彩獨歸去，一枝蘭更香。馬嘶芳草渡，門掩百花塘。',48,'御定全唐詩/json/549.json','["衣彩獨歸去，一枝蘭更香。馬嘶芳草渡，門掩百花塘。", "野色亭台晚，灘聲枕簟涼。小齋松島上，重葉覆書堂。"]'),
('yuding-27','風蟬','趙嘏','唐','御定全唐诗','yuding','','[]','風蟬旦夕鳴，伴夜送秋聲。故里客歸盡，水邊身獨行。',48,'御定全唐詩/json/549.json','["風蟬旦夕鳴，伴夜送秋聲。故里客歸盡，水邊身獨行。", "噪軒高樹合，驚枕暮山橫。聽處無人見，塵埃滿甑生。"]'),
('yuding-28','重寄盧中丞','趙嘏','唐','御定全唐诗','yuding','','[]','賤子來還去，何人伴使君。放歌迎晚醉，指路上高雲。',48,'御定全唐詩/json/549.json','["賤子來還去，何人伴使君。放歌迎晚醉，指路上高雲。", "此夜雁初至，空山雨獨聞。別多頭欲白，惆悵惜餘醺。"]'),
('yuding-29','曉發','趙嘏','唐','御定全唐诗','yuding','','[]','旅行宜早發，況複是南歸。月影緣山盡，鐘聲隔浦微。',48,'御定全唐詩/json/549.json','["旅行宜早發，況複是南歸。月影緣山盡，鐘聲隔浦微。", "星殘螢共映，葉落鳥驚飛。去去渡南渚，村深人出稀。"]'),
('yuding-30','送友人鄭州歸覲','趙嘏','唐','御定全唐诗','yuding','','[]','為有趨庭戀，應忘道路賒。風消滎澤凍，雨靜圃田沙。',48,'御定全唐詩/json/549.json','["為有趨庭戀，應忘道路賒。風消滎澤凍，雨靜圃田沙。", "古陌人來遠，遙天雁勢斜。園林新到日，春酒酌梨花。"]'),
('yuding-31','洛中逢盧郢石歸覲','趙嘏','唐','御定全唐诗','yuding','','[]','不堪俱失意，相送出東周。緣切倚門戀，倍添為客愁。',48,'御定全唐詩/json/549.json','["不堪俱失意，相送出東周。緣切倚門戀，倍添為客愁。", "春山和雪靜，寒水帶冰流。別後期君處，靈源紫閣秋。"]'),
('yuding-32','贈越客','趙嘏','唐','御定全唐诗','yuding','','[]','故國波濤隔，明時心久留。獻書雙闕晚，看月五陵秋。',48,'御定全唐詩/json/549.json','["故國波濤隔，明時心久留。獻書雙闕晚，看月五陵秋。", "南棹何當返，長江憶共遊。定知釣魚伴，相望在汀州。"]'),
('yuding-33','經無錫縣醉後吟','趙嘏','唐','御定全唐诗','yuding','','[]','客過無名姓，扁舟系柳陰。窮秋南國淚，殘日故鄉心。',48,'御定全唐詩/json/549.json','["客過無名姓，扁舟系柳陰。窮秋南國淚，殘日故鄉心。", "京洛衣塵在，江湖酒病深。何須覓陶令，乘醉自橫琴。"]'),
('yuding-34','東歸道中二首','趙嘏','唐','御定全唐诗','yuding','','[]','平生事行役，今日始知非。歲月老將至，江湖春未歸。',96,'御定全唐詩/json/549.json','["平生事行役，今日始知非。歲月老將至，江湖春未歸。", "傳家有天爵，主祭用儒衣。何必勞知己，無名亦息機。", "未明喚僮僕，江上憶殘春。風雨落花夜，山川驅馬人。", "星星一鏡發，草草百年身。此日念前事，滄洲情更親。"]'),
('yuding-35','旅次商山','趙嘏','唐','御定全唐诗','yuding','','[]','役役依山水，何曾似問津。斷崖如避馬，芳樹欲留人。',48,'御定全唐詩/json/549.json','["役役依山水，何曾似問津。斷崖如避馬，芳樹欲留人。", "日夕猿鳥伴，古今京洛塵。一枝甘已失，辜負故園春。"]'),
('yuding-36','長洲','趙嘏','唐','御定全唐诗','yuding','','[]','扁舟殊不系，浩蕩路才分。范蠡湖中樹，吳王苑外雲。',48,'御定全唐詩/json/549.json','["扁舟殊不系，浩蕩路才分。范蠡湖中樹，吳王苑外雲。", "悲心人望月，獨夜雁離群。明發還驅馬，關城見日曛。"]'),
('yuding-37','江邊','趙嘏','唐','御定全唐诗','yuding','','[]','終日勞車馬，江邊款行扉。殘花春浪闊，小酒故人稀。',48,'御定全唐詩/json/549.json','["終日勞車馬，江邊款行扉。殘花春浪闊，小酒故人稀。", "戍鼓客帆遠，津雲夕照微。何由兄與弟，俱及暮春歸。"]'),
('yuding-38','宿靈岩寺','趙嘏','唐','御定全唐诗','yuding','','[]','明月溪頭寺，蟲聲滿橘洲。倚欄香徑晚，移石太湖秋。',48,'御定全唐詩/json/549.json','["明月溪頭寺，蟲聲滿橘洲。倚欄香徑晚，移石太湖秋。", "古樹雲歸盡，荒台水更流。無人見惆悵，獨上最高樓。"]'),
('yuding-39','越中寺居','趙嘏','唐','御定全唐诗','yuding','','[]','遲客疏林下，斜溪小艇通。野橋連寺月，高竹半樓風。',48,'御定全唐詩/json/549.json','["遲客疏林下，斜溪小艇通。野橋連寺月，高竹半樓風。", "水靜魚吹浪，枝閑鳥下空。數峰相向綠，日夕郡城東。"]'),
('yuding-40','贈金剛三藏','趙嘏','唐','御定全唐诗','yuding','','[]','心法雲無住，流沙歸複來。錫隨山鳥動，經附海船回。',48,'御定全唐詩/json/549.json','["心法雲無住，流沙歸複來。錫隨山鳥動，經附海船回。", "洗足柳遮寺，坐禪花委苔。惟將一童子，又欲過天臺。"]'),
('yuding-41','長安晚秋','趙嘏','唐','御定全唐诗','yuding','','[]','雲物淒涼拂曙流，漢家宮闕動高秋。殘星幾點雁橫塞，',40,'御定全唐詩/json/549.json','["雲物淒涼拂曙流，漢家宮闕動高秋。殘星幾點雁橫塞，", "鱸魚正美不歸去，空戴南冠學楚囚。"]'),
('yuding-42','齊安早秋','趙嘏','唐','御定全唐诗','yuding','','[]','流年堪惜又堪驚，砧杵風來滿郡城。高鳥過時秋色動，',40,'御定全唐詩/json/549.json','["流年堪惜又堪驚，砧杵風來滿郡城。高鳥過時秋色動，", "此日沾襟念岐路，不知何處是前程。"]'),
('yuding-43','東望','趙嘏','唐','御定全唐诗','yuding','','[]','楚江橫在草堂前，楊柳洲西載酒船。兩見梨花歸不得，',40,'御定全唐詩/json/549.json','["楚江橫在草堂前，楊柳洲西載酒船。兩見梨花歸不得，", "同郡故人攀桂盡，把詩吟向泬寥天。"]'),
('yuding-44','長安月夜與友人話故山','趙嘏','唐','御定全唐诗','yuding','','[]','宅邊秋水浸苔磯，日日持竿去不歸。楊柳風多潮未落，',40,'御定全唐詩/json/549.json','["宅邊秋水浸苔磯，日日持竿去不歸。楊柳風多潮未落，", "今夜秦城滿樓月，故人相見一沾衣。"]'),
('yuding-45','題橫水驛雙峰院松','趙嘏','唐','御定全唐诗','yuding','','[]','故園溪上雪中別，野館門前雲外逢。白髮漸多何事苦，',40,'御定全唐詩/json/549.json','["故園溪上雪中別，野館門前雲外逢。白髮漸多何事苦，", "更憶葛洪丹井畔，數株臨水欲成龍。"]'),
('yuding-46','發剡中','趙嘏','唐','御定全唐诗','yuding','','[]','正懷何謝俯長流，更覽餘封識嵊州。樹色老依官舍晚，',40,'御定全唐詩/json/549.json','["正懷何謝俯長流，更覽餘封識嵊州。樹色老依官舍晚，", "日暮不堪還上馬，蓼花風起路悠悠。"]'),
('yuding-47','登安陸西樓','趙嘏','唐','御定全唐诗','yuding','','[]','樓上華筵日日開，眼前人事只堪哀。征車自入紅塵去，',40,'御定全唐詩/json/549.json','["樓上華筵日日開，眼前人事只堪哀。征車自入紅塵去，", "無由並寫春風恨，欲下鄖城首重回。"]'),
('yuding-48','九日陪越州元相燕龜山寺','趙嘏','唐','御定全唐诗','yuding','','[]','佳晨何處泛花游，丞相筵開水上頭。雙影旆搖山雨霽，',40,'御定全唐詩/json/549.json','["佳晨何處泛花游，丞相筵開水上頭。雙影旆搖山雨霽，", "共賀萬家逢此節，可憐風物似荊州。"]'),
('yuding-49','經漢武泉','趙嘏','唐','御定全唐诗','yuding','','[]','芙蓉苑裏起清秋，漢武泉聲落禦溝。他日江山映蓬鬢，',40,'御定全唐詩/json/549.json','["芙蓉苑裏起清秋，漢武泉聲落禦溝。他日江山映蓬鬢，", "盡把歸心付紅葉，晚來隨水向東流。"]'),
('yuding-50','曲江春望懷江南故人','趙嘏','唐','御定全唐诗','yuding','','[]','杜若洲邊人未歸，水寒煙暖想柴扉。故園何處風吹柳，',40,'御定全唐詩/json/549.json','["杜若洲邊人未歸，水寒煙暖想柴扉。故園何處風吹柳，", "此時愁望情多少，萬里春流繞釣磯。"]'),
('yuding-51','上令狐相公','趙嘏','唐','御定全唐诗','yuding','','[]','鶚在卿雲冰在壺，代天才業奉籲謨。榮同伊陟傳朱戶，',40,'御定全唐詩/json/549.json','["鶚在卿雲冰在壺，代天才業奉籲謨。榮同伊陟傳朱戶，", "不知機務時多暇，猶許詩家屬和無。"]'),
('yuding-52','憶山陽','趙嘏','唐','御定全唐诗','yuding','','[]','家在枚皋舊宅邊，竹軒晴與楚坡連。芰荷香繞垂鞭袖，',40,'御定全唐詩/json/549.json','["家在枚皋舊宅邊，竹軒晴與楚坡連。芰荷香繞垂鞭袖，", "可憐時節堪歸去，花落猿啼又一年。"]'),
('yuding-53','二','趙嘏','唐','御定全唐诗','yuding','','[]','折柳城邊起暮愁，可憐春色獨懷憂。傷心正歎人間事，',40,'御定全唐詩/json/549.json','["折柳城邊起暮愁，可憐春色獨懷憂。傷心正歎人間事，", "憑高滿眼送清渭，去傍故山山下流。"]'),
('yuding-54','送僧歸廬山','趙嘏','唐','御定全唐诗','yuding','','[]','禪棲忽憶五峰遊，去著方袍謝列侯。經啟樓臺千葉曙，',40,'御定全唐詩/json/549.json','["禪棲忽憶五峰遊，去著方袍謝列侯。經啟樓臺千葉曙，", "卻憶前年別師處，馬嘶殘月虎溪頭。"]'),
('yuding-55','贈天卿寺神亮上人','趙嘏','唐','御定全唐诗','yuding','','[]','五看春盡此江濆，花自飄零日自曛。空有慈悲隨物念，',40,'御定全唐詩/json/549.json','["五看春盡此江濆，花自飄零日自曛。空有慈悲隨物念，", "笑指白蓮心自得，世間煩惱是浮雲。"]'),
('yuding-56','降虜','趙嘏','唐','御定全唐诗','yuding','','[]','廣武溪頭降虜稀，一聲寒角怨金微。河湟不在春風地，',40,'御定全唐詩/json/549.json','["廣武溪頭降虜稀，一聲寒角怨金微。河湟不在春風地，", "揚雄尚白相如吃，今日何人從獵歸。"]'),
('yuding-57','平戎','趙嘏','唐','御定全唐诗','yuding','','[]','邊聲一夜殷秋鼙，牙帳連烽擁萬蹄。武帝未能忘塞北，',40,'御定全唐詩/json/549.json','["邊聲一夜殷秋鼙，牙帳連烽擁萬蹄。武帝未能忘塞北，", "自古平戎有良策，將軍不用倚雲梯。"]'),
('yuding-58','宿楚國寺有懷','趙嘏','唐','御定全唐诗','yuding','','[]','風動衰荷寂寞香，斷煙殘月共蒼蒼。寒生晚寺波搖壁，',40,'御定全唐詩/json/549.json','["風動衰荷寂寞香，斷煙殘月共蒼蒼。寒生晚寺波搖壁，", "江邊松菊荒應盡，八月長安夜正長。"]'),
('yuding-59','早發剡中石城寺','趙嘏','唐','御定全唐诗','yuding','','[]','暫息勞生樹色間，平明機慮又相關。吟辭宿處煙霞去，',40,'御定全唐詩/json/549.json','["暫息勞生樹色間，平明機慮又相關。吟辭宿處煙霞去，", "明朝一倍堪惆悵，回首塵中見此山。"]'),
('yuding-60','寄歸','趙嘏','唐','御定全唐诗','yuding','','[]','三年踏盡化衣塵，只見長安不見春。馬過雪街天未曙，',40,'御定全唐詩/json/549.json','["三年踏盡化衣塵，只見長安不見春。馬過雪街天未曙，", "早晚相酬身事了，水邊歸去一閒人。"]'),
('yuding-61','獻淮南李相公','趙嘏','唐','御定全唐诗','yuding','','[]','傅岩高靜見台星，廟略當時討不庭。萬里有雲歸碧落，',40,'御定全唐詩/json/549.json','["傅岩高靜見台星，廟略當時討不庭。萬里有雲歸碧落，", "聞道國人思再入，熔金新鑄鶴儀形。"]'),
('yuding-62','宛陵寓居上沈大夫二首','趙嘏','唐','御定全唐诗','yuding','','[]','滿耳歌謠滿眼山，宛陵城郭翠微間。人情已覺春長在，',80,'御定全唐詩/json/549.json','["滿耳歌謠滿眼山，宛陵城郭翠微間。人情已覺春長在，", "幽雲高鳥俱無事，晚伴西風醉客還。", "溪樹參差綠可攀，謝家雲水滿東山。能忘天上他年貴，", "觥籌不盡須歸去，路在春風縹緲間。"]'),
('yuding-63','淮信賀滕邁台州','趙嘏','唐','御定全唐诗','yuding','','[]','凋瘵民思太古風，上賢綏輯副宸衷。舟移清鏡禹祠北，',40,'御定全唐詩/json/549.json','["凋瘵民思太古風，上賢綏輯副宸衷。舟移清鏡禹祠北，", "遙知到郡滄波晏，三島離離一望中。"]'),
('yuding-64','下第寄宣城幕中諸公','趙嘏','唐','御定全唐诗','yuding','','[]','一醉曾將萬事齊，暫陪歡去便如泥。黃花李白墓前路，',40,'御定全唐詩/json/549.json','["一醉曾將萬事齊，暫陪歡去便如泥。黃花李白墓前路，", "莫言春盡不惆悵，自有閑眠到日西。"]'),
('yuding-65','送令狐郎中赴郢州','趙嘏','唐','御定全唐诗','yuding','','[]','佐幕才多始拜侯，一門清貴動神州。霜蹄曉駐秦雲斷，',40,'御定全唐詩/json/549.json','["佐幕才多始拜侯，一門清貴動神州。霜蹄曉駐秦雲斷，", "大馮罷相吟詩地，莫惜頻登白雪樓。"]'),
('yuding-66','送盧緘歸揚州','趙嘏','唐','御定全唐诗','yuding','','[]','曾向雷塘寄掩扉，荀家燈火有餘輝。關河日暮望空極，',40,'御定全唐詩/json/549.json','["曾向雷塘寄掩扉，荀家燈火有餘輝。關河日暮望空極，", "今年春色還相誤，為我江邊謝釣磯。"]'),
('yuding-67','送李裴評事','趙嘏','唐','御定全唐诗','yuding','','[]','塞垣從事識兵機，只擬平戎不擬歸。入夜笳聲含白髮，',40,'御定全唐詩/json/549.json','["塞垣從事識兵機，只擬平戎不擬歸。入夜笳聲含白髮，", "此別不應書斷絕，滿天霜雪有鴻飛。"]'),
('yuding-68','別麻氏','趙嘏','唐','御定全唐诗','yuding','','[]','曉哭呱呱動四鄰，於君我作負心人。出門便涉東西路，',40,'御定全唐詩/json/549.json','["曉哭呱呱動四鄰，於君我作負心人。出門便涉東西路，", "分離況值花時節，從此東風不似春。"]'),
('yuding-69','代人贈別','趙嘏','唐','御定全唐诗','yuding','','[]','月自斜窗夢自驚，衷腸中有萬愁生。清猿處處三聲盡，',40,'御定全唐詩/json/549.json','["月自斜窗夢自驚，衷腸中有萬愁生。清猿處處三聲盡，", "會須攜手乘鸞去，簫史樓臺在玉京。"]'),
('yuding-70','寒食新豐別友人','趙嘏','唐','御定全唐诗','yuding','','[]','一百五日家未歸，新豐雞犬獨依依。滿樓春色傍人醉，',40,'御定全唐詩/json/549.json','["一百五日家未歸，新豐雞犬獨依依。滿樓春色傍人醉，", "東風吹淚對花落，憔悴故交相見稀。"]'),
('yuding-71','李侍禦歸山同宿華嚴寺','趙嘏','唐','御定全唐诗','yuding','','[]','家有青山近玉京，風流柱史早知名。園林手植自含綠，',40,'御定全唐詩/json/549.json','["家有青山近玉京，風流柱史早知名。園林手植自含綠，", "相逢一宿最高寺，夜夜翠微泉落聲。"]'),
('yuding-72','今年新先輩以遏密之際每有宴集必資清談書此奉賀','趙嘏','唐','御定全唐诗','yuding','','[]','天上高高月桂叢，分明三十一枝風。滿懷春色向人動，',40,'御定全唐詩/json/549.json','["天上高高月桂叢，分明三十一枝風。滿懷春色向人動，", "居然自是前賢事，何必青樓倚翠空。"]'),
('yuding-73','自遣','趙嘏','唐','御定全唐诗','yuding','','[]','晚樹疏蟬起別愁，遠人回首憶滄洲。江連故國無窮恨，',40,'御定全唐詩/json/549.json','["晚樹疏蟬起別愁，遠人回首憶滄洲。江連故國無窮恨，", "到頭生長煙霞者，須向煙霞老始休。"]'),
('yuding-74','浙東陪元相公游雲門寺','趙嘏','唐','御定全唐诗','yuding','','[]','松下山前一徑通，燭迎千騎滿山紅。溪雲乍斂幽岩雨，',40,'御定全唐詩/json/549.json','["松下山前一徑通，燭迎千騎滿山紅。溪雲乍斂幽岩雨，", "歸來吹盡岩城角，路轉橫塘亂水東。"]'),
('yuding-75','陪韋中丞宴扈都頭花園','趙嘏','唐','御定全唐诗','yuding','','[]','門下煙橫載酒船，謝家攜客醉華筵。尋花偶坐將軍樹，',40,'御定全唐詩/json/549.json','["門下煙橫載酒船，謝家攜客醉華筵。尋花偶坐將軍樹，", "分明聽得輿人語，願及行春更一年。"]'),
('yuding-76','花園即事呈常','趙嘏','唐','御定全唐诗','yuding','','[]','煙暖池塘柳覆台，百花園裏看花來。燒衣焰席三千樹，',40,'御定全唐詩/json/549.json','["煙暖池塘柳覆台，百花園裏看花來。燒衣焰席三千樹，", "山公仰爾延賓客，好傍春風次第開。"]'),
('yuding-77','宿何書記先輩延福新居','趙嘏','唐','御定全唐诗','yuding','','[]','松下有琴閑未收，一燈高為石叢留。詩情似到山家夜，',40,'御定全唐詩/json/549.json','["松下有琴閑未收，一燈高為石叢留。詩情似到山家夜，", "因君撫掌問時俗，紫閣堆簷不舉頭。"]'),
('yuding-78','秦中逢王處士','趙嘏','唐','御定全唐诗','yuding','','[]','萬水東流去不回，先生獨自負仙才。蕊宮橫浪海邊別，',40,'御定全唐詩/json/549.json','["萬水東流去不回，先生獨自負仙才。蕊宮橫浪海邊別，", "春風正好分瓊液，乞取當時白玉杯。"]'),
('yuding-79','江上逢許逸人','趙嘏','唐','御定全唐诗','yuding','','[]','是非處處生塵埃，唯君襟抱無嫌猜。收帆依雁湓浦宿，',40,'御定全唐詩/json/549.json','["是非處處生塵埃，唯君襟抱無嫌猜。收帆依雁湓浦宿，", "清秋華髮好相似，卻把釣竿歸去來。"]'),
('yuding-80','和令狐補闕春日獨遊西街','趙嘏','唐','御定全唐诗','yuding','','[]','左掖初辭近侍班，馬嘶尋得過街閑。映鞭柳色微遮水，',40,'御定全唐詩/json/549.json','["左掖初辭近侍班，馬嘶尋得過街閑。映鞭柳色微遮水，", "此時失意哀吟客，更覺風流不可攀。"]'),
('yuding-81','廣陵答崔琛','趙嘏','唐','御定全唐诗','yuding','','[]','棹倚隋家舊院牆，柳金梅雪撲簷香。朱樓映日重重晚，',40,'御定全唐詩/json/549.json','["棹倚隋家舊院牆，柳金梅雪撲簷香。朱樓映日重重晚，", "聲名官職應前定，且把旌麾入醉鄉。"]'),
('yuding-82','答友人','趙嘏','唐','御定全唐诗','yuding','','[]','詩家才子酒家仙，游宦曾依積水邊。窗戶動搖三島樹，',40,'御定全唐詩/json/549.json','["詩家才子酒家仙，游宦曾依積水邊。窗戶動搖三島樹，", "今日相逢朗吟罷，滿城砧杵一燈前。"]'),
('yuding-83','送張又新除溫州','趙嘏','唐','御定全唐诗','yuding','','[]','東晉江山稱永嘉，莫辭紅旆向天涯。凝弦夜醉松亭月，',40,'御定全唐詩/json/549.json','["東晉江山稱永嘉，莫辭紅旆向天涯。凝弦夜醉松亭月，", "卻愁明詔征非晚，不得秋來見海槎。"]'),
('yuding-84','送滕邁郎中赴睦州','趙嘏','唐','御定全唐诗','yuding','','[]','郡齋秋盡一江橫，頻命郎官地更清。星月去隨新詔動，',40,'御定全唐詩/json/549.json','["郡齋秋盡一江橫，頻命郎官地更清。星月去隨新詔動，", "想到釣台逢竹馬，只應歌詠伴猿聲。"]'),
('yuding-85','送剡客','趙嘏','唐','御定全唐诗','yuding','','[]','兩重江外片帆斜，數裏林塘繞一家。門掩右軍餘水石，',40,'御定全唐詩/json/549.json','["兩重江外片帆斜，數裏林塘繞一家。門掩右軍餘水石，", "若到天臺洞陽觀，葛洪丹井在雲涯。"]'),
('yuding-86','李先輩擢第東歸有贈送','趙嘏','唐','御定全唐诗','yuding','','[]','金榜前頭無是非，平人分得一枝歸。正憐日暖雲飄路，',40,'御定全唐詩/json/549.json','["金榜前頭無是非，平人分得一枝歸。正憐日暖雲飄路，", "茂陵自笑猶多病，空有書齋在翠微。"]'),
('yuding-87','送同年鄭祥先輩歸漢南','趙嘏','唐','御定全唐诗','yuding','','[]','年來驚喜兩心知，高處同攀次第枝。人倚繡屏閑賞夜，',40,'御定全唐詩/json/549.json','["年來驚喜兩心知，高處同攀次第枝。人倚繡屏閑賞夜，", "家去恩門四千里，只應從此夢旌旗。"]'),
('yuding-88','送沈單作尉江都','趙嘏','唐','御定全唐诗','yuding','','[]','煬帝都城春水邊，笙歌夜上木蘭船。三千宮女自塗地，',40,'御定全唐詩/json/549.json','["煬帝都城春水邊，笙歌夜上木蘭船。三千宮女自塗地，", "少年作尉須矜慎，莫向樓前墜馬鞭。"]'),
('yuding-89','送李蘊赴鄭州因獻盧郎中俶','趙嘏','唐','御定全唐诗','yuding','','[]','僕射陂西想到時，滿川晴色見旌旗。馬融閑臥笛聲遠，',40,'御定全唐詩/json/549.json','["僕射陂西想到時，滿川晴色見旌旗。馬融閑臥笛聲遠，", "唯君此去人多羨，卻是恩深自不知。"]'),
('yuding-90','送韓絳歸淮南寄韓綽先輩','趙嘏','唐','御定全唐诗','yuding','','[]','島上花枝系釣船，隋家宮畔水連天。江帆自落鳥飛外，',40,'御定全唐詩/json/549.json','["島上花枝系釣船，隋家宮畔水連天。江帆自落鳥飛外，", "相逢且問昭州事，曾鼓莊盆對逝川。"]'),
('yuding-91','送薛耽先輩歸謁漢南','趙嘏','唐','御定全唐诗','yuding','','[]','雪繞千峰驛路長，謝家聯句待檀郎。手持碧落新攀桂，',40,'御定全唐詩/json/549.json','["雪繞千峰驛路長，謝家聯句待檀郎。手持碧落新攀桂，", "孔門多少風流處，不遣顏回識醉鄉。"]'),
('yuding-92','送陳嘏登第作尉歸覲','趙嘏','唐','御定全唐诗','yuding','','[]','千峰歸去舊林塘，溪縣門前即故鄉。曾把桂誇春裏巷，',40,'御定全唐詩/json/549.json','["千峰歸去舊林塘，溪縣門前即故鄉。曾把桂誇春裏巷，", "就養舉朝人共羨，清資讓卻校書郎。"]'),
('yuding-93','送裴延翰下第歸覲滁州','趙嘏','唐','御定全唐诗','yuding','','[]','失意何曾恨解攜，問安歸去秣陵西。郡斜楊柳春風岸，',40,'御定全唐詩/json/549.json','["失意何曾恨解攜，問安歸去秣陵西。郡斜楊柳春風岸，", "一枝攀折回頭是，莫向清秋惜馬蹄。"]'),
('yuding-94','題崇聖寺簡雲端僧錄','趙嘏','唐','御定全唐诗','yuding','','[]','暮塵飄盡客愁長，來扣禪關月滿廊。宋玉逢秋空雪涕，',40,'御定全唐詩/json/549.json','["暮塵飄盡客愁長，來扣禪關月滿廊。宋玉逢秋空雪涕，", "回首故園紅葉外，只將多病告醫王。"]'),
('yuding-95','越中寺居寄上主人','趙嘏','唐','御定全唐诗','yuding','','[]','野寺初容訪靜來，晚晴江上見樓臺。中林有路到花盡，',40,'御定全唐詩/json/549.json','["野寺初容訪靜來，晚晴江上見樓臺。中林有路到花盡，", "苦心若是酬恩事，不敢吟春憶酒杯。"]'),
('yuding-96','早出洞仙觀','趙嘏','唐','御定全唐诗','yuding','','[]','露濃如水灑蒼苔，洞口煙蘿密不開。殘月色低當戶後，',40,'御定全唐詩/json/549.json','["露濃如水灑蒼苔，洞口煙蘿密不開。殘月色低當戶後，", "愁是獨尋歸路去，人間步步是塵埃。"]'),
('yuding-97','題昭應王明府溪亭','趙嘏','唐','御定全唐诗','yuding','','[]','靖節何須彭澤逢，菊洲松島水悠溶。行人自折門前柳，',40,'御定全唐詩/json/549.json','["靖節何須彭澤逢，菊洲松島水悠溶。行人自折門前柳，", "軒車過盡無公事，枕上一聲長樂鐘。"]'),
('yuding-98','贈王先生','趙嘏','唐','御定全唐诗','yuding','','[]','太一真人隱翠霞，早年曾降蔡經家。羽衣使者峭于鶴，',40,'御定全唐詩/json/549.json','["太一真人隱翠霞，早年曾降蔡經家。羽衣使者峭于鶴，", "時因弟子偷靈藥，散落人間駐物華。"]'),
('yuding-99','贈道者','趙嘏','唐','御定全唐诗','yuding','','[]','華蓋飄飄綠鬢翁，往來朝謁蕊珠宮。幾年山下陰陽鼎，',40,'御定全唐詩/json/549.json','["華蓋飄飄綠鬢翁，往來朝謁蕊珠宮。幾年山下陰陽鼎，", "應憐有客外妻子，思在長生一顧中。"]'),
('yuding-100','王先生不別而去','趙嘏','唐','御定全唐诗','yuding','','[]','仙翁歸袖拂煙霓，一卷素書還獨攜。劚藥滿囊身不病，',40,'御定全唐詩/json/549.json','["仙翁歸袖拂煙霓，一卷素書還獨攜。劚藥滿囊身不病，", "樹樹白雲幽徑絕，短船空倚武陵溪。"]'),
('yuding-101','山陽盧明府以雙鶴寄遺，白氏以詩回答，因寄和','趙嘏','唐','御定全唐诗','yuding','','[]','緱山雙去羽翰輕，應為仙家好弟兄。茅固枕前秋對舞，',40,'御定全唐詩/json/549.json','["緱山雙去羽翰輕，應為仙家好弟兄。茅固枕前秋對舞，", "自笑滄江一漁叟，何由似爾到層城。"]'),
('yuding-102','贈李秘書','趙嘏','唐','御定全唐诗','yuding','','[]','束帶臨風氣調新，孔門才業獨誰倫。杉松韻冷雪溪暗，',40,'御定全唐詩/json/549.json','["束帶臨風氣調新，孔門才業獨誰倫。杉松韻冷雪溪暗，", "莫將芸閣輕科第，須作人間第一人。"]'),
('yuding-103','回於道中寄舒州李玨相公','趙嘏','唐','御定全唐诗','yuding','','[]','都無鄙吝隔塵埃，昨日丘門避席來。靜語乍臨清廟瑟，',40,'御定全唐詩/json/549.json','["都無鄙吝隔塵埃，昨日丘門避席來。靜語乍臨清廟瑟，", "從此微塵知感戀，七真臺上望三台。"]'),
('yuding-104','舒州獻李相公','趙嘏','唐','御定全唐诗','yuding','','[]','野人留得五湖船，丞相興歌郡國年。醉筆倚風飄澗雪，',40,'御定全唐詩/json/549.json','["野人留得五湖船，丞相興歌郡國年。醉筆倚風飄澗雪，", "聞說萬方思舊德，一時傾望重陶甄。"]'),
('yuding-105','成名年獻座主僕射兼呈同年','趙嘏','唐','御定全唐诗','yuding','','[]','拂煙披月羽毛新，千里初辭九陌塵。曾失玄珠求象罔，',40,'御定全唐詩/json/549.json','["拂煙披月羽毛新，千里初辭九陌塵。曾失玄珠求象罔，", "除卻今年仙侶外，堂堂又見兩三春。"]'),
('yuding-106','抒懷上歙州盧中丞宣州杜侍郎','趙嘏','唐','御定全唐诗','yuding','','[]','東來珠履與旌旗，前者登朝亦一時。竹馬迎呼逢稚子，',40,'御定全唐詩/json/549.json','["東來珠履與旌旗，前者登朝亦一時。竹馬迎呼逢稚子，", "獨有賤夫懷感激，十年兩地負恩知。"]'),
('yuding-107','山陽韋中丞罷郡因獻','趙嘏','唐','御定全唐诗','yuding','','[]','笙歌只是舊笙歌，腸斷風流奈別何。照物二年春色在，',40,'御定全唐詩/json/549.json','["笙歌只是舊笙歌，腸斷風流奈別何。照物二年春色在，", "今日尊前無限思，萬重雲月隔煙波。"]'),
('yuding-108','山陽即席獻裴中丞','趙嘏','唐','御定全唐诗','yuding','','[]','早年天上見清塵，今日樓中醉一春。暫肯剖符臨水石，',40,'御定全唐詩/json/549.json','["早年天上見清塵，今日樓中醉一春。暫肯剖符臨水石，", "好是仙家羽衣使，欲教垂涕問何人。"]'),
('yuding-109','西峰即事獻沈大夫','趙嘏','唐','御定全唐诗','yuding','','[]','松竹閒遊道路身，衣襟落盡往來塵。山連謝宅餘霞在，',40,'御定全唐詩/json/549.json','["松竹閒遊道路身，衣襟落盡往來塵。山連謝宅餘霞在，", "安知不及屠沽者，曾對青萍淚滿巾。"]'),
('yuding-110','杜陵貽杜牧侍禦','趙嘏','唐','御定全唐诗','yuding','','[]','紫陌塵多不可尋，南溪酒熟一披襟。山高晝枕石床隱，',40,'御定全唐詩/json/549.json','["紫陌塵多不可尋，南溪酒熟一披襟。山高晝枕石床隱，", "唯君懷抱安如水，他日門牆許醉吟。"]'),
('yuding-111','下第後上李中丞','趙嘏','唐','御定全唐诗','yuding','','[]','落第逢人慟哭初，平生志業欲何如。鬢毛灑盡一枝桂，',40,'御定全唐詩/json/549.json','["落第逢人慟哭初，平生志業欲何如。鬢毛灑盡一枝桂，", "唯應感激知恩地，不待功成死有餘。"]'),
('yuding-112','浙東贈李副使員外','趙嘏','唐','御定全唐诗','yuding','','[]','妙盡戎機佐上臺，少年清苦自霜台。馬嘶深竹閑宜貴，',40,'御定全唐詩/json/549.json','["妙盡戎機佐上臺，少年清苦自霜台。馬嘶深竹閑宜貴，", "名高漸少翻飛伴，幾度煙霄獨去來。"]'),
('yuding-113','寄淮南幕中劉員外','趙嘏','唐','御定全唐诗','yuding','','[]','郎官何遜最風流，愛月憐山不下樓。三佐戎旃換朱紱，',40,'御定全唐詩/json/549.json','["郎官何遜最風流，愛月憐山不下樓。三佐戎旃換朱紱，", "休向西齋久閑臥，滿朝傾蓋是依劉。"]'),
('yuding-114','薛廷范從事自宣城至因贈','趙嘏','唐','御定全唐诗','yuding','','[]','少年從事霍嫖姚，來自楓林度柳橋。金管別筵樓灼灼，',40,'御定全唐詩/json/549.json','["少年從事霍嫖姚，來自楓林度柳橋。金管別筵樓灼灼，", "獨有故人愁欲死，晚簷疏雨動空瓢。"]'),
('yuding-115','寄潯陽趙校書','趙嘏','唐','御定全唐诗','yuding','','[]','簾下秋江夜影空，倚樓人在月明中。不將行止問朝列，',40,'御定全唐詩/json/549.json','["簾下秋江夜影空，倚樓人在月明中。不將行止問朝列，", "那應更結廬山社，見說心閑勝遠公。"]'),
('yuding-116','贈李從貴','趙嘏','唐','御定全唐诗','yuding','','[]','白馬嘶風何處還，鞭梢拂地看南山。珠簾卷盡不回首，',40,'御定全唐詩/json/549.json','["白馬嘶風何處還，鞭梢拂地看南山。珠簾卷盡不回首，", "知君舊隱嵩雲下，岩桂從今幾更攀。"]'),
('yuding-117','贈陳正字','趙嘏','唐','御定全唐诗','yuding','','[]','魯儒今日意何如，名掛春官選籍初。野艇幾曾尋水去，',40,'御定全唐詩/json/549.json','["魯儒今日意何如，名掛春官選籍初。野艇幾曾尋水去，", "聞說晚心心更靜，竹間依舊臥看書。"]'),
('yuding-118','洞庭寄所思','趙嘏','唐','御定全唐诗','yuding','','[]','日斷蘭台空望歸，錦衾香冷夢來稀。書中自報刀頭約，',40,'御定全唐詩/json/549.json','["日斷蘭台空望歸，錦衾香冷夢來稀。書中自報刀頭約，", "遙知不語坐相憶，寂寞洞房寒燭微。"]'),
('yuding-119','代人贈杜牧侍禦','趙嘏','唐','御定全唐诗','yuding','','[]','郎作東台禦史時，妾長西望斂雙眉。一從詔下人皆羨，',40,'御定全唐詩/json/549.json','["郎作東台禦史時，妾長西望斂雙眉。一從詔下人皆羨，", "坐來情態猶無限，更向樓前舞柘枝。"]'),
('yuding-120','旅館聞雁別友人','趙嘏','唐','御定全唐诗','yuding','','[]','路繞秋塘首獨搔，背群燕雁正呼號。故關何處重相失，',40,'御定全唐詩/json/549.json','["路繞秋塘首獨搔，背群燕雁正呼號。故關何處重相失，", "行衣濕盡千山雪，腸斷金籠好羽毛。"]'),
('yuding-121','泊鳧磯江館','趙嘏','唐','御定全唐诗','yuding','','[]','風雪晴來歲欲除，孤舟晚下意何如。月當軒色湖平後，',40,'御定全唐詩/json/549.json','["風雪晴來歲欲除，孤舟晚下意何如。月當軒色湖平後，", "三間茅屋東溪上，歸去生涯竹與書。"]'),
('yuding-122','春盡獨遊慈恩寺南池','趙嘏','唐','御定全唐诗','yuding','','[]','竹外池塘煙雨收，送春無伴亦遲留。秦城馬上半年客，',40,'御定全唐詩/json/549.json','["竹外池塘煙雨收，送春無伴亦遲留。秦城馬上半年客，", "杏園花落遊人盡，獨為圭峰一舉頭。"]'),
('yuding-123','重游楚國寺','趙嘏','唐','御定全唐诗','yuding','','[]','往事飄然去不回，空餘山色在樓臺。池塘風暖雁尋去，',40,'御定全唐詩/json/549.json','["往事飄然去不回，空餘山色在樓臺。池塘風暖雁尋去，", "老僧心地閑于水，猶被流年日日催。"]'),
('yuding-124','三像寺酬元秘書','趙嘏','唐','御定全唐诗','yuding','','[]','官總芸香閣署崇，可憐詩句落春風。偶然侍坐水聲裏，',40,'御定全唐詩/json/549.json','["官總芸香閣署崇，可憐詩句落春風。偶然侍坐水聲裏，", "不因高寺閑回首，誰識飄飄一寒翁。"]'),
('yuding-125','獻淮南李僕射','趙嘏','唐','御定全唐诗','yuding','','[]','早年曾謁富民侯，今日難甘失鵠羞。新諾似山無力負，',40,'御定全唐詩/json/549.json','["早年曾謁富民侯，今日難甘失鵠羞。新諾似山無力負，", "功德萬重知不惜，一言拋得百生愁。"]'),
('yuding-126','江亭晚望','趙嘏','唐','御定全唐诗','yuding','','[]','碧江涼冷雁來疏，閑望江雲思有餘。秋館池亭荷葉歇，',40,'御定全唐詩/json/549.json','["碧江涼冷雁來疏，閑望江雲思有餘。秋館池亭荷葉歇，", "聞說故園香稻熟，片帆歸去就鱸魚。"]'),
('yuding-127','贈曹處士幽居','趙嘏','唐','御定全唐诗','yuding','','[]','勾漏先生冰玉然，曾將八石問群仙。中山暫醉一千日，',40,'御定全唐詩/json/549.json','["勾漏先生冰玉然，曾將八石問群仙。中山暫醉一千日，", "何須更學鴟夷子，頭白江湖一短船。"]'),
('yuding-128','重陽日示舍弟','趙嘏','唐','御定全唐诗','yuding','','[]','多少鄉心入酒杯，野塘今日菊花開。新霜何處雁初下，',40,'御定全唐詩/json/549.json','["多少鄉心入酒杯，野塘今日菊花開。新霜何處雁初下，", "侯門無路提攜爾，虛共扁舟萬里來。"]'),
('yuding-129','客至','趙嘏','唐','御定全唐诗','yuding','','[]','得路逢津更俊才，可憐鞍馬照春來。殘花幾日小齋閉，',40,'御定全唐詩/json/549.json','["得路逢津更俊才，可憐鞍馬照春來。殘花幾日小齋閉，", "相逢少別更堪恨，何必秋風江上臺。"]'),
('yuding-0','歲暮江軒寄盧端公','趙嘏','唐','御定全唐诗','yuding','','[]','積水生高浪，長風自北時。萬艘俱擁棹，上客獨吟詩。',144,'御定全唐詩/json/550.json','["積水生高浪，長風自北時。萬艘俱擁棹，上客獨吟詩。", "路以重湖阻，心將小謝期。渚雲愁正斷，江雁重驚悲。", "笑憶遊星子，歌尋罷貴池。夢來孤島在，醉醒百憂隨。", "戍迥煙生晚，江寒鳥過遲。問山樵者對，經雨釣船移。", "敢歎今留滯，猶勝曩別離。醉從陶令得，善必丈人知。", "道蹇才何取，恩深劍不疑。此身同岸柳，只待變寒枝。"]'),
('yuding-1','秋日吳中觀貢藕','趙嘏','唐','御定全唐诗','yuding','','[]','野艇幾西東，清泠映碧空。褰衣來水上，捧玉出泥中。',72,'御定全唐詩/json/550.json','["野艇幾西東，清泠映碧空。褰衣來水上，捧玉出泥中。", "葉亂田田綠，蓮餘片片紅。激波才入選，就日已生風。", "禦潔玲瓏膳，人懷拔擢功。梯山謾多品，不與世流同。"]'),
('yuding-2','華清宮和杜舍人','趙嘏','唐','御定全唐诗','yuding','','[]','五十年天子，離宮仰峻牆。登封時正泰，禦宇日何長。',360,'御定全唐詩/json/550.json','["五十年天子，離宮仰峻牆。登封時正泰，禦宇日何長。", "上位先名實，中興事憲章。起戎輕甲胄，餘地複河湟。", "道帝玄元祖，儒封孔子王。因緣百司署，叢會一人湯。", "渭水波搖綠，秦郊草半黃。馬馴金勒細，鷹健玉鈴鏘。", "下箭朱弓滿，鳴鞭皓腕攘。畋思獲呂望，諫只避周昌。", "兔跡貪前逐，梟心不早防。幾添鸚鵡勸，先賜荔枝嘗。", "月鎖千門靜，天吹一笛涼。細音搖羽佩，輕步宛霓裳。", "禍亂基潛結，升平意遽忘。衣冠逃犬虜，鼙鼓動漁陽。", "外戚心殊迫，中途事可量。血埋妃子豔，創斷祿兒腸。", "近侍煙塵隔，前蹤輦路荒。益知迷寵佞，遺恨喪賢良。", "北闕尊明主，南宮遜上皇。禁清餘鳳吹，池冷睡龍光。", "祝壽山猶在，流年水共傷。杜鵑魂厭蜀，蝴蝶夢悲莊。", "雀卵遺雕栱，蟲絲罥畫梁。紫苔侵壁潤，紅樹閉門芳。", "守吏齊鴛瓦，耕民得翠璫。登年齊酺樂，講武舊兵場。", "暮草深岩翠，幽花墜徑香。不堪垂白叟，行折禦溝楊。"]'),
('yuding-3','下第','趙嘏','唐','御定全唐诗','yuding','','[]','南溪抱甕客，失意自懷羞。晚路誰攜手，殘春自白頭。',24,'御定全唐詩/json/550.json','["南溪抱甕客，失意自懷羞。晚路誰攜手，殘春自白頭。"]'),
('yuding-4','到家','趙嘏','唐','御定全唐诗','yuding','','[]','童稚苦相問，歸來何太遲。共誰爭歲月，贏得鬢邊絲。',24,'御定全唐詩/json/550.json','["童稚苦相問，歸來何太遲。共誰爭歲月，贏得鬢邊絲。"]'),
('yuding-5','春釀','趙嘏','唐','御定全唐诗','yuding','','[]','春釀正風流，梨花莫問愁。馬卿思一醉，不惜鷫鸘裘。',24,'御定全唐詩/json/550.json','["春釀正風流，梨花莫問愁。馬卿思一醉，不惜鷫鸘裘。"]'),
('yuding-6','寒塘','趙嘏','唐','御定全唐诗','yuding','','[]','曉發梳臨水，寒塘坐見秋。鄉心正無限，一雁度南樓。',24,'御定全唐詩/json/550.json','["曉發梳臨水，寒塘坐見秋。鄉心正無限，一雁度南樓。"]'),
('yuding-7','寄前黃州竇使君','趙嘏','唐','御定全唐诗','yuding','','[]','池上笙歌寂不聞，樓中愁殺碧虛雲。',32,'御定全唐詩/json/550.json','["池上笙歌寂不聞，樓中愁殺碧虛雲。", "玉壺凝盡重重淚，寄與風流舊使君。"]'),
('yuding-8','八月二十九日宿懷','趙嘏','唐','御定全唐诗','yuding','','[]','秋天睛日菊還香，獨坐書齋思已長。',32,'御定全唐詩/json/550.json','["秋天睛日菊還香，獨坐書齋思已長。", "無奈風光易流轉，強須傾酒一杯觴。"]'),
('yuding-9','泗上奉送相公','趙嘏','唐','御定全唐诗','yuding','','[]','語堪銘座默含春，西漢公卿絕比倫。',32,'御定全唐詩/json/550.json','["語堪銘座默含春，西漢公卿絕比倫。", "今日抱轅留不得，欲揮雙涕學舒人。"]'),
('yuding-10','贈桐鄉丞','趙嘏','唐','御定全唐诗','yuding','','[]','舟觸長松岸勢回，潺湲一夜繞亭台。',32,'御定全唐詩/json/550.json','["舟觸長松岸勢回，潺湲一夜繞亭台。", "若教靖節先生見，不肯更吟歸去來。"]'),
('yuding-11','哭李進士','趙嘏','唐','御定全唐诗','yuding','','[]','牽馬街中哭送君，靈車輾雪隔城聞。',32,'御定全唐詩/json/550.json','["牽馬街中哭送君，靈車輾雪隔城聞。", "唯有山僧與樵客，共舁孤櫬入幽墳。"]'),
('yuding-12','重陽','趙嘏','唐','御定全唐诗','yuding','','[]','節逢重九海門外，家在五湖煙水東。',32,'御定全唐詩/json/550.json','["節逢重九海門外，家在五湖煙水東。", "還向秋山覓詩句，伴僧吟對菊花風。"]'),
('yuding-13','重陽日即事','趙嘏','唐','御定全唐诗','yuding','','[]','病酒堅辭綺席春，菊花空伴水邊身。',32,'御定全唐詩/json/550.json','["病酒堅辭綺席春，菊花空伴水邊身。", "由來舉止非閒雅，不是龍山落帽人。"]'),
('yuding-14','十無詩寄桂府楊中丞','趙嘏','唐','御定全唐诗','yuding','','[]','琴酒曾將風月須，謝公名跡滿江湖。',320,'御定全唐詩/json/550.json','["琴酒曾將風月須，謝公名跡滿江湖。", "不知貴擁旌旗後，猶暇憐詩愛酒無。", "東省南宮興不孤，幾因詩酒謬招呼。", "一從開署芙蓉幕，曾向風前記得無。", "遙聞桂水繞城隅，城上江山滿畫圖。", "為問訾家洲畔月，清秋擬許醉狂無。", "日暮江邊一小儒，空憐未有白髭須。", "馬融已貴諸生老，猶自容窺絳帳無。", "一種吟詩號孔徒，滄江有客獨疏愚。", "初筵盡辟知名士，許到風前月下無。", "望斷南雲日已晡，便應憑夢過重湖。", "不知自古登龍者，曾有因詩泥得無。", "早游門館一樵夫，只愛吟詩傍藥爐。", "旌旆滿江身不見，思言記得潁川無。", "孔融襟抱稱名儒，愛物憐才與世殊。", "今日賓階忘姓字，當時省記薦雄無。", "僻愛江山俯坐隅，人間不是便為圖。", "尊前為問神仙伴，肯向三清慰薦無。", "膺門不避額逢珠，絕境由來卷軸須。", "早忝阿戎詩友契，趨庭曾薦禰生無。"]'),
('yuding-15','寄山僧','趙嘏','唐','御定全唐诗','yuding','','[]','雲裏幽僧不置房，橡花藤葉蓋禪床。',32,'御定全唐詩/json/550.json','["雲裏幽僧不置房，橡花藤葉蓋禪床。", "朝來逢著山中伴，聞說新移最上方。"]'),
('yuding-16','喜張濆及第','趙嘏','唐','御定全唐诗','yuding','','[]','九轉丹成最上仙，青天暖日踏雲軒。',32,'御定全唐詩/json/550.json','["九轉丹成最上仙，青天暖日踏雲軒。", "春風賀喜無言語，排比花枝滿杏園。"]'),
('yuding-17','贈張濆榜頭被駁落','趙嘏','唐','御定全唐诗','yuding','','[]','莫向花前泣酒杯，謫仙依舊是仙才。',32,'御定全唐詩/json/550.json','["莫向花前泣酒杯，謫仙依舊是仙才。", "猶堪與世為祥瑞，曾到蓬山頂上來。"]'),
('yuding-18','悼亡二首','趙嘏','唐','御定全唐诗','yuding','','[]','一燭從風到奈何，二年衾枕逐流波。',64,'御定全唐詩/json/550.json','["一燭從風到奈何，二年衾枕逐流波。", "雖知不得公然淚，時泣闌幹恨更多。", "明月蕭蕭海上風，君歸泉路我飄蓬。", "門前雖有如花貌，爭奈如花心不同。"]'),
('yuding-19','宮烏棲','趙嘏','唐','御定全唐诗','yuding','','[]','宮烏棲處玉樓深，微月生簷夜夜心。',32,'御定全唐詩/json/550.json','["宮烏棲處玉樓深，微月生簷夜夜心。", "香輦不回花自落，春來空佩辟寒金。"]'),
('yuding-20','長信宮','趙嘏','唐','御定全唐诗','yuding','','[]','君恩已盡欲何歸，猶有殘香在舞衣。',32,'御定全唐詩/json/550.json','["君恩已盡欲何歸，猶有殘香在舞衣。", "自恨身輕不如燕，春來長繞禦簾飛。"]'),
('yuding-21','廣陵城','趙嘏','唐','御定全唐诗','yuding','','[]','紅映高臺綠繞城，城邊春草傍牆生。',32,'御定全唐詩/json/550.json','["紅映高臺綠繞城，城邊春草傍牆生。", "隋家不向此中盡，汴水應無東去聲。"]'),
('yuding-22','冷日過驪山','趙嘏','唐','御定全唐诗','yuding','','[]','冷日微煙渭水愁，翠華宮樹不勝秋。',32,'御定全唐詩/json/550.json','["冷日微煙渭水愁，翠華宮樹不勝秋。", "霓裳一曲千門鎖，白盡梨園弟子頭。"]'),
('yuding-23','下第後歸永樂裏自題二首','趙嘏','唐','御定全唐诗','yuding','','[]','無地無媒只一身，歸來空拂滿床塵。',64,'御定全唐詩/json/550.json','["無地無媒只一身，歸來空拂滿床塵。", "尊前盡日誰相對，唯有南山似故人。", "玄發侵愁忽似翁，暖塵寒袖共東風。", "公卿門戶不知處，立馬九衢春影中。"]'),
('yuding-24','出試日獨游曲江','趙嘏','唐','御定全唐诗','yuding','','[]','江莎漸映花邊綠，樓日自開池上春。',32,'御定全唐詩/json/550.json','["江莎漸映花邊綠，樓日自開池上春。", "雙鶴繞空來又去，不知臨水有愁人。"]'),
('yuding-25','題曹娥廟','趙嘏','唐','御定全唐诗','yuding','','[]','青娥埋沒此江濱，江樹颼飀慘暮雲。',32,'御定全唐詩/json/550.json','["青娥埋沒此江濱，江樹颼飀慘暮雲。", "文字在碑碑已墮，波濤辜負色絲文。"]'),
('yuding-26','題段氏中台','趙嘏','唐','御定全唐诗','yuding','','[]','看山台下水無塵，碧筱前頭曲水春。',32,'御定全唐詩/json/550.json','["看山台下水無塵，碧筱前頭曲水春。", "獨對一尊風雨夜，不知家有早朝人。"]'),
('yuding-27','華州座中獻盧給事','趙嘏','唐','御定全唐诗','yuding','','[]','送迎皆到三峰下，滿面煙霜滿馬塵。',32,'御定全唐詩/json/550.json','["送迎皆到三峰下，滿面煙霜滿馬塵。", "自是追攀認知己，青雲不假送迎人。"]'),
('yuding-28','商山道中','趙嘏','唐','御定全唐诗','yuding','','[]','和如春色淨如秋，五月商山是勝遊。',32,'御定全唐詩/json/550.json','["和如春色淨如秋，五月商山是勝遊。", "當晝火雲生不得，一溪縈作萬重愁。"]'),
('yuding-29','贈歙州妓','趙嘏','唐','御定全唐诗','yuding','','[]','灩灩橫波思有餘，庾樓明月墮雲初。',32,'御定全唐詩/json/550.json','["灩灩橫波思有餘，庾樓明月墮雲初。", "揚州寒食春風寺，看遍花枝盡不如。"]'),
('yuding-30','贈王明府','趙嘏','唐','御定全唐诗','yuding','','[]','五柳逢秋影漸微，陶潛戀酒不知歸。',32,'御定全唐詩/json/550.json','["五柳逢秋影漸微，陶潛戀酒不知歸。", "但存物外醉鄉在，誰向人間問是非。"]'),
('yuding-31','呂校書雨中見訪','趙嘏','唐','御定全唐诗','yuding','','[]','竹閣斜溪小檻明，惟君來賞見山情。',32,'御定全唐詩/json/550.json','["竹閣斜溪小檻明，惟君來賞見山情。", "馬嘶風雨又歸去，獨聽子規千萬聲。"]'),
('yuding-32','千秋嶺下','趙嘏','唐','御定全唐诗','yuding','','[]','知有岩前萬樹桃，未逢搖落思空勞。',32,'御定全唐詩/json/550.json','["知有岩前萬樹桃，未逢搖落思空勞。", "年年盛發無人見，三十六溪春水高。"]'),
('yuding-33','歙州道中僕逃','趙嘏','唐','御定全唐诗','yuding','','[]','去跳風雨幾奔波，曾共辛勤奈若何。',32,'御定全唐詩/json/550.json','["去跳風雨幾奔波，曾共辛勤奈若何。", "莫遣窮歸不知處，秋山重疊戍旗多。"]'),
('yuding-34','重陽日寄韋舍人','趙嘏','唐','御定全唐诗','yuding','','[]','節過重陽菊委塵，江邊病起杖扶身。',32,'御定全唐詩/json/550.json','["節過重陽菊委塵，江邊病起杖扶身。", "不知此日龍山會，誰是風流落帽人。"]'),
('yuding-35','贈薛勳下第','趙嘏','唐','御定全唐诗','yuding','','[]','一擲雖然未得盧，驚人不用繞床呼。',32,'御定全唐詩/json/550.json','["一擲雖然未得盧，驚人不用繞床呼。", "牢之坐被青雲逼，只問君能酷似無。"]'),
('yuding-36','宛陵望月寄沈學士','趙嘏','唐','御定全唐诗','yuding','','[]','一川如畫敬亭東，待詔閒遊處處同。',32,'御定全唐詩/json/550.json','["一川如畫敬亭東，待詔閒遊處處同。", "天竺山前鏡湖畔，何如今日庾樓中。"]'),
('yuding-37','翡翠岩','趙嘏','唐','御定全唐诗','yuding','','[]','芙蓉幕裏千場醉，翡翠岩前半日閑。',32,'御定全唐詩/json/550.json','["芙蓉幕裏千場醉，翡翠岩前半日閑。", "惆悵晉朝人不到，謝公拋力上東山。"]'),
('yuding-38','發新安後途中寄盧中丞二首','趙嘏','唐','御定全唐诗','yuding','','[]','樓上風流庾使君，笙歌曾醉此中聞。',64,'御定全唐詩/json/550.json','["樓上風流庾使君，笙歌曾醉此中聞。", "目前已是陵陽路，回首叢山滿眼雲。", "晚樹蕭蕭促織愁，風簾似水滿床秋。", "千山不礙笙歌月，誰伴羊公上夜樓。"]'),
('yuding-39','留題興唐寺','趙嘏','唐','御定全唐诗','yuding','','[]','滿水樓臺滿寺山，七年今日共躋攀。',32,'御定全唐詩/json/550.json','["滿水樓臺滿寺山，七年今日共躋攀。", "月高對菊問行客，去折芳枝早晚還。"]'),
('yuding-40','廣陵道','趙嘏','唐','御定全唐诗','yuding','','[]','鬥雞台邊花照塵，煬帝陵下水含春。',32,'御定全唐詩/json/550.json','["鬥雞台邊花照塵，煬帝陵下水含春。", "青雲回翅北歸雁，白首哭途何處人。"]'),
('yuding-41','茅山道中','趙嘏','唐','御定全唐诗','yuding','','[]','溪樹重重水亂流，馬嘶殘雨晚程秋。',32,'御定全唐詩/json/550.json','["溪樹重重水亂流，馬嘶殘雨晚程秋。", "門前便是仙山路，目送歸雲不得遊。"]'),
('yuding-42','江上與兄別','趙嘏','唐','御定全唐诗','yuding','','[]','楚國湘江兩渺彌，暖川晴雁背帆飛。',32,'御定全唐詩/json/550.json','["楚國湘江兩渺彌，暖川晴雁背帆飛。", "人間離別盡堪哭，何況不知何日歸。"]'),
('yuding-43','落第','趙嘏','唐','御定全唐诗','yuding','','[]','九陌初晴處處春，不能回避看花塵。',32,'御定全唐詩/json/550.json','["九陌初晴處處春，不能回避看花塵。", "由來得喪非吾事，本是釣魚船上人。"]'),
('yuding-44','宛陵館冬青樹','趙嘏','唐','御定全唐诗','yuding','','[]','碧樹如煙覆晚波，清秋欲盡客重過。',32,'御定全唐詩/json/550.json','["碧樹如煙覆晚波，清秋欲盡客重過。", "故園亦有如煙樹，鴻雁不來風雨多。"]'),
('yuding-45','贈五老韓尊師','趙嘏','唐','御定全唐诗','yuding','','[]','有客齋心事玉晨，對山須鬢綠無塵。',32,'御定全唐詩/json/550.json','["有客齋心事玉晨，對山須鬢綠無塵。", "住山道士年如鶴，應識當時五老人。"]'),
('yuding-46','經汾陽舊宅','趙嘏','唐','御定全唐诗','yuding','','[]','門前不改舊山河，破虜曾輕馬伏波。',32,'御定全唐詩/json/550.json','["門前不改舊山河，破虜曾輕馬伏波。", "今日獨經歌舞地，古槐疏冷夕陽多。"]'),
('yuding-47','寄盧中丞','趙嘏','唐','御定全唐诗','yuding','','[]','葉覆清溪灩灩紅，路橫秋色馬嘶風。',32,'御定全唐詩/json/550.json','["葉覆清溪灩灩紅，路橫秋色馬嘶風。", "獨攜一榼郡齋酒，吟對青山憶謝公。"]'),
('yuding-48','途中','趙嘏','唐','御定全唐诗','yuding','','[]','故園回首雁初來，馬上千愁付一杯。',32,'御定全唐詩/json/550.json','["故園回首雁初來，馬上千愁付一杯。", "惟有新詩似相識，暮山吟處共徘徊。"]'),
('yuding-49','寄裴瀾','趙嘏','唐','御定全唐诗','yuding','','[]','綺雲初墮亭亭月，錦席惟橫灩灩波。',32,'御定全唐詩/json/550.json','["綺雲初墮亭亭月，錦席惟橫灩灩波。", "宋玉逢秋正高臥，一篇吟盡奈情何。"]'),
('yuding-50','淮南丞相坐贈歌者虞姹','趙嘏','唐','御定全唐诗','yuding','','[]','綺筵無處避梁塵，虞姹清歌日日新。',32,'御定全唐詩/json/550.json','["綺筵無處避梁塵，虞姹清歌日日新。", "來值渚亭花欲盡，一聲留得滿城春。"]'),
('yuding-51','酬段侍禦','趙嘏','唐','御定全唐诗','yuding','','[]','蓮花上客思閑閑，數首新詩到篳關。',32,'御定全唐詩/json/550.json','["蓮花上客思閑閑，數首新詩到篳關。", "吟得楚天風雨霽，一條江水兩三山。"]'),
('yuding-52','尋僧二首','趙嘏','唐','御定全唐诗','yuding','','[]','台殿參差日墮塵，塢西歸去一庵雲。',64,'御定全唐詩/json/550.json','["台殿參差日墮塵，塢西歸去一庵雲。", "寒泉何處夜深落，聲隔半岩疏葉聞。", "溪戶無人穀鳥飛，石橋橫木掛禪衣。", "看雲日暮倚松立，野水亂鳴僧未歸。"]'),
('yuding-53','發柏梯寺','趙嘏','唐','御定全唐诗','yuding','','[]','一泓秋水千竿竹，靜得勞生半日身。',32,'御定全唐詩/json/550.json','["一泓秋水千竿竹，靜得勞生半日身。", "猶有向西無限地，別僧騎馬入紅塵。"]'),
('yuding-54','西江晚泊','趙嘏','唐','御定全唐诗','yuding','','[]','茫茫靄靄失西東，柳浦桑村處處同。',32,'御定全唐詩/json/550.json','["茫茫靄靄失西東，柳浦桑村處處同。", "戍鼓一聲帆影盡，水禽飛起夕陽中。"]'),
('yuding-55','南池','趙嘏','唐','御定全唐诗','yuding','','[]','照影池邊多少愁，往來重見此塘秋。',32,'御定全唐詩/json/550.json','["照影池邊多少愁，往來重見此塘秋。", "芙蓉苑外新經雨，紅葉相隨何處流。"]'),
('yuding-56','江樓舊感','趙嘏','唐','御定全唐诗','yuding','','[]','獨上江樓思渺然，月光如水水如天。',32,'御定全唐詩/json/550.json','["獨上江樓思渺然，月光如水水如天。", "同來望月人何處，風影依稀似去年。"]'),
('yuding-57','南園','趙嘏','唐','御定全唐诗','yuding','','[]','雨過郊園綠尚微，落花惆悵滿塵衣。',32,'御定全唐詩/json/550.json','["雨過郊園綠尚微，落花惆悵滿塵衣。", "芳尊有酒無人共，日暮看山還獨歸。"]'),
('yuding-58','南亭','趙嘏','唐','御定全唐诗','yuding','','[]','孤亭影在亂花中，悵望無人此醉同。',32,'御定全唐詩/json/550.json','["孤亭影在亂花中，悵望無人此醉同。", "聽盡暮鐘猶獨坐，水邊襟袖起春風。"]'),
('yuding-59','贈女仙','趙嘏','唐','御定全唐诗','yuding','','[]','水思雲情小鳳仙，月涵花態語如弦。',32,'御定全唐詩/json/550.json','["水思雲情小鳳仙，月涵花態語如弦。", "不因金骨三清客，誰識吳州有洞天。"]'),
('yuding-60','宣州送判官','趙嘏','唐','御定全唐诗','yuding','','[]','來時健筆佐嫖姚，去折槐花度野橋。',32,'御定全唐詩/json/550.json','["來時健筆佐嫖姚，去折槐花度野橋。", "誰見尊前此惆悵，一聲歌盡路迢迢。"]'),
('yuding-61','宿僧院','趙嘏','唐','御定全唐诗','yuding','','[]','月滿長空樹滿霜，度雲低拂近簷床。',32,'御定全唐詩/json/550.json','["月滿長空樹滿霜，度雲低拂近簷床。", "林中夜半一聲磬，臥見高僧入道場。"]'),
('yuding-62','尋僧','趙嘏','唐','御定全唐诗','yuding','','[]','斜日橫窗起暗塵，水邊門戶閉閑春。',32,'御定全唐詩/json/550.json','["斜日橫窗起暗塵，水邊門戶閉閑春。", "千竿竹裏花枝動，只道無人似有人。"]'),
('yuding-63','經王先生故居','趙嘏','唐','御定全唐诗','yuding','','[]','晚波東去海茫茫，誰識蓬山不死鄉。',32,'御定全唐詩/json/550.json','["晚波東去海茫茫，誰識蓬山不死鄉。", "弄玉已歸蕭史去，碧樓紅樹倚斜陽。"]'),
('yuding-64','送從翁中丞奉使黠戛斯六首','趙嘏','唐','御定全唐诗','yuding','','[]','揚雄詞賦舉天聞，萬里油幢照塞雲。',192,'御定全唐詩/json/550.json','["揚雄詞賦舉天聞，萬里油幢照塞雲。", "僕射峰西幾千騎，一時迎著漢將軍。", "旌旗杳杳雁蕭蕭，春盡窮沙雪未消。", "料得堅昆受宣後，始知公主已歸朝。", "雖言窮北海雲中，屬國當時事不同。", "九姓如今盡臣妾，歸期那肯待秋風。", "牢山望斷絕塵氛，灩灩河西拂地雲。", "誰見魯儒持漢節，玉關降盡可汗軍。", "山川險易接胡塵，秦漢圖來或未真。", "自此盡知邊塞事，河湟更欲托何人。", "秦皇無策建長城，劉氏仍窮北路兵。", "若遇單于舊牙帳，卻應傷歎漢公卿。"]'),
('yuding-65','東亭柳','趙嘏','唐','御定全唐诗','yuding','','[]','拂水斜煙一萬條，幾隨春色倚河橋。',32,'御定全唐詩/json/550.json','["拂水斜煙一萬條，幾隨春色倚河橋。", "不知別後誰攀折，猶自風流勝舞腰。"]'),
('yuding-66','僧舍二首','趙嘏','唐','御定全唐诗','yuding','','[]','只言雙鬢未蹉跎，獨奈牛羊送日何。',64,'御定全唐詩/json/550.json','["只言雙鬢未蹉跎，獨奈牛羊送日何。", "禪客不歸車馬去，晚簷山色為誰多。", "溪上禪關水木間，水南山色與僧閑。", "春風盡日無來客，幽磬一聲高鳥還。"]'),
('yuding-67','新月','趙嘏','唐','御定全唐诗','yuding','','[]','玉鉤斜傍畫簷生，雲匣初開一寸明。',32,'御定全唐詩/json/550.json','["玉鉤斜傍畫簷生，雲匣初開一寸明。", "何事最能悲少婦，夜來依約落邊城。"]'),
('yuding-68','贈皇甫垣','趙嘏','唐','御定全唐诗','yuding','','[]','養由弓箭已無功，牢落生涯事事同。',32,'御定全唐詩/json/550.json','["養由弓箭已無功，牢落生涯事事同。", "相勸一杯寒食酒，幾多辛苦到春風。"]'),
('yuding-69','四祖寺','趙嘏','唐','御定全唐诗','yuding','','[]','千株松下雙峰寺，一盞燈前萬里身。',32,'御定全唐詩/json/550.json','["千株松下雙峰寺，一盞燈前萬里身。", "自為心猿不調伏，祖師元是世間人。"]'),
('yuding-70','聽蟬','趙嘏','唐','御定全唐诗','yuding','','[]','噪蟬聲亂日初曛，弦管樓中永不聞。',32,'御定全唐詩/json/550.json','["噪蟬聲亂日初曛，弦管樓中永不聞。", "獨奈愁人數莖發，故園秋隔五湖雲。"]'),
('yuding-71','寄遠','趙嘏','唐','御定全唐诗','yuding','','[]','禁鐘聲盡見棲禽，關塞迢迢故國心。',32,'御定全唐詩/json/550.json','["禁鐘聲盡見棲禽，關塞迢迢故國心。", "無限春愁莫相問，落花流水洞房深。"]'),
('yuding-72','池上','趙嘏','唐','御定全唐诗','yuding','','[]','正憐佳月夜深坐，池上暖回燕雁聲。',32,'御定全唐詩/json/550.json','["正憐佳月夜深坐，池上暖回燕雁聲。", "猶有漁舟系江岸，故人歸盡獨何情。"]'),
('yuding-73','春日書懷','趙嘏','唐','御定全唐诗','yuding','','[]','暖鶯春日舌難窮，枕上愁生曉聽中。',32,'御定全唐詩/json/550.json','["暖鶯春日舌難窮，枕上愁生曉聽中。", "應嫋綠窗殘夢斷，杏園零落滿枝風。"]'),
('yuding-74','贈別','趙嘏','唐','御定全唐诗','yuding','','[]','水邊秋草暮萋萋，欲駐殘陽恨馬蹄。',32,'御定全唐詩/json/550.json','["水邊秋草暮萋萋，欲駐殘陽恨馬蹄。", "曾是管弦同醉伴，一聲歌盡各東西。"]'),
('yuding-75','靈岩寺','趙嘏','唐','御定全唐诗','yuding','','[]','館娃宮伴千年寺，水闊雲多客到稀。',32,'御定全唐詩/json/550.json','["館娃宮伴千年寺，水闊雲多客到稀。", "聞說春來更惆悵，百花深處一僧歸。"]'),
('yuding-76','代人聽琴二首','趙嘏','唐','御定全唐诗','yuding','','[]','抱琴花夜不勝春，獨奏相思淚滿巾。',64,'御定全唐詩/json/550.json','["抱琴花夜不勝春，獨奏相思淚滿巾。", "第五指中心最恨，數聲嗚咽為何人。", "湘娥不葬九疑雲，楚水連天坐憶君。", "惟有啼烏舊名在，忍教嗚咽夜長聞。"]'),
('yuding-77','訪沈舍人不遇','趙嘏','唐','御定全唐诗','yuding','','[]','溪翁強訪紫微郎，曉鼓聲中滿鬢霜。',32,'御定全唐詩/json/550.json','["溪翁強訪紫微郎，曉鼓聲中滿鬢霜。", "知在禁闈人不見，好風飄下九天香。"]'),
('yuding-78','座上獻元相公','趙嘏','唐','御定全唐诗','yuding','','[]','寂寞堂前日又曛，陽臺去作不歸雲。',32,'御定全唐詩/json/550.json','["寂寞堂前日又曛，陽臺去作不歸雲。", "從來聞說沙吒利，今日青娥屬使君。"]'),
('yuding-79','遣興二首','趙嘏','唐','御定全唐诗','yuding','','[]','溪花入夏漸稀疏，雨氣如秋麥熟初。',64,'御定全唐詩/json/550.json','["溪花入夏漸稀疏，雨氣如秋麥熟初。", "終日苦吟人不會，海邊兄弟久無書。", "讀徹殘書弄水回，暮天何處笛聲哀。", "花前獨立無人會，依舊去年雙燕來。"]'),
('yuding-80','送李給事','趙嘏','唐','御定全唐诗','yuding','','[]','眼前軒冕是鴻毛，天上人間漫自勞。',32,'御定全唐詩/json/550.json','["眼前軒冕是鴻毛，天上人間漫自勞。", "脫卻朝衣獨歸去，青雲不及白雲高。"]'),
('yuding-81','宿僧舍','趙嘏','唐','御定全唐诗','yuding','','[]','高僧夜滴芙蓉漏，遠客窗含楊柳風。',32,'御定全唐詩/json/550.json','["高僧夜滴芙蓉漏，遠客窗含楊柳風。", "何處相逢話心地，月明身在磬聲中。"]'),
('yuding-82','吳門夢故山','趙嘏','唐','御定全唐诗','yuding','','[]','心熟家山夢不迷，孤峰寒繞一條溪。',32,'御定全唐詩/json/550.json','["心熟家山夢不迷，孤峰寒繞一條溪。", "秋窗覺後情無限，月墮館娃宮樹西。"]'),
('yuding-83','別李譜','趙嘏','唐','御定全唐诗','yuding','','[]','尊前路映暮塵紅，池上琴橫醉席風。',32,'御定全唐詩/json/550.json','["尊前路映暮塵紅，池上琴橫醉席風。", "今日別君如別鶴，聲容長在楚弦中。"]'),
('yuding-84','和杜侍郎題禪智寺南樓','趙嘏','唐','御定全唐诗','yuding','','[]','樓畔花枝拂檻紅，露天香動滿簾風。',32,'御定全唐詩/json/550.json','["樓畔花枝拂檻紅，露天香動滿簾風。", "誰知野寺遺鈿處，盡在相如春思中。"]'),
('yuding-85','發青山','趙嘏','唐','御定全唐诗','yuding','','[]','鳧鷖聲暖野塘春，鞍馬嘶風驛路塵。',32,'御定全唐詩/json/550.json','["鳧鷖聲暖野塘春，鞍馬嘶風驛路塵。", "一宿青山又前去，古來難得是閒人。"]'),
('yuding-86','入藍關','趙嘏','唐','御定全唐诗','yuding','','[]','微煙已辨秦中樹，遠夢更依江上臺。',32,'御定全唐詩/json/550.json','["微煙已辨秦中樹，遠夢更依江上臺。", "看落晚花還悵望，鯉魚時節入關來。"]'),
('yuding-87','落第寄沈詢','趙嘏','唐','御定全唐诗','yuding','','[]','穿楊力盡獨無功，華髮相期一夜中。',32,'御定全唐詩/json/550.json','["穿楊力盡獨無功，華髮相期一夜中。", "別到江頭舊吟處，為將雙淚問春風。"]'),
('yuding-88','送韋中丞','趙嘏','唐','御定全唐诗','yuding','','[]','二年恩意是春輝，清淨胸襟似者希。',32,'御定全唐詩/json/550.json','["二年恩意是春輝，清淨胸襟似者希。", "泣盡楚人多少淚，滿船唯載酒西歸。"]'),
('yuding-89','詠端正春樹','趙嘏','唐','御定全唐诗','yuding','','[]','一樹繁陰先著名，異花奇葉儼天成。',32,'御定全唐詩/json/550.json','["一樹繁陰先著名，異花奇葉儼天成。", "馬嵬此去無多地，只合楊妃墓上生。"]'),
('yuding-90','敘事獻同州侍禦三首','趙嘏','唐','御定全唐诗','yuding','','[]','青雲席中羅襪塵，白首江上吟詩人。',96,'御定全唐詩/json/550.json','["青雲席中羅襪塵，白首江上吟詩人。", "登龍不及三千士，虛度膺門二十春。", "平生望斷雲層層，紫府杳是他人登。", "卻應歸訪溪邊寺，說向當時同社僧。", "尊前誰伴謝公游，蓮嶽晴來翠滿樓。", "坐見一方金變化，獨吟紅藥對殘秋。"]'),
('yuding-91','婺州宴上留別','趙嘏','唐','御定全唐诗','yuding','','[]','雙溪樓影向雲橫，歌舞高臺晚更清。',32,'御定全唐詩/json/550.json','["雙溪樓影向雲橫，歌舞高臺晚更清。", "獨自下樓騎瘦馬，搖鞭重入亂蟬聲。"]'),
('yuding-92','別牛郎中門館','趙嘏','唐','御定全唐诗','yuding','','[]','整襟收淚別朱門，自料難酬顧念恩。',32,'御定全唐詩/json/550.json','["整襟收淚別朱門，自料難酬顧念恩。", "招得片魂騎匹馬，西風斜日入秋原。"]'),
('yuding-93','山中寄盧簡求','趙嘏','唐','御定全唐诗','yuding','','[]','竹西池上有花開，日日幽吟看又回。',32,'御定全唐詩/json/550.json','["竹西池上有花開，日日幽吟看又回。", "心憶郡中蕭記室，何時暫別醉鄉來。"]'),
('yuding-94','寄梁佾兄弟','趙嘏','唐','御定全唐诗','yuding','','[]','桃李春多翠影重，竹樓當月夜無風。',32,'御定全唐詩/json/550.json','["桃李春多翠影重，竹樓當月夜無風。", "荀家兄弟來還去，獨倚欄幹花露中。"]'),
('yuding-95','同州南亭陪劉侍郎送劉先輩','趙嘏','唐','御定全唐诗','yuding','','[]','處處雲隨晚望開，洞庭秋水管弦來。',32,'御定全唐詩/json/550.json','["處處雲隨晚望開，洞庭秋水管弦來。", "謝公待醉消離恨，莫惜臨川酒一杯。"]'),
('yuding-96','贈館驛劉巡官','趙嘏','唐','御定全唐诗','yuding','','[]','雲別青山馬踏塵，負才難覓作閒人。',32,'御定全唐詩/json/550.json','["雲別青山馬踏塵，負才難覓作閒人。", "莫言館驛無公事，詩酒能消一半春。"]'),
('yuding-97','贈解頭賈嵩','趙嘏','唐','御定全唐诗','yuding','','[]','賈生名跡忽無倫，十月長安看盡春。',32,'御定全唐詩/json/550.json','["賈生名跡忽無倫，十月長安看盡春。", "顧我先鳴還自笑，空沾一第是何人。"]'),
('yuding-98','題僧壁','趙嘏','唐','御定全唐诗','yuding','','[]','曉望疏林露滿巾，碧山秋寺屬閒人。',32,'御定全唐詩/json/550.json','["曉望疏林露滿巾，碧山秋寺屬閒人。", "溪頭盡日看紅葉，卻笑高僧衣有塵。"]'),
('yuding-99','沙溪館','趙嘏','唐','御定全唐诗','yuding','','[]','翠濕衣襟山滿樓，竹間溪水繞床流。',32,'御定全唐詩/json/550.json','["翠濕衣襟山滿樓，竹間溪水繞床流。", "行人莫羨郵亭吏，生向此中今白頭。"]'),
('yuding-100','李侍禦歸炭谷山居，同宿華嚴寺','趙嘏','唐','御定全唐诗','yuding','','[]','家在青山近玉京，日雲紅樹滿歸程。',32,'御定全唐詩/json/550.json','["家在青山近玉京，日雲紅樹滿歸程。", "相逢一宿最高寺，半夜翠微泉落聲。"]'),
('yuding-101','過噴玉泉','趙嘏','唐','御定全唐诗','yuding','','[]','平生半為山淹留，馬上欲去還回頭。',32,'御定全唐詩/json/550.json','["平生半為山淹留，馬上欲去還回頭。", "兩京塵路一雙鬢，不見玉泉千萬秋。"]'),
('yuding-102','漢陰庭樹','趙嘏','唐','御定全唐诗','yuding','','[]','掘溝引水澆蔬圃，插竹為籬護藥苗。',32,'御定全唐詩/json/550.json','["掘溝引水澆蔬圃，插竹為籬護藥苗。", "楊柳如絲風易亂，梅花似雪日難消。"]'),
('yuding-103','送王龜拾遺謝官後歸滻水山居','趙嘏','唐','御定全唐诗','yuding','','[]','水邊殘雪照亭台，台上風襟向雪開。',32,'御定全唐詩/json/550.json','["水邊殘雪照亭台，台上風襟向雪開。", "還似當時姓丁鶴，羽毛成後一歸來。"]'),
('yuding-104','宿長水主人','趙嘏','唐','御定全唐诗','yuding','','[]','白雲溪北叢岩東，樹石夜與潺湲通。',32,'御定全唐詩/json/550.json','["白雲溪北叢岩東，樹石夜與潺湲通。", "行人一宿翠微月，二十五弦聲滿風。"]'),
('yuding-105','寒食離白沙','趙嘏','唐','御定全唐诗','yuding','','[]','莫驚客路已經年，尚有青春一半妍。',32,'御定全唐詩/json/550.json','["莫驚客路已經年，尚有青春一半妍。", "試上方坦望春野，萬條楊柳拂青天。"]'),
('yuding-106','將發循州社日于所居館宴送','趙嘏','唐','御定全唐诗','yuding','','[]','浪花如雪疊江風，社過高秋萬恨中。',32,'御定全唐詩/json/550.json','["浪花如雪疊江風，社過高秋萬恨中。", "明日便隨江燕去，依依俱是故巢空。"]'),
('yuding-107','句','趙嘏','唐','御定全唐诗','yuding','','[]','浮雲悲晚翠，落日泣秋風。。',96,'御定全唐詩/json/550.json','["浮雲悲晚翠，落日泣秋風。。", "語風雙燕立，嫋樹百勞飛。", "松島鶴歸書信絕，橘洲風起夢魂香。", "徒知六國隨斤斧，莫有群儒定是非。（題秦皇句，", "一千里色中秋月，十萬軍聲半夜潮。。", "梁王舊館已秋色，珠履少年輕繡衣。"]'),
('yuding-0','漢堤詩','盧肇','唐','御定全唐诗','yuding','','[]','陰沴奸陽，來暴於襄。洎入大郛，波端若鋩。觸厚摧高，',275,'御定全唐詩/json/551.json','["陰沴奸陽，來暴於襄。洎入大郛，波端若鋩。觸厚摧高，", "惟恩若讎，母不能子。洪潰既涸，閈閎其虛。以隳我堵，", "流災降慝，天曷台怒。滔滔襄郊，捽我嬰孺。於惟餘甿，", "我公用諧，苴茅杖節。來視襄人，噢咻提挈。不日不月，", "公曰嗚呼，漢之有堤。實命襄人，不力乃力。則及乃身，", "必錫爾勤，襄人怡怡。聽命襄滸，背囊肩杵。奔走蹈舞，", "周旋上下，披峴斫楚。飛石挽土，舉築殷雷。駭汗霏雨，", "雜遝笑語，咸曰盧公，來賜我生。斯堤既成，蜿蜿而平。", "確爾山固，屹如雲橫。漢流雖狂，堅不可蝕。代千年億，", "萌渚不峻，此門不深。今複在茲，于漢之陰。斯堤已崇，", "繄公之功，赫焉如晝。捍此巨災，崒若京阜。天子賜之，"]'),
('yuding-1','題甘露寺','盧肇','唐','御定全唐诗','yuding','','[]','北固岩端寺，佳名自上臺。地從京口斷，山到海門回。',120,'御定全唐詩/json/551.json','["北固岩端寺，佳名自上臺。地從京口斷，山到海門回。", "曙色煙中滅，潮聲日下來。一隅通雉堞，千仞聳樓臺。", "林暗疑降虎，江空想度杯。福庭增氣象，仙磬落昭回。", "覺路花非染，流年景謾催。隋宮凋綠草，晉室散黃埃。", "西蜀波湍盡，東溟日月開。如登最高處，應得見蓬萊。"]'),
('yuding-2','江陵府初試澄心如水','盧肇','唐','御定全唐诗','yuding','','[]','丹心何所喻，唯水並清虛。莫測千尋底，難知一勺初。',72,'御定全唐詩/json/551.json','["丹心何所喻，唯水並清虛。莫測千尋底，難知一勺初。", "內明非有物，上善本無魚。澹泊隨高下，波瀾逐卷舒。", "養蒙方浩浩，出險每徐徐。若灌情田裏，常流盡不如。"]'),
('yuding-3','風不鳴條','盧肇','唐','御定全唐诗','yuding','','[]','習習和風至，過條不自鳴。暗通青律起，遠傍白蘋生。',72,'御定全唐詩/json/551.json','["習習和風至，過條不自鳴。暗通青律起，遠傍白蘋生。", "拂樹花仍落，經林鳥自驚。幾牽蘿蔓動，潛惹柳絲輕。", "入穀迷松響，開窗失竹聲。熏弦方在禦，萬國仰皇情。"]'),
('yuding-4','別宜春赴舉','盧肇','唐','御定全唐诗','yuding','','[]','秋天草木正蕭疏，西望秦關別舊居。筵上芳樽今日酒，',40,'御定全唐詩/json/551.json','["秋天草木正蕭疏，西望秦關別舊居。筵上芳樽今日酒，", "長短九霄飛直上，不教毛羽落空虛。"]'),
('yuding-5','射策後作','盧肇','唐','御定全唐诗','yuding','','[]','射策明時愧不才，敢期青律變寒灰。晴憐斷雁侵雲去，',40,'御定全唐詩/json/551.json','["射策明時愧不才，敢期青律變寒灰。晴憐斷雁侵雲去，", "曲江春淺人遊少，盡日看山醉獨回。"]'),
('yuding-6','和主司王起','盧肇','唐','御定全唐诗','yuding','','[]','嵩高降德為時生，洪筆三題造化名。鳳詔佇歸專北極，',40,'御定全唐詩/json/551.json','["嵩高降德為時生，洪筆三題造化名。鳳詔佇歸專北極，", "明日定知同相印，青衿新列柳間營。"]'),
('yuding-7','及第送潘圖歸宜春','盧肇','唐','御定全唐诗','yuding','','[]','三載皇都恨食貧，北溟今日化窮鱗。青雲乍喜逢知己，',40,'御定全唐詩/json/551.json','["三載皇都恨食貧，北溟今日化窮鱗。青雲乍喜逢知己，", "君歸為說龍門寺，雷雨初生電繞身。"]'),
('yuding-8','將歸宜春留題新安館','盧肇','唐','御定全唐诗','yuding','','[]','東裏如今號鄭鄉，西家昔日近丘牆。芸台四部添新學，',40,'御定全唐詩/json/551.json','["東裏如今號鄭鄉，西家昔日近丘牆。芸台四部添新學，", "猶張皂蓋歸蓬蓽，直謂時無許子將。"]'),
('yuding-9','競渡詩','盧肇','唐','御定全唐诗','yuding','','[]','石溪久住思端午，館驛樓前看發機。鼙鼓動時雷隱隱，',40,'御定全唐詩/json/551.json','["石溪久住思端午，館驛樓前看發機。鼙鼓動時雷隱隱，", "向道是龍剛不信，果然奪得錦標歸。"]'),
('yuding-10','除歙州途中寄座主王侍郎','盧肇','唐','御定全唐诗','yuding','','[]','忽忝專城奉六條，自憐出谷屢遷喬。驅車雖道還家近，',40,'御定全唐詩/json/551.json','["忽忝專城奉六條，自憐出谷屢遷喬。驅車雖道還家近，", "江天夜夜知消息，長見台星在碧霄。"]'),
('yuding-11','禦溝水','盧肇','唐','御定全唐诗','yuding','','[]','萬壑朝溟海，縈回歲月多。無如此溝水，咫尺奉天波。',24,'御定全唐詩/json/551.json','["萬壑朝溟海，縈回歲月多。無如此溝水，咫尺奉天波。"]'),
('yuding-12','楊柳枝','盧肇','唐','御定全唐诗','yuding','','[]','青鳥泉邊草木春，黃雲塞上是征人。',32,'御定全唐詩/json/551.json','["青鳥泉邊草木春，黃雲塞上是征人。", "歸來若得長條贈，不憚風霜與苦辛。"]'),
('yuding-13','新植紅茶花偶出被人移去以詩索之','盧肇','唐','御定全唐诗','yuding','','[]','嚴恨柴門一樹花，便隨香遠逐香車。',32,'御定全唐詩/json/551.json','["嚴恨柴門一樹花，便隨香遠逐香車。", "花如解語還應道，欺我郎君不在家。"]'),
('yuding-14','戲題','盧肇','唐','御定全唐诗','yuding','','[]','神女初離碧玉階，彤雲猶擁牡丹鞋。',32,'御定全唐詩/json/551.json','["神女初離碧玉階，彤雲猶擁牡丹鞋。", "知道相公憐玉腕，強將纖手整金釵。"]'),
('yuding-15','成名後作','盧肇','唐','御定全唐诗','yuding','','[]','桂在蟾宮不可攀，功成業熟也何難。',32,'御定全唐詩/json/551.json','["桂在蟾宮不可攀，功成業熟也何難。", "今朝折得東歸去，共與鄉閭年少看。"]'),
('yuding-16','登祝融寺蘭若','盧肇','唐','御定全唐诗','yuding','','[]','祝融絕頂萬餘層，策杖攀蘿步步登。',32,'御定全唐詩/json/551.json','["祝融絕頂萬餘層，策杖攀蘿步步登。", "行到月宮霞外寺，白雲相伴兩三僧。"]'),
('yuding-17','被謫連州','盧肇','唐','御定全唐诗','yuding','','[]','黃絹外孫翻得罪，華顛故老莫相嗤。',32,'御定全唐詩/json/551.json','["黃絹外孫翻得罪，華顛故老莫相嗤。", "連州萬里無親戚，舊識唯應有荔枝。"]'),
('yuding-18','謫後再書一絕','盧肇','唐','御定全唐诗','yuding','','[]','崆峒道士誤燒丹，赤鼠黃牙幾許難。',32,'御定全唐詩/json/551.json','["崆峒道士誤燒丹，赤鼠黃牙幾許難。", "墜墮閻浮南斗下，不知何事犯星官。"]'),
('yuding-19','題清遠峽觀音院二首','盧肇','唐','御定全唐诗','yuding','','[]','清潭洞澈深千丈，危岫攀蘿上幾層。',64,'御定全唐詩/json/551.json','["清潭洞澈深千丈，危岫攀蘿上幾層。", "秋盡更無黃葉樹，夜闌唯對白頭僧。", "風入古松添急雨，月臨虛檻背殘燈。", "老猿嘯狖還欺客，來撼窗前百尺藤。"]'),
('yuding-20','喜楊舍人入翰林','盧肇','唐','御定全唐诗','yuding','','[]','御筆親批翰長銜，夜開金殿送瑤緘。',32,'御定全唐詩/json/551.json','["御筆親批翰長銜，夜開金殿送瑤緘。", "平明玉案臨宣室，已見龍光出傅岩。"]'),
('yuding-21','謫連州書春牛榜子','盧肇','唐','御定全唐诗','yuding','','[]','陽和未解逐民憂，雪滿群山對白頭。',32,'御定全唐詩/json/551.json','["陽和未解逐民憂，雪滿群山對白頭。", "不得職田饑欲死，兒儂何事打春牛。"]'),
('yuding-22','送弟','盧肇','唐','御定全唐诗','yuding','','[]','去日家無擔石儲，汝須勤若事樵漁。',32,'御定全唐詩/json/551.json','["去日家無擔石儲，汝須勤若事樵漁。", "古人盡向塵中遠，白日耕田夜讀書。"]'),
('yuding-23','牧童','盧肇','唐','御定全唐诗','yuding','','[]','誰人得似牧童心，牛上橫眠秋聽深。',32,'御定全唐詩/json/551.json','["誰人得似牧童心，牛上橫眠秋聽深。", "時複往來吹一曲，何愁南北不知音。"]'),
('yuding-24','嘲小兒','盧肇','唐','御定全唐诗','yuding','','[]','貪生只愛眼前珍，不覺風光度歲頻。',32,'御定全唐詩/json/551.json','["貪生只愛眼前珍，不覺風光度歲頻。", "昨日見來騎竹馬，今朝早是有年人。"]'),
('yuding-25','金錢花','盧肇','唐','御定全唐诗','yuding','','[]','輪郭休誇四字書，紅窠寫出對庭除。',32,'御定全唐詩/json/551.json','["輪郭休誇四字書，紅窠寫出對庭除。", "時時買得佳人笑，本色金錢卻不如。"]'),
('yuding-26','木筆花','盧肇','唐','御定全唐诗','yuding','','[]','軟如新竹管初齊，粉膩紅輕樣可攜。',32,'御定全唐詩/json/551.json','["軟如新竹管初齊，粉膩紅輕樣可攜。", "誰與詩人偎檻看，好於箋墨並分題。"]'),
('yuding-27','句','盧肇','唐','御定全唐诗','yuding','','[]','君夢涔陽月，中秋憶棹歌。。',58,'御定全唐詩/json/551.json','["君夢涔陽月，中秋憶棹歌。。", "妙吹應諧鳳，工書定得鵝。（李群玉善急就章，", "亭邊古木晝陰陰，亭下寒潭百丈深。黃菊舊連陶令宅，"]'),
('yuding-0','塞下曲','丁棱','唐','御定全唐诗','yuding','','[]','北風鳴晚角，雨雪塞雲低。烽舉戰軍動，天寒征馬嘶。',48,'御定全唐詩/json/552.json','["北風鳴晚角，雨雪塞雲低。烽舉戰軍動，天寒征馬嘶。", "出營紅旆展，過磧暗沙迷。諸將年皆老，何時罷鼓鼙。"]'),
('yuding-1','和主司王起','丁棱','唐','御定全唐诗','yuding','','[]','公心獨立副天心，三轄春闈冠古今。蘭署門生皆入室，',40,'御定全唐詩/json/552.json','["公心獨立副天心，三轄春闈冠古今。蘭署門生皆入室，", "新有受恩江海客，坐聽朝夕繼為霖。"]'),
('yuding-2','和主司王起','高退之','唐','御定全唐诗','yuding','','[]','昔年桃李已滋榮，今日蘭蓀又發生。葑菲采時皆有道，',40,'御定全唐詩/json/552.json','["昔年桃李已滋榮，今日蘭蓀又發生。葑菲采時皆有道，", "何事感恩偏覺重，忽聞金榜扣柴荊。"]'),
('yuding-3','和主司王起','孟球','唐','御定全唐诗','yuding','','[]','當年門下化龍成，今日餘波進後生。仙籍共知推麗藻，',40,'御定全唐詩/json/552.json','["當年門下化龍成，今日餘波進後生。仙籍共知推麗藻，", "誰料羽毛方出谷，許教齊和九皋嗚。"]'),
('yuding-4','和主司王起','劉耕','唐','御定全唐诗','yuding','','[]','孔門頻建鑄顏功，紫綬青衿感激同。一簣勤勞成太華，',40,'御定全唐詩/json/552.json','["孔門頻建鑄顏功，紫綬青衿感激同。一簣勤勞成太華，", "慚和周郎應見顧，感知大造竟無窮。"]'),
('yuding-5','和主司王起','裴翻','唐','御定全唐诗','yuding','','[]','常將公道選群生，猶被春闈屈重名。文柄久持殊歲紀，',40,'御定全唐詩/json/552.json','["常將公道選群生，猶被春闈屈重名。文柄久持殊歲紀，", "乍得陽和如細柳，參差長近亞夫營。"]'),
('yuding-6','和主司王起','樊驤','唐','御定全唐诗','yuding','','[]','滿朝簪發半門生，又見新書甲乙名。孤進自今開道路，',40,'御定全唐詩/json/552.json','["滿朝簪發半門生，又見新書甲乙名。孤進自今開道路，", "忝受恩光同上客，惟將報德是經營。"]'),
('yuding-7','和主司王起','崔軒','唐','御定全唐诗','yuding','','[]','滿朝朱紫半門生，新榜勞人又得名。國器舊知收片玉，',40,'御定全唐詩/json/552.json','["滿朝朱紫半門生，新榜勞人又得名。國器舊知收片玉，", "共仰蓮峰聽雪唱，欲賡仙曲意怔營。"]'),
('yuding-8','和主司王起','蒯希逸','唐','御定全唐诗','yuding','','[]','一振聲華入紫薇，三開秦鏡照春闈。龍門舊列金章貴，',40,'御定全唐詩/json/552.json','["一振聲華入紫薇，三開秦鏡照春闈。龍門舊列金章貴，", "誰知散質多榮忝，鴛鷺清塵接布衣。"]'),
('yuding-9','句','蒯希逸','唐','御定全唐诗','yuding','','[]','蟾蜍醉裏破，蛺蝶夢中殘。。',37,'御定全唐詩/json/552.json','["蟾蜍醉裏破，蛺蝶夢中殘。。", "山險不曾離馬後，酒醒長見在床前。（希逸有僕武幹，"]'),
('yuding-10','望九華山','林滋','唐','御定全唐诗','yuding','','[]','茲山突出何怪奇，上有萬狀無凡姿。大者嶙峋若奔兕，',72,'御定全唐詩/json/552.json','["茲山突出何怪奇，上有萬狀無凡姿。大者嶙峋若奔兕，", "虛中始訝巨靈擘，陡處乍驚愚叟移。蘿煙石月相蔽虧，", "籲予比年愛靈境，到此始覺魂神馳。如何獨得百丈索，"]'),
('yuding-11','春望','林滋','唐','御定全唐诗','yuding','','[]','春海鏡長天，青郊麗上年。林光虛霽曉，山翠薄晴煙。',48,'御定全唐詩/json/552.json','["春海鏡長天，青郊麗上年。林光虛霽曉，山翠薄晴煙。", "氣暖禽聲變，風恬草色鮮。散襟披石磴，韶景自深憐。"]'),
('yuding-12','蠡澤旅懷','林滋','唐','御定全唐诗','yuding','','[]','誰言行旅日，況複桃花時。水即滄溟遠，星從天漢垂。',48,'御定全唐詩/json/552.json','["誰言行旅日，況複桃花時。水即滄溟遠，星從天漢垂。", "川光獨鳥暮，林色落英遲。豈是王程急，偏多遊子悲。"]'),
('yuding-13','宴韋侍禦新亭','林滋','唐','御定全唐诗','yuding','','[]','煙磴披青靄，風筵藉紫苔。花香淩桂醑，竹影落藤杯。',48,'御定全唐詩/json/552.json','["煙磴披青靄，風筵藉紫苔。花香淩桂醑，竹影落藤杯。", "鳴籟將歌遠，飛枝拂舞開。未愁留興晚，明月度雲來。"]'),
('yuding-14','人日','林滋','唐','御定全唐诗','yuding','','[]','春輝新入碧煙開，芳院初將穆景來。共向花前圖瑞勝，',40,'御定全唐詩/json/552.json','["春輝新入碧煙開，芳院初將穆景來。共向花前圖瑞勝，", "聞道宸游方命賞，應隨思賚喜昭回。"]'),
('yuding-15','和主司王起','林滋','唐','御定全唐诗','yuding','','[]','龍門一變荷生成，況是三傳不朽名。美譽早聞喧北闕，',40,'御定全唐詩/json/552.json','["龍門一變荷生成，況是三傳不朽名。美譽早聞喧北闕，", "從此青衿與朱紫，升堂侍宴更何營。"]'),
('yuding-16','聽蜀道士琴歌','李宣古','唐','御定全唐诗','yuding','','[]','至道不可見，正聲難得聞。忽逢羽客抱綠綺，',116,'御定全唐詩/json/552.json','["至道不可見，正聲難得聞。忽逢羽客抱綠綺，", "忽揮素爪畫七弦，蒼崖劈裂迸碎泉。憤聲高，怨聲咽，", "吹我神飛碧霄裏，牽我心靈入秋水。有如驅逐太古來，", "前弄嘯，後弄嚬，一舒一慘非冬春。從朝至暮聽不足，", "人間豈合值仙蹤，此別多應不再逢。抱琴卻上瀛洲去，"]'),
('yuding-17','和主司王起','李宣古','唐','御定全唐诗','yuding','','[]','恩光忽逐曉春生，金榜前頭忝姓名。三感至公裨造化，',40,'御定全唐詩/json/552.json','["恩光忽逐曉春生，金榜前頭忝姓名。三感至公裨造化，", "何處新詩添照灼，碧蓮峰下柳間營。"]'),
('yuding-18','杜司空席上賦','李宣古','唐','御定全唐诗','yuding','','[]','紅燈初上月輪高，照見堂前萬朵桃。觱栗調清銀象管，',40,'御定全唐詩/json/552.json','["紅燈初上月輪高，照見堂前萬朵桃。觱栗調清銀象管，", "爭奈夜深拋耍令，舞來挼去使人勞。"]'),
('yuding-19','賦寒食日亥時','李宣古','唐','御定全唐诗','yuding','','[]','人定朱門尚未開，初星粲粲照人回。',32,'御定全唐詩/json/552.json','["人定朱門尚未開，初星粲粲照人回。", "此時寒食無煙火，花柳蒼蒼月欲來。"]'),
('yuding-20','句','李宣古','唐','御定全唐诗','yuding','','[]','翠蓋不西來，池上天池歇。',37,'御定全唐詩/json/552.json','["翠蓋不西來，池上天池歇。", "冉冉池上煙。盈盈池上柳。生貴非道傍，不斷行人手。", "。"]'),
('yuding-21','風不鳴條','黃頗','唐','御定全唐诗','yuding','','[]','五緯起祥飆，無聲瑞聖朝。稍開含露蕊，才轉惹煙條。',72,'御定全唐詩/json/552.json','["五緯起祥飆，無聲瑞聖朝。稍開含露蕊，才轉惹煙條。", "密葉應潛變，低枝幾暗搖。林間鶯欲囀，花下蝶微飄。", "初滿沿堤草，因生逐水苗。太平無一事，天外奏虞韶。"]'),
('yuding-22','和主司王起','黃頗','唐','御定全唐诗','yuding','','[]','二十二年文教主，三千上士滿皇州。獨陪宣父蓬瀛奏，',40,'御定全唐詩/json/552.json','["二十二年文教主，三千上士滿皇州。獨陪宣父蓬瀛奏，", "千堂何處最榮美，朱紫環尊幾處酬。"]'),
('yuding-23','聞宜春諸舉子陪郡主登河梁玩月','黃頗','唐','御定全唐诗','yuding','','[]','一年秋半月當空，遙羨飛觴接庾公。虹影迥分銀漢上，',40,'御定全唐詩/json/552.json','["一年秋半月當空，遙羨飛觴接庾公。虹影迥分銀漢上，", "雖向東堂先折桂，不如賓席此時同。"]'),
('yuding-24','和主司王起','張道符','唐','御定全唐诗','yuding','','[]','三開文鏡繼芳聲，暗暗雲霄接去程。會壓洪波先得路，',40,'御定全唐詩/json/552.json','["三開文鏡繼芳聲，暗暗雲霄接去程。會壓洪波先得路，", "更許下才聽白雪，一枝今過郤詵榮。"]'),
('yuding-25','和主司王起','丘上卿','唐','御定全唐诗','yuding','','[]','常將公道選諸生，不是鴛鴻不得名。天上宴回聯步武，',40,'御定全唐詩/json/552.json','["常將公道選諸生，不是鴛鴻不得名。天上宴回聯步武，", "看著鳳池相繼入，都堂那肯滯關營。"]'),
('yuding-26','和主司王起','石貫','唐','御定全唐诗','yuding','','[]','重德由來為國生，五朝清顯冠公卿。風波久佇濟川楫，',40,'御定全唐詩/json/552.json','["重德由來為國生，五朝清顯冠公卿。風波久佇濟川楫，", "孔門弟子皆賢哲，誰料窮儒忝一名。"]'),
('yuding-27','和主司王起','李潛','唐','御定全唐诗','yuding','','[]','文學宗師心秤平，無私三用佐貞明。恩波舊是仙舟客，',40,'御定全唐詩/json/552.json','["文學宗師心秤平，無私三用佐貞明。恩波舊是仙舟客，", "羽毛方荷生成力，難繼鸞皇上漢聲。"]'),
('yuding-28','和主司王起','孟守','唐','御定全唐诗','yuding','','[]','科文又主守初時，光顯門生濟會期。美擅東堂登甲乙，',40,'御定全唐詩/json/552.json','["科文又主守初時，光顯門生濟會期。美擅東堂登甲乙，", "別有倍深知感士，曾經兩度得芳枝。"]'),
('yuding-29','和主司王起','唐思言','唐','御定全唐诗','yuding','','[]','儒雅皆傳德教行，幾崇浮俗贊文明。龍門昔上波濤遠，',40,'御定全唐詩/json/552.json','["儒雅皆傳德教行，幾崇浮俗贊文明。龍門昔上波濤遠，", "時方側席征賢急，況說歌謠近帝京。"]'),
('yuding-30','風不鳴條','戈牢','唐','御定全唐诗','yuding','','[]','旭日懸清景，微風在綠條。入松聲不發，度柳影空搖。',72,'御定全唐詩/json/552.json','["旭日懸清景，微風在綠條。入松聲不發，度柳影空搖。", "長養應潛變，扶疏每暗飄。有林時嫋嫋，無樹漸蕭蕭。", "慢逐青煙散，輕和瑞氣饒。豐年知有待，歌詠美唐堯。"]'),
('yuding-31','和主司王起','戈牢','唐','御定全唐诗','yuding','','[]','聖幹文德最稱賢，自古儒生少比肩。再啟龍門將二紀，',40,'御定全唐詩/json/552.json','["聖幹文德最稱賢，自古儒生少比肩。再啟龍門將二紀，", "正是感恩流涕日，但思旌旆碧峰前。"]'),
('yuding-32','風不鳴條','金厚載','唐','御定全唐诗','yuding','','[]','寂寂曙風生，遲遲散野輕。露華搖有滴，林葉嫋無聲。',72,'御定全唐詩/json/552.json','["寂寂曙風生，遲遲散野輕。露華搖有滴，林葉嫋無聲。", "暗剪叢芳發，空傳穀鳥鳴。悠揚韶景靜，澹蕩霽煙橫。", "遠水波瀾息，荒郊草樹榮。吾君垂至化，萬類共澄清。"]'),
('yuding-33','和主司王起','金厚載','唐','御定全唐诗','yuding','','[]','長慶曾收間世英，果居台閣冠公卿。天書再受恩波遠，',40,'御定全唐詩/json/552.json','["長慶曾收間世英，果居台閣冠公卿。天書再受恩波遠，", "小儒謬跡雲霄路，心仰蓮峰望太清。"]'),
('yuding-34','風不鳴條','王甚夷','唐','御定全唐诗','yuding','','[]','聖日祥風起，韶暉助發生。濛濛遙野色，嫋嫋細條輕。',72,'御定全唐詩/json/552.json','["聖日祥風起，韶暉助發生。濛濛遙野色，嫋嫋細條輕。", "荏弱看漸動，怡和吹不鳴。枝含餘露濕，林霽曉煙平。", "縹緲春光媚，悠揚景氣晴。康哉帝堯代，寰宇共澄清。"]'),
('yuding-35','和主司王起','王甚夷','唐','御定全唐诗','yuding','','[]','春闈帝念主生成，長慶公聞兩歲名。有蘊赤心分雨露，',40,'御定全唐詩/json/552.json','["春闈帝念主生成，長慶公聞兩歲名。有蘊赤心分雨露，", "遙仰高峰看白雪，多慚屬和意屏營。"]'),
('yuding-0','送李潛歸綿州覲省','姚鵠','唐','御定全唐诗','yuding','','[]','朱樓對翠微，紅旆出重扉。此地千人望，寥天一鶴歸。',48,'御定全唐詩/json/553.json','["朱樓對翠微，紅旆出重扉。此地千人望，寥天一鶴歸。", "雪封山崦白，鳥拂棧梁飛。誰比趨庭戀，驪珠耀彩衣。"]'),
('yuding-1','塞外寄張侍禦','姚鵠','唐','御定全唐诗','yuding','','[]','千里入黃雲，羈愁日日新。疏鐘關路曉，遠雨寒山春。',48,'御定全唐詩/json/553.json','["千里入黃雲，羈愁日日新。疏鐘關路曉，遠雨寒山春。", "南眺有歸雁，北來無故人。卻思陪宴處，回望與天鄰。"]'),
('yuding-2','曉發','姚鵠','唐','御定全唐诗','yuding','','[]','旅行宜早發，況複是南歸。月影緣山盡，鐘聲隔浦微。',48,'御定全唐詩/json/553.json','["旅行宜早發，況複是南歸。月影緣山盡，鐘聲隔浦微。", "殘星螢共失，落葉鳥和飛。去去渡南浦，村中人出稀。"]'),
('yuding-3','題終南山隱者居','姚鵠','唐','御定全唐诗','yuding','','[]','開門絕壑旁，躡蘚過花梁。路入峰巒影，風來芝朮香。',48,'御定全唐詩/json/553.json','["開門絕壑旁，躡蘚過花梁。路入峰巒影，風來芝朮香。", "夜吟明雪牖，春夢閉雲房。盡室更何有，一琴兼一觴。"]'),
('yuding-4','嘉川驛樓晚望','姚鵠','唐','御定全唐诗','yuding','','[]','樓壓寒江上，開簾對翠微。斜陽諸嶺暮，古渡一僧歸。',48,'御定全唐詩/json/553.json','["樓壓寒江上，開簾對翠微。斜陽諸嶺暮，古渡一僧歸。", "窗迥雲沖起，汀遙鳥背飛。誰言坐多倦，目極自忘機。"]'),
('yuding-5','送人歸吳','姚鵠','唐','御定全唐诗','yuding','','[]','東吳與上國，萬里路迢迢。為別晨昏久，全輕水陸遙。',48,'御定全唐詩/json/553.json','["東吳與上國，萬里路迢迢。為別晨昏久，全輕水陸遙。", "湘陰島上寺，楚色月中潮。到此一長望，知君積恨銷。"]'),
('yuding-6','送石貫歸湖州','姚鵠','唐','御定全唐诗','yuding','','[]','同志幸同年，高堂君獨還。齊榮恩未報，共隱事應閑。',48,'御定全唐詩/json/553.json','["同志幸同年，高堂君獨還。齊榮恩未報，共隱事應閑。", "訪寺臨湖岸，開樓見海山。洛中推二陸，莫久戀鄉關。"]'),
('yuding-7','送劉耕歸舒州','姚鵠','唐','御定全唐诗','yuding','','[]','四座莫紛紛，須臾岐路分。自從同得意，誰不惜離群。',48,'御定全唐詩/json/553.json','["四座莫紛紛，須臾岐路分。自從同得意，誰不惜離群。", "舊國連青海，歸程在白雲。棄繻當日路，應競看終軍。"]'),
('yuding-8','寄贈許璋少府','姚鵠','唐','御定全唐诗','yuding','','[]','若說君高道，何人更得如。公庭唯樹石，生計是琴書。',48,'御定全唐詩/json/553.json','["若說君高道，何人更得如。公庭唯樹石，生計是琴書。", "詩句峭無敵，文才清有餘。不知尺水內，爭滯北溟魚。"]'),
('yuding-9','寄雍陶先輩','姚鵠','唐','御定全唐诗','yuding','','[]','知音杳何處，書劄寄無由。獨宿月中寺，相思天畔樓。',48,'御定全唐詩/json/553.json','["知音杳何處，書劄寄無由。獨宿月中寺，相思天畔樓。", "露凝衰草白，螢度遠煙秋。悵望難歸枕，吟勞生夜愁。"]'),
('yuding-10','寄友人','姚鵠','唐','御定全唐诗','yuding','','[]','西風又開菊，久客意如何。舊國天涯遠，清砧月夜多。',48,'御定全唐詩/json/553.json','["西風又開菊，久客意如何。舊國天涯遠，清砧月夜多。", "明時難際會，急景易蹉跎。抱玉終須獻，誰言戀薜蘿。"]'),
('yuding-11','感懷陳情','姚鵠','唐','御定全唐诗','yuding','','[]','恩重空感激，何門誓殺身。謬曾分玉石，竟自困風塵。',48,'御定全唐詩/json/553.json','["恩重空感激，何門誓殺身。謬曾分玉石，竟自困風塵。", "陰穀非因暖，幽叢豈望春。升沉在言下，應念異他人。"]'),
('yuding-12','送程秀才下第歸蜀','姚鵠','唐','御定全唐诗','yuding','','[]','鶯遷與鶂退，十載泣岐分。蜀道重來老，巴猿此去聞。',48,'御定全唐詩/json/553.json','["鶯遷與鶂退，十載泣岐分。蜀道重來老，巴猿此去聞。", "曉程侵嶺雪，遠棧入溪雲。莫滯趨庭戀，榮親只待君。"]'),
('yuding-13','旱魚詞上苗相公','姚鵠','唐','御定全唐诗','yuding','','[]','似龍鱗已足，唯是欠登門。日裏腮猶濕，泥中目未昏。',48,'御定全唐詩/json/553.json','["似龍鱗已足，唯是欠登門。日裏腮猶濕，泥中目未昏。", "乞鋤防蟻穴，望水瀉金盆。他日能為雨，公田報此恩。"]'),
('yuding-14','野寺寓居即事二首','姚鵠','唐','御定全唐诗','yuding','','[]','南山色當戶，初日半簷時。鶴去臥看遠，僧來嫌起遲。',96,'御定全唐詩/json/553.json','["南山色當戶，初日半簷時。鶴去臥看遠，僧來嫌起遲。", "窗明雲影斷，庭曉樹陰移。何處題新句，連溪密葉垂。", "古寺更何有，當庭唯折幢。伴僧青蘚榻，對雨白雲窗。", "暝色生前嶺，離魂隔遠江。沙洲半藜草，飛鷺白雙雙。"]'),
('yuding-15','襄州獻盧尚書','姚鵠','唐','御定全唐诗','yuding','','[]','立事成功盡遠圖，一方獨與萬方殊。藩臣皆競師兵略，',40,'御定全唐詩/json/553.json','["立事成功盡遠圖，一方獨與萬方殊。藩臣皆競師兵略，", "即隨鳳詔歸何處，只是操持造化爐。"]'),
('yuding-16','將歸蜀留獻恩地僕射二首','姚鵠','唐','御定全唐诗','yuding','','[]','自持衡鏡采幽沈，此事常聞曠古今。危葉只將終委地，',80,'御定全唐詩/json/553.json','["自持衡鏡采幽沈，此事常聞曠古今。危葉只將終委地，", "明日還家盈眼血，定應回首即沾襟。", "江上長思狎釣翁，此心難與昨心同。自承丘壑新恩重，", "應憐死節無門效，永歎潛懷似轉蓬。"]'),
('yuding-17','隨州獻李侍禦二首','姚鵠','唐','御定全唐诗','yuding','','[]','彩筆曾專造化權，道尊翻向宦途閑。端居有地唯栽藥，',80,'御定全唐詩/json/553.json','["彩筆曾專造化權，道尊翻向宦途閑。端居有地唯栽藥，", "眾知聖主搜賢相，朝夕欲征黃霸還。", "再刖未甘何處說，但垂雙淚出咸秦。風塵匹馬來千里，", "今朝儻降非常顧，倒屐甯惟有古人。"]'),
('yuding-18','虢州獻楊抑卿二首','姚鵠','唐','御定全唐诗','yuding','','[]','蓋世英華更有誰，賦成傳寫遍坤維。名科累中求賢日，',80,'御定全唐詩/json/553.json','["蓋世英華更有誰，賦成傳寫遍坤維。名科累中求賢日，", "征歸詔下應非久，德望人情在鳳池。", "碧山曾共惜分陰，暗學相如賦上林。到此敢逾千里恨，", "一顧儻憐持苦節，更令何處問升沉。"]'),
('yuding-19','贈邊將','姚鵠','唐','御定全唐诗','yuding','','[]','三邊近日往來通，儘是將軍鎮撫功。兵統萬人為上將，',40,'御定全唐詩/json/553.json','["三邊近日往來通，儘是將軍鎮撫功。兵統萬人為上將，", "卻恨北荒沾雨露，無因掃盡虜庭空。"]'),
('yuding-20','送費煉師供奉赴上都','姚鵠','唐','御定全唐诗','yuding','','[]','縮地周遊不計程，古今應只有先生。已同化鶴臨華表，',40,'御定全唐詩/json/553.json','["縮地周遊不計程，古今應只有先生。已同化鶴臨華表，", "無因相逐朝天帝，空羨煙霞得送迎。"]'),
('yuding-21','和徐先輩秋日游涇州南亭呈三二同年','姚鵠','唐','御定全唐诗','yuding','','[]','多此歡情泛鷁舟，桂枝同折塞同遊。聲喧島上巢松鶴，',40,'御定全唐詩/json/553.json','["多此歡情泛鷁舟，桂枝同折塞同遊。聲喧島上巢松鶴，", "酒酣笑語秋風裏，誰道槐花更起愁。"]'),
('yuding-22','送黃頗歸袁','姚鵠','唐','御定全唐诗','yuding','','[]','莫倦連期在醉鄉，孔門多戀惜分行。文章聲價從來重，',40,'御定全唐詩/json/553.json','["莫倦連期在醉鄉，孔門多戀惜分行。文章聲價從來重，", "爐峰若上應相憶，不得同過惠遠房。"]'),
('yuding-23','和陝州參軍李通微首夏書懷呈同寮張裳段群二先輩','姚鵠','唐','御定全唐诗','yuding','','[]','公門何事更相牽，邵伯優賢任養閑。滿院落花從覆地，',40,'御定全唐詩/json/553.json','["公門何事更相牽，邵伯優賢任養閑。滿院落花從覆地，", "獨為高懷誰和繼，掾曹同處桂同攀。"]'),
('yuding-24','玉真觀尋趙尊師不遇','姚鵠','唐','御定全唐诗','yuding','','[]','羽客朝元晝掩扉，林中一徑雪中微。松陰繞院鶴相對，',40,'御定全唐詩/json/553.json','["羽客朝元晝掩扉，林中一徑雪中微。松陰繞院鶴相對，", "憑高目斷無消息，自醉自吟愁落暉。"]'),
('yuding-25','及第後上主司王起','姚鵠','唐','御定全唐诗','yuding','','[]','三年竭力向春闈，塞斷浮華眾路岐。盛選棟樑非昔日，',40,'御定全唐詩/json/553.json','["三年竭力向春闈，塞斷浮華眾路岐。盛選棟樑非昔日，", "莫道只陪金馬貴，相期更在鳳凰池。"]'),
('yuding-26','送賀知章入道','姚鵠','唐','御定全唐诗','yuding','','[]','若非堯運及垂衣，肯許巢由脫俗機。太液始同黃鶴下，',40,'御定全唐詩/json/553.json','["若非堯運及垂衣，肯許巢由脫俗機。太液始同黃鶴下，", "羈束慚無仙藥分，隨車空有夢魂飛。"]'),
('yuding-27','送友人出塞','姚鵠','唐','御定全唐诗','yuding','','[]','帝城春色著寒梅，去恨離懷醉不開。作別欲將何計免，',40,'御定全唐詩/json/553.json','["帝城春色著寒梅，去恨離懷醉不開。作別欲將何計免，", "有思莫忘清塞學，眾傳君負佐王才。"]'),
('yuding-28','送僧歸新羅','姚鵠','唐','御定全唐诗','yuding','','[]','淼淼萬餘裏，扁舟發落暉。滄溟何歲別，白首此時歸。',72,'御定全唐詩/json/553.json','["淼淼萬餘裏，扁舟發落暉。滄溟何歲別，白首此時歸。", "寒暑途中變，人煙嶺外稀。驚天巨鼇鬥，蔽日大鵬飛。", "雪入行砂屨，雲生坐石衣。漢風深習得，休恨本心違。"]'),
('yuding-29','奉和秘監從翁夏日陝州河亭晚望','姚鵠','唐','御定全唐诗','yuding','','[]','洪河何處望，一境在孤煙。極野如藍日，長波似鏡年。',72,'御定全唐詩/json/553.json','["洪河何處望，一境在孤煙。極野如藍日，長波似鏡年。", "捲簾花影裏，倚檻鶴巢邊。霞焰侵旌旆，灘聲雜管弦。", "鐘微來疊岫，帆遠落遙天。過客多相指，應疑會水仙。"]'),
('yuding-30','風不鳴條','姚鵠','唐','御定全唐诗','yuding','','[]','吾君理化清，上瑞報時平。曉吹何曾歇，柔條自不鳴。',72,'御定全唐詩/json/553.json','["吾君理化清，上瑞報時平。曉吹何曾歇，柔條自不鳴。", "花香知暗度，柳動覺潛生。只見低垂影，那聞擊觸聲。", "大王初溥暢，少女正輕盈。幸遇無私力，幽芳願發榮。"]'),
('yuding-31','書情獻知己','姚鵠','唐','御定全唐诗','yuding','','[]','日日恨何窮，巴雲舊隱空。一為棲寓客，二見北歸鴻。',120,'御定全唐詩/json/553.json','["日日恨何窮，巴雲舊隱空。一為棲寓客，二見北歸鴻。", "有道期攀桂，無門息轉蓬。賃居將罄比，乞食與僧同。", "花月登臨處，江山悵望中。眾皆輕病驥，誰肯救焦桐。", "坐惜春還至，愁吟夜每終。谷寒思變律，葉晚怯回風。", "謁蔡慚王粲，憐衡冀孔融。深恩知尚在，何處問窮通。"]'),
('yuding-32','和工部楊尚書重送絕句','姚鵠','唐','御定全唐诗','yuding','','[]','桂枝攀得獻庭闈，何似空懷楚橘歸。',32,'御定全唐詩/json/553.json','["桂枝攀得獻庭闈，何似空懷楚橘歸。", "好控扶搖早回首，人人思看大鵬飛。"]'),
('yuding-0','寄石橋僧','項斯','唐','御定全唐诗','yuding','','[]','逢師入山日，道在石橋邊。別後何人見，秋來幾處禪。',48,'御定全唐詩/json/554.json','["逢師入山日，道在石橋邊。別後何人見，秋來幾處禪。", "溪中雲隔寺，夜半雪添泉。生有天臺約，知無卻出緣。"]'),
('yuding-1','送歐陽袞歸閩中','項斯','唐','御定全唐诗','yuding','','[]','秦城幾年住，猶著故鄉衣。失意時相識，成名後獨歸。',48,'御定全唐詩/json/554.json','["秦城幾年住，猶著故鄉衣。失意時相識，成名後獨歸。", "海秋蠻樹黑，嶺夜瘴禽飛。為學心難滿，知君更掩扉。"]'),
('yuding-2','古觀','項斯','唐','御定全唐诗','yuding','','[]','置觀碑已折，看松年不分。洞中誰識藥，門外日添墳。',48,'御定全唐詩/json/554.json','["置觀碑已折，看松年不分。洞中誰識藥，門外日添墳。", "放去龜隨水，呼來鹿怕熏。壇邊見灰火，幾燒祭星文。"]'),
('yuding-3','題令狐處士溪居','項斯','唐','御定全唐诗','yuding','','[]','白髮已過半，無心離此溪。病嘗山藥遍，貧起草堂低。',48,'御定全唐詩/json/554.json','["白髮已過半，無心離此溪。病嘗山藥遍，貧起草堂低。", "為月窗從破，因詩壁重泥。近來常夜坐，寂寞與僧齊。"]'),
('yuding-4','送僧歸南嶽','項斯','唐','御定全唐诗','yuding','','[]','心知衡岳路，不怕去人稀。船裏誰鳴磬，沙頭自曝衣。',48,'御定全唐詩/json/554.json','["心知衡岳路，不怕去人稀。船裏誰鳴磬，沙頭自曝衣。", "有家從小別，是寺即言歸。料得逢春住，當禪雲滿扉。"]'),
('yuding-5','寧州春思','項斯','唐','御定全唐诗','yuding','','[]','失意離城早，邊城任見花。初為斷酒客，舊識賣書家。',48,'御定全唐詩/json/554.json','["失意離城早，邊城任見花。初為斷酒客，舊識賣書家。", "寒寺稀無雪，春風亦有沙。思歸頻入夢，即路不言賒。"]'),
('yuding-6','山友贈蘚花冠','項斯','唐','御定全唐诗','yuding','','[]','塵汙出華髮，慚君青蘚冠。此身閑未得，終日戴應難。',48,'御定全唐詩/json/554.json','["塵汙出華髮，慚君青蘚冠。此身閑未得，終日戴應難。", "好就松陰掛，宜當枕石看。會須尋道士，簪去繞霜壇。"]'),
('yuding-7','蠻家','項斯','唐','御定全唐诗','yuding','','[]','領得賣珠錢，還歸銅柱邊。看兒調小象，打鼓試新船。',48,'御定全唐詩/json/554.json','["領得賣珠錢，還歸銅柱邊。看兒調小象，打鼓試新船。", "醉後眠神樹，耕時語瘴煙。不逢寒便老，相問莫知年。"]'),
('yuding-8','早春題湖上顧氏新居二首','項斯','唐','御定全唐诗','yuding','','[]','近得水雲看，門長侵早開。到時微有雪，行處又無苔。',96,'御定全唐詩/json/554.json','["近得水雲看，門長侵早開。到時微有雪，行處又無苔。", "勸酒客初醉，留茶僧未來。每逢晴暖日，唯見乞花栽。", "門不當官道，行人到亦稀。故從餐後出，方至夜深歸。", "開篋揀書卷，掃床移褐衣。幾時同買宅，相近有柴扉。"]'),
('yuding-9','蒼梧雲氣','項斯','唐','御定全唐诗','yuding','','[]','何年化作愁，漠漠便難收。數點山能遠，平鋪水不流。',48,'御定全唐詩/json/554.json','["何年化作愁，漠漠便難收。數點山能遠，平鋪水不流。", "濕連湘竹暮，濃蓋舜墳秋。亦有思歸客，看來盡白頭。"]'),
('yuding-10','晚春花','項斯','唐','御定全唐诗','yuding','','[]','陰洞日光薄，花開不及時。當春無半樹，經燒足空枝。',48,'御定全唐詩/json/554.json','["陰洞日光薄，花開不及時。當春無半樹，經燒足空枝。", "疏與香風會，細將泉影移。此中人到少，開盡幾人知。"]'),
('yuding-11','宿胡氏溪亭','項斯','唐','御定全唐诗','yuding','','[]','獨住水聲裏，有亭無熱時。客來因月宿，床勢向山移。',48,'御定全唐詩/json/554.json','["獨住水聲裏，有亭無熱時。客來因月宿，床勢向山移。", "鶴睡松枝定，螢歸葛葉垂。寂寥猶欠伴，誰為報僧知。"]'),
('yuding-12','送華陰隱者','項斯','唐','御定全唐诗','yuding','','[]','往往到城市，得非征藥錢。世人空識面，弟子莫知年。',48,'御定全唐詩/json/554.json','["往往到城市，得非征藥錢。世人空識面，弟子莫知年。", "自說能醫死，相期更學仙。近來移住處，毛女舊峰前。"]'),
('yuding-13','落第後寄江南親友','項斯','唐','御定全唐诗','yuding','','[]','古巷槐陰合，愁多晝掩扉。獨存過江馬，強拂看花衣。',48,'御定全唐詩/json/554.json','["古巷槐陰合，愁多晝掩扉。獨存過江馬，強拂看花衣。", "送客心先醉，尋僧夜不歸。龍鍾易惆悵，莫遣寄書稀。"]'),
('yuding-14','欲別','項斯','唐','御定全唐诗','yuding','','[]','花時人欲別，每日醉櫻桃。買酒金錢盡，彈箏玉指勞。',48,'御定全唐詩/json/554.json','["花時人欲別，每日醉櫻桃。買酒金錢盡，彈箏玉指勞。", "歸期無歲月，客路有風濤。錦緞裁衣贈，麒麟落剪刀。"]'),
('yuding-15','留別張水部籍','項斯','唐','御定全唐诗','yuding','','[]','省中重拜別，兼領寄人書。已念此行遠，不應相問疏。',48,'御定全唐詩/json/554.json','["省中重拜別，兼領寄人書。已念此行遠，不應相問疏。", "子城西並宅，禦水北同渠。要取春前到，乘閑候起居。"]'),
('yuding-16','小古鏡','項斯','唐','御定全唐诗','yuding','','[]','字已無人識，唯應記鑄年。見來深似水，攜去重于錢。',48,'御定全唐詩/json/554.json','["字已無人識，唯應記鑄年。見來深似水，攜去重于錢。", "鸞翅巢空月，菱花遍小天。宮中照黃帝，曾得化為仙。"]'),
('yuding-17','題太白山隱者','項斯','唐','御定全唐诗','yuding','','[]','高居在幽嶺，人得見時稀。寫籙扃虛白，尋僧到翠微。',48,'御定全唐詩/json/554.json','["高居在幽嶺，人得見時稀。寫籙扃虛白，尋僧到翠微。", "掃壇星下宿，收藥雨中歸。從服小還後，自疑身解飛。"]'),
('yuding-18','病中懷王展先輩在天臺','項斯','唐','御定全唐诗','yuding','','[]','枕上用心靜，唯應改舊詩。強行休去早，暫臥起還遲。',48,'御定全唐詩/json/554.json','["枕上用心靜，唯應改舊詩。強行休去早，暫臥起還遲。", "因說來歸處，卻愁初病時。赤城山下寺，無計得相隨。"]'),
('yuding-19','鯉魚','項斯','唐','御定全唐诗','yuding','','[]','似龍鱗又足，只是欠登門。月裏腮猶濕，泥中目未昏。',48,'御定全唐詩/json/554.json','["似龍鱗又足，只是欠登門。月裏腮猶濕，泥中目未昏。", "乞鋤防蟻穴，望水寫金盆。他日能為雨，公田報此恩。"]'),
('yuding-20','子規','項斯','唐','御定全唐诗','yuding','','[]','遊魂自相叫，寧複記前身。飛過人家月，聲連客路春。',48,'御定全唐詩/json/554.json','["遊魂自相叫，寧複記前身。飛過人家月，聲連客路春。", "夢邊催曉急，愁外送風頻。自有沾花血，相和淚滴新。"]'),
('yuding-21','邊州客舍','項斯','唐','御定全唐诗','yuding','','[]','開門不成出，麥色遍前坡。自小詩名在，如今白髮多。',48,'御定全唐詩/json/554.json','["開門不成出，麥色遍前坡。自小詩名在，如今白髮多。", "經年無越信，終日厭蕃歌。近寺居僧少，春來亦懶過。"]'),
('yuding-22','贈道者','項斯','唐','御定全唐诗','yuding','','[]','晏來知養氣，度日語時稀。到處留丹井，終寒不絮衣。',48,'御定全唐詩/json/554.json','["晏來知養氣，度日語時稀。到處留丹井，終寒不絮衣。", "病鄉多惠藥，鬼俗有符威。自說身輕健，今年數夢飛。"]'),
('yuding-23','邊游','項斯','唐','御定全唐诗','yuding','','[]','古鎮門前去，長安路在東。天寒明堠火，日晚裂旗風。',48,'御定全唐詩/json/554.json','["古鎮門前去，長安路在東。天寒明堠火，日晚裂旗風。", "塞館皆無事，儒裝亦有弓。防秋故鄉卒，暫喜語音同。"]'),
('yuding-24','夜泊淮陰','項斯','唐','御定全唐诗','yuding','','[]','夜入楚家煙，煙中人未眠。望來淮岸盡，坐到酒樓前。',48,'御定全唐詩/json/554.json','["夜入楚家煙，煙中人未眠。望來淮岸盡，坐到酒樓前。", "燈影半臨水，箏聲多在船。乘流向東去，別此易經年。"]'),
('yuding-25','遠水','項斯','唐','御定全唐诗','yuding','','[]','渺渺浸天色，一邊生晚光。闊浮萍思遠，寒入雁愁長。',48,'御定全唐詩/json/554.json','["渺渺浸天色，一邊生晚光。闊浮萍思遠，寒入雁愁長。", "北極連平地，東流即故鄉。扁舟來宿處，仿佛似瀟湘。"]'),
('yuding-26','黃州暮愁','項斯','唐','御定全唐诗','yuding','','[]','淩澌沖淚眼，重疊自西來。即夜寒應合，非春暖不開。',48,'御定全唐詩/json/554.json','["淩澌沖淚眼，重疊自西來。即夜寒應合，非春暖不開。", "豈無登陸計，宜棄濟川材。願寄浮天外，高風萬里回。"]'),
('yuding-27','曉發昭應','項斯','唐','御定全唐诗','yuding','','[]','行人見雪愁，初作帝鄉遊。旅店開偏早，鄉帆去未收。',48,'御定全唐詩/json/554.json','["行人見雪愁，初作帝鄉遊。旅店開偏早，鄉帆去未收。", "燈殘催卷席，手冷怕梳頭。是物寒無色，湯泉正自流。"]'),
('yuding-28','贈金州姚合使君','項斯','唐','御定全唐诗','yuding','','[]','為郎名更重，領郡是蹉跎。官壁題詩盡，衙庭看鶴多。',48,'御定全唐詩/json/554.json','["為郎名更重，領郡是蹉跎。官壁題詩盡，衙庭看鶴多。", "城池連草塹，籬落帶椒坡。未覺旗幡貴，閑行觸處過。"]'),
('yuding-29','送殷中丞游邊','項斯','唐','御定全唐诗','yuding','','[]','話別無長夜，燈前聞曙鴉。已行難避雪，何處合逢花。',48,'御定全唐詩/json/554.json','["話別無長夜，燈前聞曙鴉。已行難避雪，何處合逢花。", "野寺門多閉，羌樓酒不賒。還須見邊將，誰擬靜塵沙。"]'),
('yuding-30','寄坐夏僧','項斯','唐','御定全唐诗','yuding','','[]','坐夏日偏長，知師在律堂。多因束帶熱，更憶剃頭涼。',48,'御定全唐詩/json/554.json','["坐夏日偏長，知師在律堂。多因束帶熱，更憶剃頭涼。", "苔色侵經架，松陰到簟床。還應煉詩句，借臥石池傍。"]'),
('yuding-31','寄盧式','項斯','唐','御定全唐诗','yuding','','[]','到處久南望，未知何日回。寄書頻到海，得夢忽聞雷。',48,'御定全唐詩/json/554.json','["到處久南望，未知何日回。寄書頻到海，得夢忽聞雷。", "嶺日當秋暗，蠻花近臘開。白身居瘴癘，誰不惜君才。"]'),
('yuding-32','日東病僧','項斯','唐','御定全唐诗','yuding','','[]','雲水絕歸路，來時風送船。不言身後事，猶坐病中禪。',48,'御定全唐詩/json/554.json','["雲水絕歸路，來時風送船。不言身後事，猶坐病中禪。", "深壁藏燈影，空窗出艾煙。已無鄉土信，起塔寺門前。"]'),
('yuding-33','泛溪','項斯','唐','御定全唐诗','yuding','','[]','溪船泛渺彌，漸覺滅炎輝。動水花連影，逢人鳥背飛。',48,'御定全唐詩/json/554.json','["溪船泛渺彌，漸覺滅炎輝。動水花連影，逢人鳥背飛。", "深猶見白石，涼好換生衣。未得多詩句，終須隔宿歸。"]'),
('yuding-34','送顧少府','項斯','唐','御定全唐诗','yuding','','[]','作尉年猶少，無辭去路賒。漁舟縣前泊，山吏日高衙。',48,'御定全唐詩/json/554.json','["作尉年猶少，無辭去路賒。漁舟縣前泊，山吏日高衙。", "幽景臨溪寺，秋蟬織杼家。行程須過越，先醉鏡湖花。"]'),
('yuding-35','咸陽別李處士','項斯','唐','御定全唐诗','yuding','','[]','古道自迢迢，咸陽離別橋。越人聞水處，秦樹帶霜朝。',48,'御定全唐詩/json/554.json','["古道自迢迢，咸陽離別橋。越人聞水處，秦樹帶霜朝。", "駐馬言難盡，分程望易遙。秋前未相見，此意轉蕭條。"]'),
('yuding-36','寄流人','項斯','唐','御定全唐诗','yuding','','[]','毒草不曾枯，長添客健無。霧開蠻市合，船散海城孤。',48,'御定全唐詩/json/554.json','["毒草不曾枯，長添客健無。霧開蠻市合，船散海城孤。", "象跡頻藏齒，龍涎遠蔽珠。家人秦地老，泣對日南圖。"]'),
('yuding-37','華頂道者','項斯','唐','御定全唐诗','yuding','','[]','仙人掌中住，生有上天期。已廢燒丹處，猶多種杏時。',48,'御定全唐詩/json/554.json','["仙人掌中住，生有上天期。已廢燒丹處，猶多種杏時。", "養龍於淺水，寄鶴在高枝。得道複無事，相逢盡日棋。"]'),
('yuding-38','酬從叔聽夜泉見寄','項斯','唐','御定全唐诗','yuding','','[]','夢罷更開戶，寒泉聲隔雲。共誰尋最遠，獨自坐偏聞。',48,'御定全唐詩/json/554.json','["夢罷更開戶，寒泉聲隔雲。共誰尋最遠，獨自坐偏聞。", "岩際和風滴，溪中泛月分。豈知當此夜，流念到江濆。"]'),
('yuding-39','和李用夫栽小松','項斯','唐','御定全唐诗','yuding','','[]','移來未換葉，已勝在空山。靜對心標直，遙吟境助閑。',48,'御定全唐詩/json/554.json','["移來未換葉，已勝在空山。靜對心標直，遙吟境助閑。", "影侵殘雪際，聲透小窗間。即聳淩空幹，翛翛豈易攀。"]'),
('yuding-40','哭南流人','項斯','唐','御定全唐诗','yuding','','[]','遙見南來使，江頭哭問君。臨終時有雪，旅葬處無雲。',48,'御定全唐詩/json/554.json','["遙見南來使，江頭哭問君。臨終時有雪，旅葬處無雲。", "官庫空收劍，蠻僧共起墳。知名人尚少，誰為錄遺文。"]'),
('yuding-41','經李白墓','項斯','唐','御定全唐诗','yuding','','[]','夜郎歸未老，醉死此江邊。葬闕官家禮，詩殘樂府篇。',48,'御定全唐詩/json/554.json','["夜郎歸未老，醉死此江邊。葬闕官家禮，詩殘樂府篇。", "游魂應到蜀，小碣豈旌賢。身沒猶何罪，遺墳野火燃。"]'),
('yuding-42','春夜樊川竹亭陪諸同年宴','項斯','唐','御定全唐诗','yuding','','[]','相知皆是舊，每恨獨遊頻。幸此同芳夕，寧辭倒醉身。',48,'御定全唐詩/json/554.json','["相知皆是舊，每恨獨遊頻。幸此同芳夕，寧辭倒醉身。", "燈光遙映燭，萼粉暗飄茵。明月分歸騎，重來更幾春。"]'),
('yuding-43','送僧','項斯','唐','御定全唐诗','yuding','','[]','靈山巡未遍，不作住持心。逢寺暫投宿，是山皆獨尋。',48,'御定全唐詩/json/554.json','["靈山巡未遍，不作住持心。逢寺暫投宿，是山皆獨尋。", "有時過靜界，在處想空林。從小即行腳，出家來至今。"]'),
('yuding-44','送蘇處士歸西山','項斯','唐','御定全唐诗','yuding','','[]','南游何所為，一篋又空歸。守道安清世，無心換白衣。',48,'御定全唐詩/json/554.json','["南游何所為，一篋又空歸。守道安清世，無心換白衣。", "深林蟬噪暮，絕頂客來稀。早晚重相見，論詩更及微。"]'),
('yuding-45','游爛柯山','項斯','唐','御定全唐诗','yuding','','[]','步步出塵氛，溪山別是春。壇邊時過鶴，棋處寂無人。',48,'御定全唐詩/json/554.json','["步步出塵氛，溪山別是春。壇邊時過鶴，棋處寂無人。", "訪古碑多缺，探幽路不真。翻疑歸去晚，清世累移晨。"]'),
('yuding-46','送友人之永嘉','項斯','唐','御定全唐诗','yuding','','[]','長貧知不易，去計擬何逃。相對人愁別，經過幾處勞。',48,'御定全唐詩/json/554.json','["長貧知不易，去計擬何逃。相對人愁別，經過幾處勞。", "城連沙岫遠，山斷夏雲高。猶想成詩處，秋燈半照濤。"]'),
('yuding-47','巴中逢故人','項斯','唐','御定全唐诗','yuding','','[]','勞思空積歲，偶會更無由。以分難相舍，將行且暫留。',48,'御定全唐詩/json/554.json','["勞思空積歲，偶會更無由。以分難相舍，將行且暫留。", "路岐何處極，江峽半猿愁。到此分南北，離懷豈易收。"]'),
('yuding-48','送歸江州友人初下第','項斯','唐','御定全唐诗','yuding','','[]','名高不俟召，收采獻君門。偶屈應緣數，他人盡為冤。',48,'御定全唐詩/json/554.json','["名高不俟召，收采獻君門。偶屈應緣數，他人盡為冤。", "新春城外路，舊隱水邊村。歸去無勞久，知君更待論。"]'),
('yuding-49','舜城懷古','項斯','唐','御定全唐诗','yuding','','[]','禪禹遜堯聰，巍巍盛此中。四隅咸啟聖，萬古賴成功。',48,'御定全唐詩/json/554.json','["禪禹遜堯聰，巍巍盛此中。四隅咸啟聖，萬古賴成功。", "道德去彌遠，山河勢不窮。停車一再拜，帝業即今同。"]'),
('yuding-50','送劉道士之成都嚴真觀','項斯','唐','御定全唐诗','yuding','','[]','嚴君名不朽，道出二經中。歸去精誠懇，還應夢寐通。',48,'御定全唐詩/json/554.json','["嚴君名不朽，道出二經中。歸去精誠懇，還應夢寐通。", "池台鏡定月，松檜雨餘風。想對靈玄憶，人間戀若空。"]'),
('yuding-51','漢南遇友人','項斯','唐','御定全唐诗','yuding','','[]','此身西複東，何計此相逢。夢盡吳越水，恨深襄漢鐘。',48,'御定全唐詩/json/554.json','["此身西複東，何計此相逢。夢盡吳越水，恨深襄漢鐘。", "積雲開去路，曙雪疊前峰。誰即知非舊，憐君忽見容。"]'),
('yuding-52','遊頭陀寺上方','項斯','唐','御定全唐诗','yuding','','[]','高步陟崔嵬，吟閑路惜回。寺知何代有，僧見梵天來。',48,'御定全唐詩/json/554.json','["高步陟崔嵬，吟閑路惜回。寺知何代有，僧見梵天來。", "暮靄連沙積，餘霞遍檻開。更期招靜者，長嘯上南台。"]'),
('yuding-53','送友人游河東','項斯','唐','御定全唐诗','yuding','','[]','停車曉燭前，一語幾潸然。路去干戈日，鄉遙饑饉年。',48,'御定全唐詩/json/554.json','["停車曉燭前，一語幾潸然。路去干戈日，鄉遙饑饉年。", "湖波晴見雁，槐驛晚無蟬。莫縱經時住，東南書信偏。"]'),
('yuding-54','中秋夜懷','項斯','唐','御定全唐诗','yuding','','[]','趨馳早晚休，一歲又殘秋。若只如今日，何難至白頭。',48,'御定全唐詩/json/554.json','["趨馳早晚休，一歲又殘秋。若只如今日，何難至白頭。", "滄波歸處遠，旅食尚邊愁。賴見前賢說，窮通不自由。"]'),
('yuding-55','寄富春孫路處士','項斯','唐','御定全唐诗','yuding','','[]','平生醉與吟，誰是見君心。上國一歸去，滄江閑至今。',48,'御定全唐詩/json/554.json','["平生醉與吟，誰是見君心。上國一歸去，滄江閑至今。", "鐘繁秋寺近，峰闊晚濤深。疏放長如此，何人長得尋。"]'),
('yuding-56','送客歸新羅','項斯','唐','御定全唐诗','yuding','','[]','君家滄海外，一別見何因。風土雖知教，程途自致貧。',48,'御定全唐詩/json/554.json','["君家滄海外，一別見何因。風土雖知教，程途自致貧。", "浸天波色晚，橫笛鳥行春。明發千檣下，應無更遠人。"]'),
('yuding-57','杭州江亭留題登眺','項斯','唐','御定全唐诗','yuding','','[]','處處日馳銷，憑軒夕似朝。漁翁閑鼓棹，沙鳥戲迎潮。',48,'御定全唐詩/json/554.json','["處處日馳銷，憑軒夕似朝。漁翁閑鼓棹，沙鳥戲迎潮。", "樹間津亭密，城連塢寺遙。因誰報隱者，向此得耕樵。"]'),
('yuding-58','荊州夜與友親相遇','項斯','唐','御定全唐诗','yuding','','[]','山海兩分岐，停舟偶似期。別來何限意，相見卻無辭。',48,'御定全唐詩/json/554.json','["山海兩分岐，停舟偶似期。別來何限意，相見卻無辭。", "坐永神凝夢，愁繁鬢欲絲。趨名易遲晚，此去莫經時。"]'),
('yuding-59','送友人游邊','項斯','唐','御定全唐诗','yuding','','[]','方春到帝京，有戀有愁並。萬里江海思，半年沙塞程。',48,'御定全唐詩/json/554.json','["方春到帝京，有戀有愁並。萬里江海思，半年沙塞程。", "綠陰斜向驛，殘照遠侵城。自可資新課，還期振盛名。"]'),
('yuding-60','題贈宣州亢拾遺','項斯','唐','御定全唐诗','yuding','','[]','傳騎一何催，山門晝未開。高人終避世，聖主不遺才。',48,'御定全唐詩/json/554.json','["傳騎一何催，山門晝未開。高人終避世，聖主不遺才。", "坐次欹臨水，門中獨舉杯。誰為旦夕侶，深寺數僧來。"]'),
('yuding-61','姚氏池亭','項斯','唐','御定全唐诗','yuding','','[]','池館饒嘉致，幽人愜所閑。筱風能動浪，岸樹不遮山。',48,'御定全唐詩/json/554.json','["池館饒嘉致，幽人愜所閑。筱風能動浪，岸樹不遮山。", "嘯檻魚驚後，眠窗鶴語間。何須說廬阜，深處更躋攀。"]'),
('yuding-62','送友人之江南','項斯','唐','御定全唐诗','yuding','','[]','東南路苦辛，去路見無因。萬里此相送，故交誰更親。',48,'御定全唐詩/json/554.json','["東南路苦辛，去路見無因。萬里此相送，故交誰更親。", "日浮汀草綠，煙霽海山春。握手無別贈，為予書劄頻。"]'),
('yuding-63','彭蠡湖春望','項斯','唐','御定全唐诗','yuding','','[]','湖亭東極望，遠棹不須回。遍草新湖落，連天眾雁來。',48,'御定全唐詩/json/554.json','["湖亭東極望，遠棹不須回。遍草新湖落，連天眾雁來。", "蘆洲殘照盡，雲障積煙開。更想鴟夷子，扁舟安在哉。"]'),
('yuding-64','聞友人會裴明府縣樓','項斯','唐','御定全唐诗','yuding','','[]','閑閣雨吹塵，陶家揖上賓。湖山萬疊翠，門樹一行春。',48,'御定全唐詩/json/554.json','["閑閣雨吹塵，陶家揖上賓。湖山萬疊翠，門樹一行春。", "景遍歸簷燕，歌喧已醉身。登臨興不足，喜有數來因。"]'),
('yuding-65','歸家山行','項斯','唐','御定全唐诗','yuding','','[]','獻賦才何拙，經時不恥歸。能知此意是，甘取眾人非。',48,'御定全唐詩/json/554.json','["獻賦才何拙，經時不恥歸。能知此意是，甘取眾人非。", "遍隴耕無圃，緣溪釣有磯。此懷難自遣，期在振儒衣。"]'),
('yuding-66','長安書懷呈知己','項斯','唐','御定全唐诗','yuding','','[]','江湖歸不易，京邑計長貧。獨夜有知己，論心無故人。',48,'御定全唐詩/json/554.json','["江湖歸不易，京邑計長貧。獨夜有知己，論心無故人。", "一燈愁裏夢，九陌病中春。為問清平日，無門致出身。"]'),
('yuding-67','聞蟬','項斯','唐','御定全唐诗','yuding','','[]','動葉複驚神，聲聲斷續勻。坐來同聽者，俱是未歸人。',48,'御定全唐詩/json/554.json','["動葉複驚神，聲聲斷續勻。坐來同聽者，俱是未歸人。", "一棹三湘浪，單車二蜀塵。傷秋各有日，千可念因循。"]'),
('yuding-68','李處士道院南樓','項斯','唐','御定全唐诗','yuding','','[]','霜晚複秋殘，樓明近遠山。滿壺邀我醉，一榻為僧閑。',48,'御定全唐詩/json/554.json','["霜晚複秋殘，樓明近遠山。滿壺邀我醉，一榻為僧閑。", "樹簇孤汀眇，帆欹積浪間。從容更南望，殊欲外人寰。"]'),
('yuding-69','送顧非熊及第歸茅山','項斯','唐','御定全唐诗','yuding','','[]','吟詩三十載，成此一名難。自有恩門入，全無帝裏歡。',48,'御定全唐詩/json/554.json','["吟詩三十載，成此一名難。自有恩門入，全無帝裏歡。", "湖光愁裏碧，岩景夢中寒。到後松杉月，何人共曉看。"]'),
('yuding-70','春日題李中丞樊川別墅','項斯','唐','御定全唐诗','yuding','','[]','心知受恩地，到此亦裴回。上路移時立，中軒隔宿來。',48,'御定全唐詩/json/554.json','["心知受恩地，到此亦裴回。上路移時立，中軒隔宿來。", "川光通沼沚，寺影帶樓臺。無限成蹊樹，花多向客開。"]'),
('yuding-71','龍州與韓將軍夜會','項斯','唐','御定全唐诗','yuding','','[]','庭綠草纖纖，邊州白露沾。別歌緣劍起，客淚是愁添。',48,'御定全唐詩/json/554.json','["庭綠草纖纖，邊州白露沾。別歌緣劍起，客淚是愁添。", "見月鵲啼樹，避風雲滿簾。將軍盡尊酒，樓上賦星占。"]'),
('yuding-72','途中逢友人','項斯','唐','御定全唐诗','yuding','','[]','長大有南北，山川各所之。相逢孤館夜，共憶少年時。',48,'御定全唐詩/json/554.json','["長大有南北，山川各所之。相逢孤館夜，共憶少年時。", "爛醉百花酒，狂題幾首詩。來朝又分袂，後會鬢應絲。"]'),
('yuding-73','送友人下第歸襄陽','項斯','唐','御定全唐诗','yuding','','[]','失意已春殘，歸愁與別難。山分關路細，江繞夜城寒。',48,'御定全唐詩/json/554.json','["失意已春殘，歸愁與別難。山分關路細，江繞夜城寒。", "草色連晴阪，鼉聲離曉灘。差池是秋賦，何以暫懷安。"]'),
('yuding-74','宿山寺','項斯','唐','御定全唐诗','yuding','','[]','栗葉重重複翠微，黃昏溪上語人稀。月明古寺客初到，',40,'御定全唐詩/json/554.json','["栗葉重重複翠微，黃昏溪上語人稀。月明古寺客初到，", "中宵能得幾時睡，又被鐘聲催著衣。"]'),
('yuding-75','病鶴','項斯','唐','御定全唐诗','yuding','','[]','青雲有意力猶微，豈料低回得所依。幸念翅因風雨困，',40,'御定全唐詩/json/554.json','["青雲有意力猶微，豈料低回得所依。幸念翅因風雨困，", "縱使他年引仙駕，主人恩在亦應歸。"]'),
('yuding-76','夢仙','項斯','唐','御定全唐诗','yuding','','[]','昨宵魂夢到仙津，得見蓬山不死人。雲葉許裁成野服，',40,'御定全唐詩/json/554.json','["昨宵魂夢到仙津，得見蓬山不死人。雲葉許裁成野服，", "次第引看行未遍，浮光牽入世間塵。"]'),
('yuding-77','古扇','項斯','唐','御定全唐诗','yuding','','[]','昨日裁成奪夏威，忽逢秋節便相違。寒塵妒盡秦王女，',40,'御定全唐詩/json/554.json','["昨日裁成奪夏威，忽逢秋節便相違。寒塵妒盡秦王女，", "千年蕭瑟關人事，莫語當時掩淚歸。"]'),
('yuding-78','涇州聽張處士彈琴','項斯','唐','御定全唐诗','yuding','','[]','邊州獨夜正思鄉，君又彈琴在客堂。',32,'御定全唐詩/json/554.json','["邊州獨夜正思鄉，君又彈琴在客堂。", "仿佛不離燈影外，似聞流水到瀟湘。"]'),
('yuding-79','贈別','項斯','唐','御定全唐诗','yuding','','[]','魚在深泉鳥在雲，從來只得影相親。',32,'御定全唐詩/json/554.json','["魚在深泉鳥在雲，從來只得影相親。", "他時縱有逢君處，應作人間白髮身。"]'),
('yuding-80','對鱠','項斯','唐','御定全唐诗','yuding','','[]','行到鱸魚鄉里時，鱠盤如雪怕風吹。',32,'御定全唐詩/json/554.json','["行到鱸魚鄉里時，鱠盤如雪怕風吹。", "猶憐醉裏江南路，馬上垂鞭學釣時。"]'),
('yuding-81','憶朝陽峰前居','項斯','唐','御定全唐诗','yuding','','[]','每憶閑眠處，朝陽最上峰。溪僧來自遠，林路出無蹤。',96,'御定全唐詩/json/554.json','["每憶閑眠處，朝陽最上峰。溪僧來自遠，林路出無蹤。", "敗褐黏苔遍，新題出石重。霞光侵曙發，嵐翠近秋濃。", "健羨機能破，安危道不逢。雪殘猿到閣，庭午鶴離松。", "此地虛為別，人間久未容。何時無一事，卻去養疏慵。"]'),
('yuding-82','暮上瞿唐峽','項斯','唐','御定全唐诗','yuding','','[]','自古艱難地，孤舟旦暮程。獨愁空托命，省已是輕生。',72,'御定全唐詩/json/554.json','["自古艱難地，孤舟旦暮程。獨愁空托命，省已是輕生。", "有樹皆相倚，無岩不倒傾。蛟螭波數怒，鬼怪火潛明。", "履道知無負，離心自要驚。何年面骨肉，細話苦辛行。"]'),
('yuding-83','和李中丞醉中期王征君月夜同游滻水舊居','項斯','唐','御定全唐诗','yuding','','[]','醉後情俱遠，難忘素滻間。照花深處月，當戶舊時山。',48,'御定全唐詩/json/554.json','["醉後情俱遠，難忘素滻間。照花深處月，當戶舊時山。", "事想同清話，歡期一破顏。風流還愛竹，此夜尚思閑。"]'),
('yuding-84','濁水求珠','項斯','唐','御定全唐诗','yuding','','[]','靈魄自沉浮，從來任濁流。願從深處得，不向暗中投。',72,'御定全唐詩/json/554.json','["靈魄自沉浮，從來任濁流。願從深處得，不向暗中投。", "圓月時堪惜，滄波路可求。沙尋龍窟遠，泥訪蚌津幽。", "是寶終知貴，唯恩且用酬。如能在公掌，的不負明眸。"]'),
('yuding-85','江村夜泊','項斯','唐','御定全唐诗','yuding','','[]','日落江路黑，前村人語稀。幾家深樹裏，一火夜漁歸。',24,'御定全唐詩/json/554.json','["日落江路黑，前村人語稀。幾家深樹裏，一火夜漁歸。"]'),
('yuding-86','落第後歸覲喜逢僧再陽','項斯','唐','御定全唐诗','yuding','','[]','相逢須強笑，人世別離頻。去曉長侵月，歸鄉動隔春。',96,'御定全唐詩/json/554.json','["相逢須強笑，人世別離頻。去曉長侵月，歸鄉動隔春。", "見僧心暫靜，從俗事多屯。宇宙詩名小，山河客路新。", "翠桐猶入爨，青鏡未辭塵。逸足常思驥，隨群且退鱗。", "宴乖紅杏寺，愁在綠楊津。羞病難為藥，開眉懶顧人。"]'),
('yuding-87','送越僧元瑞','項斯','唐','御定全唐诗','yuding','','[]','靜中無伴侶，今亦獨隨緣。昨夜離空室，焚香淨去船。',24,'御定全唐詩/json/554.json','["靜中無伴侶，今亦獨隨緣。昨夜離空室，焚香淨去船。"]'),
('yuding-88','舊宮人','項斯','唐','御定全唐诗','yuding','','[]','自出先皇玉殿中，衣裳不更染深紅。宮釵折盡垂空鬢，',40,'御定全唐詩/json/554.json','["自出先皇玉殿中，衣裳不更染深紅。宮釵折盡垂空鬢，", "如今還向城邊住，禦水東流意不通。"]'),
('yuding-89','夢游仙','項斯','唐','御定全唐诗','yuding','','[]','夢遊飛上天家樓，珠箔當風掛玉鉤。鸚鵡隔簾呼再拜，',40,'御定全唐詩/json/554.json','["夢遊飛上天家樓，珠箔當風掛玉鉤。鸚鵡隔簾呼再拜，", "將謂便長於此地，雞聲入耳所堪愁。"]'),
('yuding-90','送宮人入道','項斯','唐','御定全唐诗','yuding','','[]','願隨仙女董雙成，王母前頭作伴行。初戴玉冠多誤拜，',40,'御定全唐詩/json/554.json','["願隨仙女董雙成，王母前頭作伴行。初戴玉冠多誤拜，", "旦暮焚香繞壇上，步虛猶作按歌聲。"]'),
('yuding-91','長安退將','項斯','唐','御定全唐诗','yuding','','[]','塞晚沖沙損眼明，歸來養病住秦京。上高樓閣看星坐，',40,'御定全唐詩/json/554.json','["塞晚沖沙損眼明，歸來養病住秦京。上高樓閣看星坐，", "翠眉紅臉和回鶻，惆悵中原不用兵。"]'),
('yuding-92','遙裝夜','項斯','唐','御定全唐诗','yuding','','[]','卷席貧拋壁下床，且鋪他處對燈光。欲行千里從今夜，',40,'御定全唐詩/json/554.json','["卷席貧拋壁下床，且鋪他處對燈光。欲行千里從今夜，", "誰知更有芙蓉浦，南去令人愁思長。"]'),
('yuding-93','送苗七求職','項斯','唐','御定全唐诗','yuding','','[]','相逢未得三回笑，風送離情入剪刀。客路最能銷日月，',40,'御定全唐詩/json/554.json','["相逢未得三回笑，風送離情入剪刀。客路最能銷日月，", "去去緣多山與海，鶴身寧肯為飛勞。"]'),
('yuding-94','山行','項斯','唐','御定全唐诗','yuding','','[]','青櫪林深亦有人，一渠流水數家分。山當日午回峰影，',40,'御定全唐詩/json/554.json','["青櫪林深亦有人，一渠流水數家分。山當日午回峰影，", "行逢賣藥歸來客，不惜相隨入島雲。"]'),
('yuding-95','題永忻寺影堂','項斯','唐','御定全唐诗','yuding','','[]','不遇修寺日，無錢入影堂。故來空禮拜，臨去重添香。',48,'御定全唐詩/json/554.json','["不遇修寺日，無錢入影堂。故來空禮拜，臨去重添香。", "僧得名難近，燈傳火已長。發心依止後，借住有鄰房。"]'),
('yuding-96','獻令狐相公，時相公郊壇行事回','項斯','唐','御定全唐诗','yuding','','[]','鶚在卿雲冰在壺，代天才業本籲謨。榮同伊陟傳朱戶，',40,'御定全唐詩/json/554.json','["鶚在卿雲冰在壺，代天才業本籲謨。榮同伊陟傳朱戶，", "不知機務時多暇，還許詩家屬和無。"]'),
('yuding-97','句','項斯','唐','御定全唐诗','yuding','','[]','佳人背江坐，眉際列煙樹。。',72,'御定全唐詩/json/554.json','["佳人背江坐，眉際列煙樹。。", "馬蹄沒青莎，船跡成空波。", "春風吹兩意，何意更相值。（《古意》。", "以上並見張為《主客圖》）", "更望會稽何處是，沙連竹箭白鷳群。。"]'),
('yuding-0','校獵曲','馬戴','唐','御定全唐诗','yuding','','[]','楚子畋郊野，布罟籠天涯。浮雲張作羅，萬草結成罝。',72,'御定全唐詩/json/555.json','["楚子畋郊野，布罟籠天涯。浮雲張作羅，萬草結成罝。", "意在絕飛鳥，臂弓腰鏌鋣。遠將射勾踐，次欲誅夫差。", "壯志一朝盡，他□□繁華。當時能獵賢，保國兼保家。"]'),
('yuding-1','蠻家','馬戴','唐','御定全唐诗','yuding','','[]','領得賣珠錢，還歸銅柱邊。看兒調小象，打鼓放新船。',48,'御定全唐詩/json/555.json','["領得賣珠錢，還歸銅柱邊。看兒調小象，打鼓放新船。", "醉後眠神樹，耕時語瘴煙。又逢衰蹇老，相問莫知年。"]'),
('yuding-2','春思','馬戴','唐','御定全唐诗','yuding','','[]','初日照楊柳，玉樓含翠陰。啼春獨鳥思，望遠佳人心。',48,'御定全唐詩/json/555.json','["初日照楊柳，玉樓含翠陰。啼春獨鳥思，望遠佳人心。", "幽怨貯瑤瑟，韶光凝碧林。所思曾不見，芳草意空深。"]'),
('yuding-3','送從叔赴南海幕','馬戴','唐','御定全唐诗','yuding','','[]','洞庭秋色起，哀狖更難聞。身往海邊郡，帆懸天際雲。',48,'御定全唐詩/json/555.json','["洞庭秋色起，哀狖更難聞。身往海邊郡，帆懸天際雲。", "炎州羅翠鳥，瘴嶺控蠻軍。信息來非易，堪悲此路分。"]'),
('yuding-4','江行留別','馬戴','唐','御定全唐诗','yuding','','[]','吳楚半秋色，渡江逢葦花。雲侵帆影盡，風逼雁行斜。',48,'御定全唐詩/json/555.json','["吳楚半秋色，渡江逢葦花。雲侵帆影盡，風逼雁行斜。", "返照開嵐翠，寒潮蕩浦沙。余將何所往，海嶠擬營家。"]'),
('yuding-5','將別寄友人','馬戴','唐','御定全唐诗','yuding','','[]','帝鄉歸未得，辛苦事羈遊。別館一尊酒，客程千里秋。',48,'御定全唐詩/json/555.json','["帝鄉歸未得，辛苦事羈遊。別館一尊酒，客程千里秋。", "霜風紅葉寺，夜雨白蘋洲。長恐此時淚，不禁和恨流。"]'),
('yuding-6','客行','馬戴','唐','御定全唐诗','yuding','','[]','路岐長不盡，客恨杳難通。蘆荻晚汀雨，柳花南浦風。',48,'御定全唐詩/json/555.json','["路岐長不盡，客恨杳難通。蘆荻晚汀雨，柳花南浦風。", "亂鐘嘶馬急，殘日半帆紅。卻羨漁樵侶，閑歌落照中。"]'),
('yuding-7','過野叟居','馬戴','唐','御定全唐诗','yuding','','[]','野人閑種樹，樹老野人前。居止白雲內，漁樵滄海邊。',48,'御定全唐詩/json/555.json','["野人閑種樹，樹老野人前。居止白雲內，漁樵滄海邊。", "呼兒采山藥，放犢飲溪泉。自著養生論，無煩憂暮年。"]'),
('yuding-8','答光州王使君','馬戴','唐','御定全唐诗','yuding','','[]','信來淮上郡，楚岫入秦雲。自顧為儒者，何由答使君。',48,'御定全唐詩/json/555.json','["信來淮上郡，楚岫入秦雲。自顧為儒者，何由答使君。", "蛻風蟬半失，阻雨雁頻聞。欲識平生分，他時別紀勳。"]'),
('yuding-9','下第再過崔邵池陽居','馬戴','唐','御定全唐诗','yuding','','[]','豈無故鄉路，路遠未成歸。關內相知少，海邊來信稀。',48,'御定全唐詩/json/555.json','["豈無故鄉路，路遠未成歸。關內相知少，海邊來信稀。", "離雲空石穴，芳草偃郊扉。謝子一留宿，此心聊息機。"]'),
('yuding-10','夕次淮口','馬戴','唐','御定全唐诗','yuding','','[]','天涯秋光盡，木末群鳥還。夜久遊子息，月明岐路閑。',48,'御定全唐詩/json/555.json','["天涯秋光盡，木末群鳥還。夜久遊子息，月明岐路閑。", "風生淮水上，帆落楚雲間。此意竟誰見，行行非故關。"]'),
('yuding-11','落日悵望','馬戴','唐','御定全唐诗','yuding','','[]','孤雲與歸鳥，千里片時間。念我一何滯，辭家久未還。',48,'御定全唐詩/json/555.json','["孤雲與歸鳥，千里片時間。念我一何滯，辭家久未還。", "微陽下喬木，遠色隱秋山。臨水不敢照，恐驚平昔顏。"]'),
('yuding-12','早發故山作','馬戴','唐','御定全唐诗','yuding','','[]','雲門夾峭石，石路蔭長松。穀響猿相應，山深水複重。',48,'御定全唐詩/json/555.json','["雲門夾峭石，石路蔭長松。穀響猿相應，山深水複重。", "餐霞人不見，采藥客猶逢。獨宿靈潭側，時聞岳頂鐘。"]'),
('yuding-13','下第別郜扶','馬戴','唐','御定全唐诗','yuding','','[]','窮途別故人，京洛泣風塵。在世即應老，他鄉又欲春。',48,'御定全唐詩/json/555.json','["窮途別故人，京洛泣風塵。在世即應老，他鄉又欲春。", "平生空志學，晚歲拙謀身。靜話歸休計，唯將海上親。"]'),
('yuding-14','寄終南真空禪師','馬戴','唐','御定全唐诗','yuding','','[]','閑想白雲外，了然清淨僧。松門山半寺，夜雨佛前燈。',48,'御定全唐詩/json/555.json','["閑想白雲外，了然清淨僧。松門山半寺，夜雨佛前燈。", "此境可長住，浮生自不能。一從林下別，瀑布幾成冰。"]'),
('yuding-15','長安寓居寄贈賈島','馬戴','唐','御定全唐诗','yuding','','[]','歲暮見華髮，平生志半空。孤雲不我棄，歸隱與誰同。',48,'御定全唐詩/json/555.json','["歲暮見華髮，平生志半空。孤雲不我棄，歸隱與誰同。", "枉道紫宸謁，妨栽丹桂叢。何如隨野鹿，棲止石岩中。"]'),
('yuding-16','秋郊夕望','馬戴','唐','御定全唐诗','yuding','','[]','度鳥向棲急，陰蟲逢夜多。餘霞媚秋漢，迥月濯滄波。',48,'御定全唐詩/json/555.json','["度鳥向棲急，陰蟲逢夜多。餘霞媚秋漢，迥月濯滄波。", "蔓草將萎絕，流年其奈何。耿然搖落思，獨酌不成歌。"]'),
('yuding-17','贈越客','馬戴','唐','御定全唐诗','yuding','','[]','故國波濤隔，明時已久留。獻書雙闕晚，看月五陵秋。',48,'御定全唐詩/json/555.json','["故國波濤隔，明時已久留。獻書雙闕晚，看月五陵秋。", "南棹何時返，長江憶共遊。遙知釣船畔，相望在汀洲。"]'),
('yuding-18','送顧非熊下第歸江南','馬戴','唐','御定全唐诗','yuding','','[]','無成西別秦，返駕江南春。草際楚田雁，舟中吳苑人。',48,'御定全唐詩/json/555.json','["無成西別秦，返駕江南春。草際楚田雁，舟中吳苑人。", "殘雲掛絕島，迥樹入通津。想到長洲日，門前多白蘋。"]'),
('yuding-19','汧上勸舊友','馬戴','唐','御定全唐诗','yuding','','[]','鬥酒故人同，長歌起北風。斜陽高壘閉，秋角暮山空。',48,'御定全唐詩/json/555.json','["鬥酒故人同，長歌起北風。斜陽高壘閉，秋角暮山空。", "雁叫寒流上，螢飛薄霧中。坐來生白髮，況複久從戎。"]'),
('yuding-20','送狄參軍赴杭州','馬戴','唐','御定全唐诗','yuding','','[]','新官非次受，聖主寵前勳。關雪發車晚，風濤掛席聞。',48,'御定全唐詩/json/555.json','["新官非次受，聖主寵前勳。關雪發車晚，風濤掛席聞。", "海門山疊翠，湖岸郡藏雲。執簡從公後，髯參豈勝君。"]'),
('yuding-21','過故人所遷新居','馬戴','唐','御定全唐诗','yuding','','[]','金馬詔何晚，茂陵居近修。客來雲雨散，鳥下梧桐秋。',48,'御定全唐詩/json/555.json','["金馬詔何晚，茂陵居近修。客來雲雨散，鳥下梧桐秋。", "迥漢銜天闕，遙泉響禦溝。坐看涼月上，為子一淹留。"]'),
('yuding-22','落照','馬戴','唐','御定全唐诗','yuding','','[]','照曜天山外，飛鴉幾共過。微紅拂秋漢，片白透長波。',48,'御定全唐詩/json/555.json','["照曜天山外，飛鴉幾共過。微紅拂秋漢，片白透長波。", "影促寒汀薄，光殘古木多。金霞與雲氣，散漫複相和。"]'),
('yuding-23','宿崔邵池陽別墅','馬戴','唐','御定全唐诗','yuding','','[]','楊柳色已改，郊原日複低。煙生寒渚上，霞散亂山西。',48,'御定全唐詩/json/555.json','["楊柳色已改，郊原日複低。煙生寒渚上，霞散亂山西。", "待月人相對，驚風雁不齊。此心君莫問，舊國去將迷。"]'),
('yuding-24','楚江懷古三首','馬戴','唐','御定全唐诗','yuding','','[]','露氣寒光集，微陽下楚丘。猿啼洞庭樹，人在木蘭舟。',144,'御定全唐詩/json/555.json','["露氣寒光集，微陽下楚丘。猿啼洞庭樹，人在木蘭舟。", "廣澤生明月，蒼山夾亂流。雲中君不降，竟夕自悲秋。", "驚鳥去無際，寒蛩鳴我傍。蘆洲生早霧，蘭隰下微霜。", "列宿分窮野，空流注大荒。看山候明月，聊自整雲裝。", "野風吹蕙帶，驟雨滴蘭橈。屈宋魂冥寞，江山思寂寥。", "陰霓侵晚景，海樹入回潮。欲折寒芳薦，明神詎可招。"]'),
('yuding-25','遠水','馬戴','唐','御定全唐诗','yuding','','[]','蕩漾空沙際，虛明入遠天。秋光照不極，鳥影去無邊。',48,'御定全唐詩/json/555.json','["蕩漾空沙際，虛明入遠天。秋光照不極，鳥影去無邊。", "勢引長雲斷，波輕片雪連。汀洲杳難到，萬古覆蒼煙。"]'),
('yuding-26','夕發邠甯寄從弟','馬戴','唐','御定全唐诗','yuding','','[]','半酣走馬別，別後鎖邊城。日落月未上，鳥棲人獨行。',48,'御定全唐詩/json/555.json','["半酣走馬別，別後鎖邊城。日落月未上，鳥棲人獨行。", "方馳故國戀，複愴長年情。入夜不能息，何當閑此生。"]'),
('yuding-27','贈別北客','馬戴','唐','御定全唐诗','yuding','','[]','君生遊俠地，感激氣何高。飲盡玉壺酒，贈留金錯刀。',48,'御定全唐詩/json/555.json','["君生遊俠地，感激氣何高。飲盡玉壺酒，贈留金錯刀。", "雁關飛霰雪，鯨海落雲濤。決去如征鳥，離心空自勞。"]'),
('yuding-28','夜下湘中','馬戴','唐','御定全唐诗','yuding','','[]','洞庭人夜別，孤棹下湘中。露洗寒山遍，波搖楚月空。',48,'御定全唐詩/json/555.json','["洞庭人夜別，孤棹下湘中。露洗寒山遍，波搖楚月空。", "密林飛暗狖，廣澤發鳴鴻。行值揚帆者，江分又不同。"]'),
('yuding-29','送呂郎中牧東海郡','馬戴','唐','御定全唐诗','yuding','','[]','假道經淮泗，檣烏集隼旟。蕪城沙菼接，波島石林疏。',48,'御定全唐詩/json/555.json','["假道經淮泗，檣烏集隼旟。蕪城沙菼接，波島石林疏。", "海鶴空庭下，夷人遠岸居。山鄉足遺老，佇聽薦賢書。"]'),
('yuding-30','山行偶作','馬戴','唐','御定全唐诗','yuding','','[]','緣危路忽窮，投宿值樵翁。鳥下山含暝，蟬鳴露滴空。',48,'御定全唐詩/json/555.json','["緣危路忽窮，投宿值樵翁。鳥下山含暝，蟬鳴露滴空。", "石門斜月入，雲竇暗泉通。寂寞生幽思，心疑舊隱同。"]'),
('yuding-31','巴江夜猿','馬戴','唐','御定全唐诗','yuding','','[]','日飲巴江水，還啼巴岸邊。秋聲巫峽斷，夜影楚雲連。',48,'御定全唐詩/json/555.json','["日飲巴江水，還啼巴岸邊。秋聲巫峽斷，夜影楚雲連。", "露滴青楓樹，山空明月天。誰知泊船者，聽此不能眠。"]'),
('yuding-32','送田使君牧蔡州','馬戴','唐','御定全唐诗','yuding','','[]','主意思政理，牧人官不輕。樹多淮右地，山遠汝南城。',48,'御定全唐詩/json/555.json','["主意思政理，牧人官不輕。樹多淮右地，山遠汝南城。", "望稼周田隔，登樓楚月生。懸知蔣亭下，渚鶴伴閑行。"]'),
('yuding-33','雀台怨','馬戴','唐','御定全唐诗','yuding','','[]','魏宮歌舞地，蝶戲鳥還鳴。玉座人難到，銅台雨滴平。',48,'御定全唐詩/json/555.json','["魏宮歌舞地，蝶戲鳥還鳴。玉座人難到，銅台雨滴平。", "西陵樹不見，漳浦草空生。萬恨盡埋此，徒懸千載名。"]'),
('yuding-34','早發故園','馬戴','唐','御定全唐诗','yuding','','[]','語別在中夜，登車離故鄉。曙鐘寒出嶽，殘月迥凝霜。',48,'御定全唐詩/json/555.json','["語別在中夜，登車離故鄉。曙鐘寒出嶽，殘月迥凝霜。", "風柳條多折，沙雲氣盡黃。行逢海西雁，零落不成行。"]'),
('yuding-35','贈別江客','馬戴','唐','御定全唐诗','yuding','','[]','湘中有岑穴，君去掛帆過。露細蒹葭廣，潮回島嶼多。',48,'御定全唐詩/json/555.json','["湘中有岑穴，君去掛帆過。露細蒹葭廣，潮回島嶼多。", "汀洲延夕照，楓葉墜寒波。應使同漁者，生涯許釣歌。"]'),
('yuding-36','宿翠微寺','馬戴','唐','御定全唐诗','yuding','','[]','處處松陰滿，樵開一徑通。鳥歸雲壑靜，僧語石樓空。',48,'御定全唐詩/json/555.json','["處處松陰滿，樵開一徑通。鳥歸雲壑靜，僧語石樓空。", "積翠含微月，遙泉韻細風。經行心不厭，憶在故山中。"]'),
('yuding-37','霽後寄白閣僧','馬戴','唐','御定全唐诗','yuding','','[]','蒼翠霾高雪，西峰鳥外看。久披山衲壞，孤坐石床寒。',48,'御定全唐詩/json/555.json','["蒼翠霾高雪，西峰鳥外看。久披山衲壞，孤坐石床寒。", "盥手水泉滴，燃燈夜燒殘。終期老雲嶠，煮藥伴中餐。"]'),
('yuding-38','送僧歸金山寺','馬戴','唐','御定全唐诗','yuding','','[]','金陵山色裏，蟬急向秋分。迥寺橫洲島，歸僧渡水雲。',48,'御定全唐詩/json/555.json','["金陵山色裏，蟬急向秋分。迥寺橫洲島，歸僧渡水雲。", "夕陽依岸盡，清磬隔潮聞。遙想禪林下，爐香帶月焚。"]'),
('yuding-39','新秋雨霽宿王處士東郊','馬戴','唐','御定全唐诗','yuding','','[]','夕陽逢一雨，夜木洗清陰。露氣竹窗靜，秋光雲月深。',48,'御定全唐詩/json/555.json','["夕陽逢一雨，夜木洗清陰。露氣竹窗靜，秋光雲月深。", "煎嘗靈藥味，話及故山心。得意兩不寐，微風生玉琴。"]'),
('yuding-40','關山曲二首','馬戴','唐','御定全唐诗','yuding','','[]','金甲耀兜鍪，黃金拂紫騮。叛羌旗下戮，陷壁夜中收。',96,'御定全唐詩/json/555.json','["金甲耀兜鍪，黃金拂紫騮。叛羌旗下戮，陷壁夜中收。", "霜霰戎衣月，關河磧氣秋。箭瘡殊未合，更遣擊蘭州。", "火發龍山北，中宵易左賢。勒兵臨漢水，驚雁散胡天。", "木落防河急，軍孤受敵偏。猶聞漢皇怒，按劍待開邊。"]'),
('yuding-41','塞下曲二首','馬戴','唐','御定全唐诗','yuding','','[]','旌旗倒北風，霜霰逐南鴻。夜救龍城急，朝焚虜帳空。',96,'御定全唐詩/json/555.json','["旌旗倒北風，霜霰逐南鴻。夜救龍城急，朝焚虜帳空。", "骨銷金鏃在，鬢改玉關中。卻想羲軒氏，無人尚戰功。", "廣漠雲凝慘，日斜飛霰生。燒山搜猛獸，伏道擊回兵。", "風折旗竿曲，沙埋樹杪平。黃雲飛旦夕，偏奏苦寒聲。"]'),
('yuding-42','廣陵曲','馬戴','唐','御定全唐诗','yuding','','[]','蔥蘢桂樹枝，高系黃金羈。葉隱青蛾翠，花飄白玉墀。',48,'御定全唐詩/json/555.json','["蔥蘢桂樹枝，高系黃金羈。葉隱青蛾翠，花飄白玉墀。", "上鳴間關鳥，下醉遊俠兒。煬帝國已破，此中都不知。"]'),
('yuding-43','送人游蜀','馬戴','唐','御定全唐诗','yuding','','[]','別離楊柳陌，迢遞蜀門行。若聽清猿後，應多白髮生。',48,'御定全唐詩/json/555.json','["別離楊柳陌，迢遞蜀門行。若聽清猿後，應多白髮生。", "虹霓侵棧道，風雨雜江聲。過盡愁人處，煙花是錦城。"]'),
('yuding-44','宿無可上人房','馬戴','唐','御定全唐诗','yuding','','[]','稀逢息心侶，細話遠山期。河漢秋深夜，杉梧露滴時。',48,'御定全唐詩/json/555.json','["稀逢息心侶，細話遠山期。河漢秋深夜，杉梧露滴時。", "風傳林磬響，月掩草堂遲。坐臥禪心在，浮生皆不知。"]'),
('yuding-45','旅次夏州','馬戴','唐','御定全唐诗','yuding','','[]','嘶馬發相續，行次夏王台。鎖郡雲陰暮，鳴笳燒色來。',48,'御定全唐詩/json/555.json','["嘶馬發相續，行次夏王台。鎖郡雲陰暮，鳴笳燒色來。", "霜繁邊上宿，鬢改磧中回。悵望胡沙曉，驚蓬朔吹催。"]'),
('yuding-46','同莊秀才宿鎮星觀','馬戴','唐','御定全唐诗','yuding','','[]','的的星河落，沾苔複灑松。濕光微泛草，石翠澹搖峰。',48,'御定全唐詩/json/555.json','["的的星河落，沾苔複灑松。濕光微泛草，石翠澹搖峰。", "野觀雲和月，秋城漏間鐘。知君親此境，九陌少相逢。"]'),
('yuding-47','鸛雀樓晴望','馬戴','唐','御定全唐诗','yuding','','[]','堯女樓西望，人懷太古時。海波通禹鑿，山木閉虞祠。',48,'御定全唐詩/json/555.json','["堯女樓西望，人懷太古時。海波通禹鑿，山木閉虞祠。", "鳥道殘虹掛，龍潭返照移。行雲如可馭，萬里赴心期。"]'),
('yuding-48','贈淮南將','馬戴','唐','御定全唐诗','yuding','','[]','何事淮南將，功高業未成。風濤辭海郡，雷雨鎮山營。',72,'御定全唐詩/json/555.json','["何事淮南將，功高業未成。風濤辭海郡，雷雨鎮山營。", "度磧黃雲起，防秋白髮生。密機曾制敵，憂國更論兵。", "塞色侵旗動，寒光鎖甲明。自憐心有作，獨立望專征。"]'),
('yuding-49','寄賈島','馬戴','唐','御定全唐诗','yuding','','[]','海上不同來，關中俱久住。尋思別山日，老盡經行樹。',84,'御定全唐詩/json/555.json','["海上不同來，關中俱久住。尋思別山日，老盡經行樹。", "志業人未聞，時光鳥空度。風悲漢苑秋，雨滴秦城暮。", "佩玉與鏘金，非親亦非故。朱顏枉自毀，明代空相遇。", "歲晏各能歸，心知舊岐路。"]'),
('yuding-50','湘川吊舜','馬戴','唐','御定全唐诗','yuding','','[]','伊予生好古，吊舜蒼梧間。白日坐將沒，遊波凝不還。',72,'御定全唐詩/json/555.json','["伊予生好古，吊舜蒼梧間。白日坐將沒，遊波凝不還。", "九疑雲動影，曠野竹成班。雁集蒹葭渚，猿啼霧露山。", "南風吹早恨，瑤瑟怨長閑。元化誰能問，天門恨久關。"]'),
('yuding-51','送僧歸閩中舊寺','馬戴','唐','御定全唐诗','yuding','','[]','寺隔海山遙，帆前落葉飄。斷猿通楚塞，驚鷺出蘭橈。',72,'御定全唐詩/json/555.json','["寺隔海山遙，帆前落葉飄。斷猿通楚塞，驚鷺出蘭橈。", "星月浮波島，煙蘿渡石橋。鐘聲催野飯，秋色落寒潮。", "舊社人多老，閒房樹半凋。空林容病士，歲晚待相招。"]'),
('yuding-52','寄遠','馬戴','唐','御定全唐诗','yuding','','[]','坐想親愛遠，行嗟天地闊。積疹甘毀顏，沈憂更銷骨。',60,'御定全唐詩/json/555.json','["坐想親愛遠，行嗟天地闊。積疹甘毀顏，沈憂更銷骨。", "迢迢遊子心，望望歸雲沒。喬木非故里，高樓共明月。", "夜深秋風多，聞雁來天末。"]'),
('yuding-53','經咸陽北原','馬戴','唐','御定全唐诗','yuding','','[]','秦山曾共轉，秦雲自舒卷。古來爭雄圖，到此多不返。',60,'御定全唐詩/json/555.json','["秦山曾共轉，秦雲自舒卷。古來爭雄圖，到此多不返。", "野狖穴孤墳，農人耕廢苑。川長波又逝，日與歲俱晚。", "夜入咸陽中，悲吞不能飯。"]'),
('yuding-54','冬日寄洛中楊少尹','馬戴','唐','御定全唐诗','yuding','','[]','黃河岸柳衰，城下度流澌。年長從公懶，天寒入府遲。',48,'御定全唐詩/json/555.json','["黃河岸柳衰，城下度流澌。年長從公懶，天寒入府遲。", "家山望幾遍，魏闕赴何時。懷古心誰識，應多謁舜祠。"]'),
('yuding-55','浙江夜宿','馬戴','唐','御定全唐诗','yuding','','[]','落帆人更起，露草滿汀洲。遠狖啼荒嶠，孤螢溺漫流。',48,'御定全唐詩/json/555.json','["落帆人更起，露草滿汀洲。遠狖啼荒嶠，孤螢溺漫流。", "積陰開片月，爽氣集高秋。去去胡為戀，搴芳時一遊。"]'),
('yuding-56','寄西嶽白石僧','馬戴','唐','御定全唐诗','yuding','','[]','掛錫中峰上，經行踏石梯。雲房出定後，岳月在池西。',48,'御定全唐詩/json/555.json','["掛錫中峰上，經行踏石梯。雲房出定後，岳月在池西。", "峭壁殘霞照，欹松積雪齊。年年著山屐，曾得到招提。"]'),
('yuding-57','同州冬日陪吳常侍閑宴','馬戴','唐','御定全唐诗','yuding','','[]','中天白雲散，集客郡齋時。陶性聊飛爵，看山忽罷棋。',48,'御定全唐詩/json/555.json','["中天白雲散，集客郡齋時。陶性聊飛爵，看山忽罷棋。", "雪花凝始散，木葉脫無遺。靜理良多暇，招邀愜所思。"]'),
('yuding-58','答鄜畤友人同宿見示','馬戴','唐','御定全唐诗','yuding','','[]','為客自堪悲，風塵日滿衣。承明無計入，舊隱但懷歸。',48,'御定全唐詩/json/555.json','["為客自堪悲，風塵日滿衣。承明無計入，舊隱但懷歸。", "雪積孤城暗，燈殘曉角微。相逢喜同宿，此地故人稀。"]'),
('yuding-59','題僧禪院','馬戴','唐','御定全唐诗','yuding','','[]','虛室焚香久，禪心悟幾生。濾泉侵月起，掃徑避蟲行。',48,'御定全唐詩/json/555.json','["虛室焚香久，禪心悟幾生。濾泉侵月起，掃徑避蟲行。", "樹隔前朝在，苔滋廢渚平。我來風雨夜，像設一燈明。"]'),
('yuding-60','懷故山寄賈島','馬戴','唐','御定全唐诗','yuding','','[]','心偶羨明代，學詩觀國風。自從來闕下，未勝在山中。',48,'御定全唐詩/json/555.json','["心偶羨明代，學詩觀國風。自從來闕下，未勝在山中。", "丹桂日應老，白雲居久空。誰能謝時去，聊與此生同。"]'),
('yuding-61','灞上秋居','馬戴','唐','御定全唐诗','yuding','','[]','灞原風雨定，晚見雁行頻。落葉他鄉樹，寒燈獨夜人。',48,'御定全唐詩/json/555.json','["灞原風雨定，晚見雁行頻。落葉他鄉樹，寒燈獨夜人。", "空園白露滴，孤壁野僧鄰。寄臥郊扉久，何門致此身。"]'),
('yuding-62','寄崇德里居作','馬戴','唐','御定全唐诗','yuding','','[]','掃君園林地，澤我清涼襟。高鳥雲路晚，孤蟬楊柳深。',48,'御定全唐詩/json/555.json','["掃君園林地，澤我清涼襟。高鳥雲路晚，孤蟬楊柳深。", "風微漢宮漏，月迥秦城砧。光景坐如此，徒懷經濟心。"]'),
('yuding-63','河梁別','馬戴','唐','御定全唐诗','yuding','','[]','河梁送別者，行哭半非親。此路足征客，胡天多殺人。',48,'御定全唐詩/json/555.json','["河梁送別者，行哭半非親。此路足征客，胡天多殺人。", "金罍照離思，寶瑟凝殘春。早晚期相見，垂楊凋複新。"]'),
('yuding-64','留別定襄盧軍事','馬戴','唐','御定全唐诗','yuding','','[]','行行與君別，路在雁門西。秋色見邊草，軍聲聞戍鼙。',48,'御定全唐詩/json/555.json','["行行與君別，路在雁門西。秋色見邊草，軍聲聞戍鼙。", "酣歌擊寶劍，躍馬上金堤。歸去咸陽裏，平生志不迷。"]'),
('yuding-65','送杜秀才東游','馬戴','唐','御定全唐诗','yuding','','[]','羈遊年複長，去日值秋殘。草出函關白，雲藏野渡寒。',48,'御定全唐詩/json/555.json','["羈遊年複長，去日值秋殘。草出函關白，雲藏野渡寒。", "鴻多霜雪重，山廣道途難。心事何人識，鬥牛應數看。"]'),
('yuding-66','懷黃頗','馬戴','唐','御定全唐诗','yuding','','[]','有客南浮去，平生與我同。炎州結遙思，芳杜采應空。',48,'御定全唐詩/json/555.json','["有客南浮去，平生與我同。炎州結遙思，芳杜采應空。", "秦雁歸侵月，湘猿戲褭楓。期君翼明代，未可戀山中。"]'),
('yuding-67','隴上獨望','馬戴','唐','御定全唐诗','yuding','','[]','斜日掛邊樹，蕭蕭獨望間。陰雲藏漢壘，飛火照胡山。',48,'御定全唐詩/json/555.json','["斜日掛邊樹，蕭蕭獨望間。陰雲藏漢壘，飛火照胡山。", "隴首行人絕，河源夕鳥還。誰為立勳者，可惜寶刀閑。"]'),
('yuding-68','長安書懷','馬戴','唐','御定全唐诗','yuding','','[]','岐路今如此，還堪慟哭頻。關中成久客，海上老諸親。',48,'御定全唐詩/json/555.json','["岐路今如此，還堪慟哭頻。關中成久客，海上老諸親。", "谷口田應廢，鄉山草又春。年年銷壯志，空作獻書人。"]'),
('yuding-69','邯鄲驛樓作','馬戴','唐','御定全唐诗','yuding','','[]','蕪沒叢台久，清漳廢禦溝。蟬鳴河外樹，人在驛西樓。',48,'御定全唐詩/json/555.json','["蕪沒叢台久，清漳廢禦溝。蟬鳴河外樹，人在驛西樓。", "雲燒天中赤，山當日落秋。近郊經戰後，處處骨成丘。"]'),
('yuding-70','別家後次飛狐西即事','馬戴','唐','御定全唐诗','yuding','','[]','遠歸從此別，親愛失天涯。去國頻回首，方秋不在家。',48,'御定全唐詩/json/555.json','["遠歸從此別，親愛失天涯。去國頻回首，方秋不在家。", "鳴蛩聞塞路，冷雁背龍沙。西次桑幹曲，洲中見荻花。"]'),
('yuding-71','題青龍寺鏡公房','馬戴','唐','御定全唐诗','yuding','','[]','一室意何有，閑門為我開。爐香寒自滅，履雪飯初回。',48,'御定全唐詩/json/555.json','["一室意何有，閑門為我開。爐香寒自滅，履雪飯初回。", "窗迥孤山入，燈殘片月來。禪心方此地，不必訪天臺。"]'),
('yuding-0','邊城獨望','馬戴','唐','御定全唐诗','yuding','','[]','聊憑危堞望，倍起異鄉情。霜落蒹葭白，山昏霧露生。',48,'御定全唐詩/json/556.json','["聊憑危堞望，倍起異鄉情。霜落蒹葭白，山昏霧露生。", "河灘胡雁下，戎壘漢鼙驚。獨樹殘秋色，狂歌淚滿纓。"]'),
('yuding-1','江亭贈別','馬戴','唐','御定全唐诗','yuding','','[]','長亭晚送君，秋色渡江濆。衰柳風難定，寒濤雪不分。',48,'御定全唐詩/json/556.json','["長亭晚送君，秋色渡江濆。衰柳風難定，寒濤雪不分。", "猿聲離楚峽，帆影入湘雲。獨泛扁舟夜，山鐘可臥聞。"]'),
('yuding-2','旅次寄賈島兼簡無可上人','馬戴','唐','御定全唐诗','yuding','','[]','相思邊草長，回望水連空。雁過當行次，蟬鳴複客中。',48,'御定全唐詩/json/556.json','["相思邊草長，回望水連空。雁過當行次，蟬鳴複客中。", "壯年看即改，羸病計多同。儻宿林中寺，深憑問遠公。"]'),
('yuding-3','寄剡中友人','馬戴','唐','御定全唐诗','yuding','','[]','故人今在剡，秋草意如何。嶺暮雲霞雜，潮回島嶼多。',48,'御定全唐詩/json/556.json','["故人今在剡，秋草意如何。嶺暮雲霞雜，潮回島嶼多。", "沃洲僧幾訪，天姥客誰過。歲晚偏相憶，風生隔楚波。"]'),
('yuding-4','送國子韋丞','馬戴','唐','御定全唐诗','yuding','','[]','臨水獨相送，歸期千里間。雲回逢過雨，路轉入連山。',48,'御定全唐詩/json/556.json','["臨水獨相送，歸期千里間。雲回逢過雨，路轉入連山。", "一騎行芳草，新蟬發故關。遙聆茂陵下，夜啟竹扉閑。"]'),
('yuding-5','題吳發原南居','馬戴','唐','御定全唐诗','yuding','','[]','閒居誰厭僻，門掩漢祠前。山色夏雲映，樹陰幽草連。',48,'御定全唐詩/json/556.json','["閒居誰厭僻，門掩漢祠前。山色夏雲映，樹陰幽草連。", "晴光分渚曲，綠氣冒原田。何日遠遊罷，高枝已噪蟬。"]'),
('yuding-6','雒中寒夜姚侍禦宅懷賈島','馬戴','唐','御定全唐诗','yuding','','[]','夜木動寒色，雒陽城闕深。如何異鄉思，更抱故人心。',48,'御定全唐詩/json/556.json','["夜木動寒色，雒陽城闕深。如何異鄉思，更抱故人心。", "微月關山遠，閑階霜霰侵。誰知石門路，待與子同尋。"]'),
('yuding-7','征婦歎','馬戴','唐','御定全唐诗','yuding','','[]','稚子在我抱，送君登遠道。稚子今已行，念君上邊城。',60,'御定全唐詩/json/556.json','["稚子在我抱，送君登遠道。稚子今已行，念君上邊城。", "蓬根既無定，蓬子焉用生。但見請防胡，不聞言罷兵。", "及老能得歸，少者還長征。"]'),
('yuding-8','山中寄姚合員外','馬戴','唐','御定全唐诗','yuding','','[]','朝與城闕別，暮同麋鹿歸。鳥鳴松觀靜，人過石橋稀。',48,'御定全唐詩/json/556.json','["朝與城闕別，暮同麋鹿歸。鳥鳴松觀靜，人過石橋稀。", "木葉搖山翠，泉痕入澗扉。敢招仙署客，暫此拂朝衣。"]'),
('yuding-9','中秋月','馬戴','唐','御定全唐诗','yuding','','[]','陰魄出海上，望之增苦吟。冷搜驪頷重，寒徹蚌胎深。',48,'御定全唐詩/json/556.json','["陰魄出海上，望之增苦吟。冷搜驪頷重，寒徹蚌胎深。", "皓氣籠諸夏，清光射萬岑。悠然天地內，皎潔一般心。"]'),
('yuding-10','下第寄友人','馬戴','唐','御定全唐诗','yuding','','[]','金門君待問，石室我思歸。聖主尊黃屋，何人薦白衣。',36,'御定全唐詩/json/556.json','["金門君待問，石室我思歸。聖主尊黃屋，何人薦白衣。", "年來禦溝柳，贈別雨霏霏。"]'),
('yuding-11','寄廣州楊參軍','馬戴','唐','御定全唐诗','yuding','','[]','南方春景好，念子緩歸心。身方脫野服，冠未系朝簪。',96,'御定全唐詩/json/556.json','["南方春景好，念子緩歸心。身方脫野服，冠未系朝簪。", "足恣平生賞，無虞外役侵。汀洲觀鳥戲，向月和猿吟。", "稅駕楚山廣，揚帆湘水深。采奇搜石穴，懷勝即楓林。", "悵望極霞際，流情墮海陰。前朝杳難問，歎息灑鳴琴。"]'),
('yuding-12','離夜二首','馬戴','唐','御定全唐诗','yuding','','[]','東征遼水迥，北近單于台。戎衣掛寶劍，玉箸銜金杯。',72,'御定全唐詩/json/556.json','["東征遼水迥，北近單于台。戎衣掛寶劍，玉箸銜金杯。", "紅燭暗將滅，翠蛾終不開。", "凝夜照離色，恐聞啼晚鴉。前年營雁塞，明月戍龍沙。", "曾與五陵子，休裝孤劍花。"]'),
('yuding-13','答太原從軍楊員外送別','馬戴','唐','御定全唐诗','yuding','','[]','君將海月佩，贈之光我行。見知言不淺，懷報意非輕。',72,'御定全唐詩/json/556.json','["君將海月佩，贈之光我行。見知言不淺，懷報意非輕。", "反照臨岐思，中年未達情。河梁人送別，秋漢雁相鳴。", "衰柳搖邊吹，寒雲冒古城。西遊還獻賦，應許托平生。"]'),
('yuding-14','送從叔重赴海南從事','馬戴','唐','御定全唐诗','yuding','','[]','又從連帥請，還作嶺南行。窮海何時到，孤帆累月程。',72,'御定全唐詩/json/556.json','["又從連帥請，還作嶺南行。窮海何時到，孤帆累月程。", "亂蟬吟暮色，哀狖落秋聲。晚路潮波起，寒葭霧雨生。", "沙埋銅柱沒，山簇瘴雲平。念此別離苦，其如宗從情。"]'),
('yuding-15','送韓校書江西從事','馬戴','唐','御定全唐诗','yuding','','[]','出關寒色盡，雲夢草生新。雁背岳陽雨，客行江上春。',72,'御定全唐詩/json/556.json','["出關寒色盡，雲夢草生新。雁背岳陽雨，客行江上春。", "遙程隨水闊，枉路倒帆頻。夕照臨孤館，朝霞發廣津。", "湖山潮半隔，郡壁岸斜鄰。自此鐘陵道，裁書有故人。"]'),
('yuding-16','送顧少府之永康','馬戴','唐','御定全唐诗','yuding','','[]','婺女星邊去，春生即有花。寒關雲複雪，古渡草連沙。',72,'御定全唐詩/json/556.json','["婺女星邊去，春生即有花。寒關雲複雪，古渡草連沙。", "宿次吳江晚，行侵日徼斜。官傳梅福政，縣顧赤松家。", "燒起明山翠，潮回動海霞。清高宜閱此，莫歎近天涯。"]'),
('yuding-17','幽上留別令狐侍郎','馬戴','唐','御定全唐诗','yuding','','[]','自別丘中隱，頻年哭路岐。辛勤今若是，少壯豈多時。',96,'御定全唐詩/json/556.json','["自別丘中隱，頻年哭路岐。辛勤今若是，少壯豈多時。", "露滴陰蟲苦，秋聲遠客悲。晚營嚴鼓角，紅葉拂旌旗。", "北闕虛延望，西林久見思。川流寒水急，雲返故山遲。", "落照遊人去，長空獨鳥隨。不堪風景隔，忠信寡相知。"]'),
('yuding-18','襄陽席上呈于司空','馬戴','唐','御定全唐诗','yuding','','[]','花枝臨水複臨堤，也照清江也照泥。',32,'御定全唐詩/json/556.json','["花枝臨水複臨堤，也照清江也照泥。", "寄語東君好抬舉，夜來曾伴鳳凰棲。"]'),
('yuding-19','宿裴氏溪居懷厲玄先輩','馬戴','唐','御定全唐诗','yuding','','[]','樹下孤石坐，草間微有霜。同人不同北，雲鳥自南翔。',48,'御定全唐詩/json/556.json','["樹下孤石坐，草間微有霜。同人不同北，雲鳥自南翔。", "迢遞夜山色，清泠泉月光。西風耿離抱，江海遙相望。"]'),
('yuding-20','集宿姚殿中宅期僧無可不至','馬戴','唐','御定全唐诗','yuding','','[]','殿中日相命，開尊話舊時。餘鐘催鳥絕，積雪阻僧期。',48,'御定全唐詩/json/556.json','["殿中日相命，開尊話舊時。餘鐘催鳥絕，積雪阻僧期。", "林靜寒光遠，天陰曙色遲。今夕複何夕，人謁去難追。"]'),
('yuding-21','宿賈島原居','馬戴','唐','御定全唐诗','yuding','','[]','寒雁過原急，渚邊秋色深。煙霞向海島，風雨宿園林。',48,'御定全唐詩/json/556.json','["寒雁過原急，渚邊秋色深。煙霞向海島，風雨宿園林。", "俱住明時願，同懷故國心。未能先隱跡，聊此一相尋。"]'),
('yuding-22','贈別空公','馬戴','唐','御定全唐诗','yuding','','[]','雲門秋卻入，微徑久無人。後夜中峰月，空林百衲身。',48,'御定全唐詩/json/556.json','["雲門秋卻入，微徑久無人。後夜中峰月，空林百衲身。", "寂寥寒磬盡，盥漱瀑泉新。履跡誰相見，松風掃石塵。"]'),
('yuding-23','府試觀開元皇帝東封圖','馬戴','唐','御定全唐诗','yuding','','[]','儼若翠華舉，登封圖乍開。冕旒明主立，冠劍侍臣陪。',72,'御定全唐詩/json/556.json','["儼若翠華舉，登封圖乍開。冕旒明主立，冠劍侍臣陪。", "跡類飛仙去，光同拜日來。粉痕疑檢玉，黛色訝生苔。", "掛壁雲將起，陵風仗若回。何年複東幸，魯叟望悠哉。"]'),
('yuding-24','府試水始冰','馬戴','唐','御定全唐诗','yuding','','[]','南池寒色動，北陸歲陰生。薄薄流澌聚，漓漓翠瀲平。',72,'御定全唐詩/json/556.json','["南池寒色動，北陸歲陰生。薄薄流澌聚，漓漓翠瀲平。", "暗沾霜稍厚，回照日還輕。乳竇懸殘滴，湘流減恨聲。", "即堪金井貯，會映玉壺清。潔白心雖識，空期飲此明。"]'),
('yuding-25','邊館逢賀秀才','馬戴','唐','御定全唐诗','yuding','','[]','貧病無疏我與君，不知何事久離群。鹿裘共弊同為客，',40,'御定全唐詩/json/556.json','["貧病無疏我與君，不知何事久離群。鹿裘共弊同為客，", "不堪吟斷邊笳曉，葉落東西客又分。"]'),
('yuding-26','宿王屋天壇','馬戴','唐','御定全唐诗','yuding','','[]','星斗半沈蒼翠色，紅霞遠照海濤分。折松曉拂天壇雪，',40,'御定全唐詩/json/556.json','["星斗半沈蒼翠色，紅霞遠照海濤分。折松曉拂天壇雪，", "未知誰與傳金籙，獨向仙祠拜老君。"]'),
('yuding-27','岐陽逢曲陽故人話舊','馬戴','唐','御定全唐诗','yuding','','[]','異地還相見，平生問可知。壯年俱欲暮，往事盡堪悲。',96,'御定全唐詩/json/556.json','["異地還相見，平生問可知。壯年俱欲暮，往事盡堪悲。", "道路頻艱阻，親朋久別離。解兵逃白刃，謁帝值明時。", "淹疾生涯故，因官事業移。雞鳴關月落，雁度朔風吹。", "客淚翻岐下，鄉心落海湄。積愁何計遣，滿酌浣相思。"]'),
('yuding-28','贈禪僧','馬戴','唐','御定全唐诗','yuding','','[]','弟子人天遍，童年在沃洲。開禪山木長，浣衲海沙秋。',48,'御定全唐詩/json/556.json','["弟子人天遍，童年在沃洲。開禪山木長，浣衲海沙秋。", "振錫搖汀月，持瓶接瀑流。赤城何日上，鄙願從師遊。"]'),
('yuding-29','題廬山寺','馬戴','唐','御定全唐诗','yuding','','[]','白茅為屋宇編荊，數處階墀石疊成。東谷笑言西穀響，',40,'御定全唐詩/json/556.json','["白茅為屋宇編荊，數處階墀石疊成。東谷笑言西穀響，", "別有一條投澗水，竹筒斜引入茶鐺。"]'),
('yuding-30','題石甕寺','馬戴','唐','御定全唐诗','yuding','','[]','僧室並皇宮，雲門輦路同。渭分雙闕北，山迥五陵東。',72,'御定全唐詩/json/556.json','["僧室並皇宮，雲門輦路同。渭分雙闕北，山迥五陵東。", "修綆懸林表，深泉汲洞中。人煙窺垤蟻，鴛瓦拂冥鴻。", "蘚壁松生峭，龕燈月照空。稀逢息心侶，獨禮竺幹公。"]'),
('yuding-31','謁仙觀二首','馬戴','唐','御定全唐诗','yuding','','[]','我生求羽化，齋沐造仙居。葛蔓沒丹井，石函盛道書。',96,'御定全唐詩/json/556.json','["我生求羽化，齋沐造仙居。葛蔓沒丹井，石函盛道書。", "寒松多偃側，靈洞遍清虛。一就泉西飲，雲中采藥蔬。", "山空蕙氣香，乳管折雲房。願值壺中客，親傳肘後方。", "三更禮星斗，寸匕服丹霜。默坐樹陰下，仙經橫石床。"]'),
('yuding-32','送樸山人歸新羅','馬戴','唐','御定全唐诗','yuding','','[]','浩渺行無極，揚帆但信風。雲山過海半，鄉樹入舟中。',48,'御定全唐詩/json/556.json','["浩渺行無極，揚帆但信風。雲山過海半，鄉樹入舟中。", "波定遙天出，沙平遠岸窮。離心寄何處，目斷曙霞東。"]'),
('yuding-33','題靜住寺欽用上人房','馬戴','唐','御定全唐诗','yuding','','[]','寺近朝天路，多聞玉佩音。鑒人開慧眼，歸鳥息禪心。',48,'御定全唐詩/json/556.json','["寺近朝天路，多聞玉佩音。鑒人開慧眼，歸鳥息禪心。", "磬接星河曙，窗連夏木深。此中能宴坐，何必在雲林。"]'),
('yuding-34','贈楊先輩','馬戴','唐','御定全唐诗','yuding','','[]','平生閑放久，野鹿許為群。居止鄰西嶽，軒窗度白雲。',48,'御定全唐詩/json/556.json','["平生閑放久，野鹿許為群。居止鄰西嶽，軒窗度白雲。", "齋心飯松子，話道接茅君。漢主思清淨，休書諫獵文。"]'),
('yuding-35','酬李景章先輩','馬戴','唐','御定全唐诗','yuding','','[]','平生詩句忝多同，不得陪君奉至公。金鏑自宜先中鵠，',40,'御定全唐詩/json/556.json','["平生詩句忝多同，不得陪君奉至公。金鏑自宜先中鵠，", "九陌芳菲人競賞，此時心在別離中。"]'),
('yuding-36','贈祠部令狐郎中','馬戴','唐','御定全唐诗','yuding','','[]','官初執憲稱雄才，省轉為郎雅望催。待制松陰移玉殿，',40,'御定全唐詩/json/556.json','["官初執憲稱雄才，省轉為郎雅望催。待制松陰移玉殿，", "忽憶十年相識日，小儒新自海邊來。"]'),
('yuding-37','送冊東夷王使','馬戴','唐','御定全唐诗','yuding','','[]','越海傳金冊，華夷禮命行。片帆秋色動，萬里信潮生。',72,'御定全唐詩/json/556.json','["越海傳金冊，華夷禮命行。片帆秋色動，萬里信潮生。", "日映孤舟出，沙連絕島明。翳空翻大鳥，飛雪灑長鯨。", "舊鬢回應改，遐荒夢易驚。何當理風楫，天外問來程。"]'),
('yuding-38','送武陵王將軍','馬戴','唐','御定全唐诗','yuding','','[]','河外今無事，將軍有戰名。艱難長劍缺，功業少年成。',72,'御定全唐詩/json/556.json','["河外今無事，將軍有戰名。艱難長劍缺，功業少年成。", "曉仗親雲陛，寒宵突禁營。朱旗身外色，玉漏耳邊聲。", "開合談賓至，調弓過雁驚。為儒多不達，見學請長纓。"]'),
('yuding-39','贈鄠縣尉李先輩二首','馬戴','唐','御定全唐诗','yuding','','[]','同人家鄠杜，相見罷官時。野坐苔生石，荒居菊入籬。',96,'御定全唐詩/json/556.json','["同人家鄠杜，相見罷官時。野坐苔生石，荒居菊入籬。", "聽蟬臨水久，送鶴背山遲。未擬還城闕，溪僧別有期。", "休官不到闕，求靜匪營他。種藥唯愁晚，看雲肯厭多。", "渚邊逢鷺下，林表伴僧過。閑檢仙方試，松花酒自和。"]'),
('yuding-40','邊將','馬戴','唐','御定全唐诗','yuding','','[]','玉榼酒頻傾，論功笑李陵。紅韁跑駿馬，金鏃掣秋鷹。',48,'御定全唐詩/json/556.json','["玉榼酒頻傾，論功笑李陵。紅韁跑駿馬，金鏃掣秋鷹。", "塞迥連天雪，河深徹底冰。誰言提一劍，勤苦事中興。"]'),
('yuding-41','下第別令狐員外','馬戴','唐','御定全唐诗','yuding','','[]','論文期雨夜，飲酒及芳晨。坐歎百花發，潛驚雙鬢新。',48,'御定全唐詩/json/556.json','["論文期雨夜，飲酒及芳晨。坐歎百花發，潛驚雙鬢新。", "舊交多得路，別業遠仍貧。便欲辭知己，歸耕海上春。"]'),
('yuding-42','送春坊董正字浙右歸覲','馬戴','唐','御定全唐诗','yuding','','[]','去覲毗陵日，秋殘建業中。莎垂石城古，山闊海門空。',48,'御定全唐詩/json/556.json','["去覲毗陵日，秋殘建業中。莎垂石城古，山闊海門空。", "灌木寒檣遠，層波皓月同。何當複讎校，春集少陽宮。"]'),
('yuding-43','送和北虜使','馬戴','唐','御定全唐诗','yuding','','[]','路始陰山北，迢迢雨雪天。長城人過少，沙磧馬難前。',96,'御定全唐詩/json/556.json','["路始陰山北，迢迢雨雪天。長城人過少，沙磧馬難前。", "日入流沙際，陰生瀚海邊。刀鐶向月動，旌纛冒霜懸。", "逐獸孤圍合，交兵一箭傳。穹廬移斥候，烽火絕祁連。", "漢將行持節，胡兒坐控弦。明妃的回面，南送使君旋。"]'),
('yuding-44','攄情留別並州從事','馬戴','唐','御定全唐诗','yuding','','[]','淺學長自鄙，謬承賢達知。才希漢主召，玉任楚人疑。',96,'御定全唐詩/json/556.json','["淺學長自鄙，謬承賢達知。才希漢主召，玉任楚人疑。", "年長慚漂泊，恩深惜別離。秋光獨鳥過，暝色一蟬悲。", "鶴發生何速，龍門上苦遲。雕蟲羞朗鑒，幹祿貴明時。", "故國誠難返，青雲致未期。空將感激淚，一自灑臨岐。"]'),
('yuding-45','酬田卿送西游','馬戴','唐','御定全唐诗','yuding','','[]','華堂開翠簟，惜別玉壺深。客去當煩暑，蟬鳴複此心。',48,'御定全唐詩/json/556.json','["華堂開翠簟，惜別玉壺深。客去當煩暑，蟬鳴複此心。", "廢城喬木在，古道濁河侵。莫慮西遊遠，西關絕隴陰。"]'),
('yuding-46','雪中送青州薛評事','馬戴','唐','御定全唐诗','yuding','','[]','臘景不可犯，從戎難自由。憐君急王事，走馬赴邊州。',48,'御定全唐詩/json/556.json','["臘景不可犯，從戎難自由。憐君急王事，走馬赴邊州。", "嶽雪明日觀，海雲冒營丘。慚無鬥酒瀉，敢望禦重裘。"]'),
('yuding-47','哭京兆龐尹','馬戴','唐','御定全唐诗','yuding','','[]','神州喪賢尹，父老泣關中。未盡群生願，才留及物功。',60,'御定全唐詩/json/556.json','["神州喪賢尹，父老泣關中。未盡群生願，才留及物功。", "清光沉皎月，素業振遺風。履跡莓苔掩，珂聲紫陌空。", "從來受知者，會葬漢陵東。"]'),
('yuding-48','路傍樹','馬戴','唐','御定全唐诗','yuding','','[]','古樹何人種，清陰減昔時。莓苔根半露，風雨節偏危。',48,'御定全唐詩/json/556.json','["古樹何人種，清陰減昔時。莓苔根半露，風雨節偏危。", "蟲蠹心將穴，蟬催葉向衰。樵童不須翦，聊起邵公思。"]'),
('yuding-49','送客南游','馬戴','唐','御定全唐诗','yuding','','[]','擬卜何山隱，高秋指岳陽。葦幹雲夢色，橘熟洞庭香。',48,'御定全唐詩/json/556.json','["擬卜何山隱，高秋指岳陽。葦幹雲夢色，橘熟洞庭香。", "疏雨殘虹影，回雲背鳥行。靈均如可問，一為哭清湘。"]'),
('yuding-50','寄襄陽王公子','馬戴','唐','御定全唐诗','yuding','','[]','君馬勒金羈，君家貯玉笄。白雲登峴首，碧樹醉銅鞮。',48,'御定全唐詩/json/556.json','["君馬勒金羈，君家貯玉笄。白雲登峴首，碧樹醉銅鞮。", "澤廣荊州北，山多漢水西。鹿門知不隱，芳草自萋萋。"]'),
('yuding-51','集宿姚侍禦宅懷永樂宰殷侍禦','馬戴','唐','御定全唐诗','yuding','','[]','石田虞芮接，種樹白雲陰。穴閉神蹤古，河流禹鑿深。',48,'御定全唐詩/json/556.json','["石田虞芮接，種樹白雲陰。穴閉神蹤古，河流禹鑿深。", "樵人應滿郭，仙鳥幾巢林。此會偏相語，曾供雪夜吟。"]'),
('yuding-52','易水懷古','馬戴','唐','御定全唐诗','yuding','','[]','荊卿西去不復返，易水東流無盡期。',32,'御定全唐詩/json/556.json','["荊卿西去不復返，易水東流無盡期。", "落日蕭條薊城北，黃沙白草任風吹。"]'),
('yuding-53','送僧二首','馬戴','唐','御定全唐诗','yuding','','[]','親在平陽憶久歸，洪河雨漲出關遲。',64,'御定全唐詩/json/556.json','["親在平陽憶久歸，洪河雨漲出關遲。", "獨過舊寺人稀識，一一杉松老別時。", "龕中破衲自持行，樹下禪床坐一生。", "來往白雲知歲久，滿山猿鳥會經聲。"]'),
('yuding-54','贈友人邊游回','馬戴','唐','御定全唐诗','yuding','','[]','遊子新從絕塞回，自言曾上李陵台。',32,'御定全唐詩/json/556.json','["遊子新從絕塞回，自言曾上李陵台。", "尊前語盡北風起，秋色蕭條胡雁來。"]'),
('yuding-55','山中作','馬戴','唐','御定全唐诗','yuding','','[]','屐齒無泥竹策輕，莓苔梯滑夜難行。',32,'御定全唐詩/json/556.json','["屐齒無泥竹策輕，莓苔梯滑夜難行。", "獨開石室松門裏，月照前山空水聲。"]'),
('yuding-56','出塞詞','馬戴','唐','御定全唐诗','yuding','','[]','金帶連環束戰袍，馬頭沖雪度臨洮。',32,'御定全唐詩/json/556.json','["金帶連環束戰袍，馬頭沖雪度臨洮。", "卷旗夜劫單于帳，亂斫胡兒缺寶刀。"]'),
('yuding-57','寄雲台觀田秀才','馬戴','唐','御定全唐诗','yuding','','[]','雲壓松枝拂石窗，幽人獨坐鶴成雙。',32,'御定全唐詩/json/556.json','["雲壓松枝拂石窗，幽人獨坐鶴成雙。", "晚來漱齒敲冰渚，閑讀仙書倚翠幢。"]'),
('yuding-58','邊上送楊侍禦鞫獄回','馬戴','唐','御定全唐诗','yuding','','[]','獄成冤雪晚雲開，豸角威清塞雁回。',32,'御定全唐詩/json/556.json','["獄成冤雪晚雲開，豸角威清塞雁回。", "飛將送迎遙避馬，離亭不敢勸金杯。"]'),
('yuding-59','射雕騎','馬戴','唐','御定全唐诗','yuding','','[]','蕃面將軍著鼠裘，酣歌沖雪在邊州。',32,'御定全唐詩/json/556.json','["蕃面將軍著鼠裘，酣歌沖雪在邊州。", "獵過黑山猶走馬，寒雕射落不回頭。"]'),
('yuding-60','高司馬移竹','馬戴','唐','御定全唐诗','yuding','','[]','叢居堂下幸君移，翠掩燈窗露葉垂。',32,'御定全唐詩/json/556.json','["叢居堂下幸君移，翠掩燈窗露葉垂。", "莫羨孤生在山者，無人看著拂雲枝。"]'),
('yuding-61','贈前蔚州崔使君','馬戴','唐','御定全唐诗','yuding','','[]','戰回脫劍綰銅魚，塞雁迎風避隼旟。',32,'御定全唐詩/json/556.json','["戰回脫劍綰銅魚，塞雁迎風避隼旟。", "欲識前時為郡政，校成上下考新書。"]'),
('yuding-62','秋思二首','馬戴','唐','御定全唐诗','yuding','','[]','萬木秋霖後，孤山夕照餘。田園無歲計，寒近憶樵漁。',48,'御定全唐詩/json/556.json','["萬木秋霖後，孤山夕照餘。田園無歲計，寒近憶樵漁。", "亭樹霜霰滿，野塘鳧鳥多。蕙蘭不可折，楚老徒悲歌。"]'),
('yuding-63','黃神谷紀事','馬戴','唐','御定全唐诗','yuding','','[]','霹靂振秋嶽，折松橫洞門。雲龍忽變化，但覺玉潭昏。',24,'御定全唐詩/json/556.json','["霹靂振秋嶽，折松橫洞門。雲龍忽變化，但覺玉潭昏。"]'),
('yuding-64','過亡友墓','馬戴','唐','御定全唐诗','yuding','','[]','憶昨送君葬，今看墳樹高。尋思後期者，只是益生勞。',24,'御定全唐詩/json/556.json','["憶昨送君葬，今看墳樹高。尋思後期者，只是益生勞。"]'),
('yuding-65','聞瀑布冰折','馬戴','唐','御定全唐诗','yuding','','[]','萬仞冰峭折，寒聲投白雲。光搖山月墮，我向石床聞。',24,'御定全唐詩/json/556.json','["萬仞冰峭折，寒聲投白雲。光搖山月墮，我向石床聞。"]'),
('yuding-66','贈道者','馬戴','唐','御定全唐诗','yuding','','[]','深居白雲穴，靜注赤松經。往往龍潭上，焚香禮鬥星。',24,'御定全唐詩/json/556.json','["深居白雲穴，靜注赤松經。往往龍潭上，焚香禮鬥星。"]'),
('yuding-67','華下逢楊侍禦','馬戴','唐','御定全唐诗','yuding','','[]','巨靈掌上月，玉女盆中泉。柱史息車看，孤雲心浩然。',24,'御定全唐詩/json/556.json','["巨靈掌上月，玉女盆中泉。柱史息車看，孤雲心浩然。"]'),
('yuding-68','新春聞赦','馬戴','唐','御定全唐诗','yuding','','[]','道在猜讒息，仁深疾苦除。堯聰能下聽，湯網本來疏。',24,'御定全唐詩/json/556.json','["道在猜讒息，仁深疾苦除。堯聰能下聽，湯網本來疏。"]'),
('yuding-69','送李侍禦福建從事','馬戴','唐','御定全唐诗','yuding','','[]','晉安來越國，蔓草故宮迷。釣渚龍應在，琴台鶴亂棲。',72,'御定全唐詩/json/556.json','["晉安來越國，蔓草故宮迷。釣渚龍應在，琴台鶴亂棲。", "泛濤明月廣，邊海眾山齊。賓府通蘭棹，蠻僧接石梯。", "片雲和瘴濕，孤嶼映帆低。上客多詩興，秋猿足夜啼。"]'),
('yuding-70','酬刑部姚郎中','馬戴','唐','御定全唐诗','yuding','','[]','路岐人不見，尚得記心中。月憶瀟湘渚，春生蘭杜叢。',48,'御定全唐詩/json/556.json','["路岐人不見，尚得記心中。月憶瀟湘渚，春生蘭杜叢。", "鳥啼花半落，人散爵方空。所贈誠難答，泠然一雅風。"]'),
('yuding-71','送柳秀才往連州看弟','馬戴','唐','御定全唐诗','yuding','','[]','離人非逆旅，有弟謫連州。楚雨沾猿暮，湘雲拂雁秋。',48,'御定全唐詩/json/556.json','["離人非逆旅，有弟謫連州。楚雨沾猿暮，湘雲拂雁秋。", "蒹葭行廣澤，星月棹寒流。何處江關鎖，風濤阻客愁。"]'),
('yuding-72','晚眺有懷','馬戴','唐','御定全唐诗','yuding','','[]','點點抱離念，曠懷成怨歌。高臺試延望，落照在寒波。',48,'御定全唐詩/json/556.json','["點點抱離念，曠懷成怨歌。高臺試延望，落照在寒波。", "此地芳草歇，舊山喬木多。悠然暮天際，但見鳥相過。"]'),
('yuding-73','山中興作','馬戴','唐','御定全唐诗','yuding','','[]','高高丹桂枝，嫋嫋女蘿衣。密葉浮雲過，幽陰暮鳥歸。',48,'御定全唐詩/json/556.json','["高高丹桂枝，嫋嫋女蘿衣。密葉浮雲過，幽陰暮鳥歸。", "月和風翠動，花落瀑泉飛。欲剪蘭為佩，中林露未晞。"]'),
('yuding-74','送皇甫協律淮南從事','馬戴','唐','御定全唐诗','yuding','','[]','辟書丞相草，招作廣陵行。隋柳疏淮岸，汀洲接海城。',48,'御定全唐詩/json/556.json','["辟書丞相草，招作廣陵行。隋柳疏淮岸，汀洲接海城。", "楚檣經雨泊，煙月隔潮生。誰與同尊俎，雞鸞集虎營。"]'),
('yuding-75','別靈武令狐校書','馬戴','唐','御定全唐诗','yuding','','[]','北風吹別思，落月度關河。樹隱流沙短，山平近塞多。',48,'御定全唐詩/json/556.json','["北風吹別思，落月度關河。樹隱流沙短，山平近塞多。", "雁池戎馬飲，雕帳戍人過。莫慮行軍苦，華夷道正和。"]'),
('yuding-76','田氏南樓對月','馬戴','唐','御定全唐诗','yuding','','[]','主人同露坐，明月在高臺。咽咽陰蟲叫，蕭蕭寒雁來。',48,'御定全唐詩/json/556.json','["主人同露坐，明月在高臺。咽咽陰蟲叫，蕭蕭寒雁來。", "影搖疏木落，魄轉曙鐘開。倖免丹霞映，清光溢酒杯。"]'),
('yuding-77','送宗密上人','馬戴','唐','御定全唐诗','yuding','','[]','門前九陌塵，石上定中身。近放遼天鶴，曾為南嶽人。',48,'御定全唐詩/json/556.json','["門前九陌塵，石上定中身。近放遼天鶴，曾為南嶽人。", "臘高松葉換，雪盡茗芽新。一自傳香後，名山願卜鄰。"]'),
('yuding-78','白鹿原晚望','馬戴','唐','御定全唐诗','yuding','','[]','滻曲雁飛下，秦原人葬回。丘墳與城闕，草樹共塵埃。',24,'御定全唐詩/json/556.json','["滻曲雁飛下，秦原人葬回。丘墳與城闕，草樹共塵埃。"]'),
('yuding-79','失意書懷呈知己','馬戴','唐','御定全唐诗','yuding','','[]','直道何由啟聖君，非才誰敢議論文。心存黃籙兼丹訣，',40,'御定全唐詩/json/556.json','["直道何由啟聖君，非才誰敢議論文。心存黃籙兼丹訣，", "微生不學劉琨輩，劍刃相交擬立勳。"]'),
('yuding-80','春日尋滻川王處士','馬戴','唐','御定全唐诗','yuding','','[]','碧草徑微斷，白雲扉晚開。罷琴松韻發，鑒水月光來。',48,'御定全唐詩/json/556.json','["碧草徑微斷，白雲扉晚開。罷琴松韻發，鑒水月光來。", "宿鳥排花動，樵童澆竹回。與君同露坐，澗石拂青苔。"]'),
('yuding-81','宿陽臺觀','馬戴','唐','御定全唐诗','yuding','','[]','玉洞仙何在，爐香客自焚。醮壇圍古木，石磬響寒雲。',48,'御定全唐詩/json/556.json','["玉洞仙何在，爐香客自焚。醮壇圍古木，石磬響寒雲。", "曙月孤霞映，懸流峭壁分。心知人世隔，坐與鶴為群。"]'),
('yuding-82','寄金州姚使君員外','馬戴','唐','御定全唐诗','yuding','','[]','老懷清淨化，乞去守洵陽。廢井人應滿，空林虎自藏。',120,'御定全唐詩/json/556.json','["老懷清淨化，乞去守洵陽。廢井人應滿，空林虎自藏。", "迸泉疏石竇，殘雨發椒香。山缺通巴峽，江流帶楚檣。", "憂農生野思，禱廟結雲裝。覆局松移影，聽琴月墮光。", "鳥鳴開郡印，僧去置禪床。罷貢金休鑿，淩寒筍更長。", "退公披鶴氅，高步隔鵷行。相見朱門內，麾幢拂曙霜。"]'),
('yuding-83','中秋夜坐有懷','馬戴','唐','御定全唐诗','yuding','','[]','秋光動河漢，耿耿曙難分。墮露垂叢藥，殘星間薄雲。',48,'御定全唐詩/json/556.json','["秋光動河漢，耿耿曙難分。墮露垂叢藥，殘星間薄雲。", "心懸赤城嶠，志向紫陽君。雁過海風起，蕭蕭時獨聞。"]'),
('yuding-84','題鏡湖野老所居','馬戴','唐','御定全唐诗','yuding','','[]','湖裏尋君去，樵風往返吹。樹喧巢鳥出，路細葑田移。',48,'御定全唐詩/json/556.json','["湖裏尋君去，樵風往返吹。樹喧巢鳥出，路細葑田移。", "漚苧成魚網，枯根是酒卮。老年唯自適，生事任群兒。"]'),
('yuding-85','題女道士居','馬戴','唐','御定全唐诗','yuding','','[]','不餌住雲溪，休丹罷藥畦。杏花虛結子，石髓任成泥。',48,'御定全唐詩/json/556.json','["不餌住雲溪，休丹罷藥畦。杏花虛結子，石髓任成泥。", "掃地青牛臥，栽松白鶴棲。共知仙女麗，莫是阮郎妻。"]'),
('yuding-86','送王道士','馬戴','唐','御定全唐诗','yuding','','[]','真人俄整舄，雙鶴屢飛翔。恐入壺中住，須傳肘後方。',48,'御定全唐詩/json/556.json','["真人俄整舄，雙鶴屢飛翔。恐入壺中住，須傳肘後方。", "霓裳雲氣潤，石徑術苗香。一去何時見，仙家日月長。"]'),
('yuding-87','送道友入天臺山作','馬戴','唐','御定全唐诗','yuding','','[]','卻憶天臺去，移居海島空。觀寒琪樹碧，雪淺石橋通。',48,'御定全唐詩/json/556.json','["卻憶天臺去，移居海島空。觀寒琪樹碧，雪淺石橋通。", "漱齒飛泉外，餐霞早境中。終期赤城裏，披氅與君同。"]'),
('yuding-88','題章野人山居','馬戴','唐','御定全唐诗','yuding','','[]','帶郭茅亭詩興饒，回看一曲倚危橋。門前山色能深淺，',40,'御定全唐詩/json/556.json','["帶郭茅亭詩興饒，回看一曲倚危橋。門前山色能深淺，", "向此隱來經幾載，如今已是漢家朝。"]'),
('yuding-89','江中遇客','馬戴','唐','御定全唐诗','yuding','','[]','危石江中起，孤雲嶺上還。相逢皆得意，何處是鄉關。',24,'御定全唐詩/json/556.json','["危石江中起，孤雲嶺上還。相逢皆得意，何處是鄉關。"]'),
('yuding-90','期王煉師不至','馬戴','唐','御定全唐诗','yuding','','[]','黃精蒸罷洗瓊杯，林下從留石上苔。',32,'御定全唐詩/json/556.json','["黃精蒸罷洗瓊杯，林下從留石上苔。", "昨日圍棋未終局，多乘白鶴下山來。"]'),
('yuding-91','秋日送僧志幽歸山寺','馬戴','唐','御定全唐诗','yuding','','[]','禪室繩床在翠微，松間荷笠一僧歸。',32,'御定全唐詩/json/556.json','["禪室繩床在翠微，松間荷笠一僧歸。", "磬聲寂曆宜秋夜，手冷燈前自衲衣。"]'),
('yuding-92','句','馬戴','唐','御定全唐诗','yuding','','[]','申胥任向秦庭哭，靳尚終貽楚國憂。',16,'御定全唐詩/json/556.json','["申胥任向秦庭哭，靳尚終貽楚國憂。"]'),
('yuding-0','寄宜陽兄弟','易重','唐','御定全唐诗','yuding','','[]','六年雁序恨分離，詔下今朝遇已知。上國皇風初喜日，',40,'御定全唐詩/json/557.json','["六年雁序恨分離，詔下今朝遇已知。上國皇風初喜日，", "故里仙才若相問，一春攀得兩重枝。"]'),
('yuding-1','發蕙風館遇陰不見九華山有作','孟遲','唐','御定全唐诗','yuding','','[]','我來淮陰城，千江萬山無不經。山青水碧千萬丈，',44,'御定全唐詩/json/557.json','["我來淮陰城，千江萬山無不經。山青水碧千萬丈，", "人家敲鏡救不得，光陰卻屬貪狼星。恨亦不能通，"]'),
('yuding-2','寄浙右舊幕僚','孟遲','唐','御定全唐诗','yuding','','[]','由來惡舌駟難追，自古無媒謗所歸。勾踐豈能容範蠡，',40,'御定全唐詩/json/557.json','["由來惡舌駟難追，自古無媒謗所歸。勾踐豈能容範蠡，", "慚愧故人同鮑叔，此心江柳尚依依。"]'),
('yuding-3','壯士吟','孟遲','唐','御定全唐诗','yuding','','[]','壯士何曾悲，悲即無回期。如何易水上，未歌淚先垂。',24,'御定全唐詩/json/557.json','["壯士何曾悲，悲即無回期。如何易水上，未歌淚先垂。"]'),
('yuding-4','徐波渡','孟遲','唐','御定全唐诗','yuding','','[]','曉月千重樹，春煙十裏溪。過來還過去，此路不知迷。',24,'御定全唐詩/json/557.json','["曉月千重樹，春煙十裏溪。過來還過去，此路不知迷。"]'),
('yuding-5','題嘉祥驛','孟遲','唐','御定全唐诗','yuding','','[]','樹頂煙微綠，山根菊暗香。何人獨鞭馬，落日上嘉祥。',24,'御定全唐詩/json/557.json','["樹頂煙微綠，山根菊暗香。何人獨鞭馬，落日上嘉祥。"]'),
('yuding-6','懷鄭洎','孟遲','唐','御定全唐诗','yuding','','[]','風蘭舞幽香，雨葉墮寒滴。美人來不來，前山看向夕。',24,'御定全唐詩/json/557.json','["風蘭舞幽香，雨葉墮寒滴。美人來不來，前山看向夕。"]'),
('yuding-7','長信宮','孟遲','唐','御定全唐诗','yuding','','[]','君恩已盡欲何歸，猶有殘香在舞衣。',32,'御定全唐詩/json/557.json','["君恩已盡欲何歸，猶有殘香在舞衣。", "自恨身輕不如燕，春來還繞禦簾飛。"]'),
('yuding-8','閨情','孟遲','唐','御定全唐诗','yuding','','[]','山上有山歸不得，湘江暮雨鷓鴣飛。',32,'御定全唐詩/json/557.json','["山上有山歸不得，湘江暮雨鷓鴣飛。", "蘼蕪亦是王孫草，莫送春香入客衣。"]'),
('yuding-9','蓮塘','孟遲','唐','御定全唐诗','yuding','','[]','脈脈低回殷袖遮，臉橫秋水髻盤鴉。',32,'御定全唐詩/json/557.json','["脈脈低回殷袖遮，臉橫秋水髻盤鴉。", "蓮莖有刺不成折，盡日岸傍空看花。"]'),
('yuding-10','還淮卻寄睢陽','孟遲','唐','御定全唐诗','yuding','','[]','梁王池苑已蒼然，滿樹斜陽極浦煙。',32,'御定全唐詩/json/557.json','["梁王池苑已蒼然，滿樹斜陽極浦煙。", "盡日回頭看不見，兩行愁淚上南船。"]'),
('yuding-11','烏江','孟遲','唐','御定全唐诗','yuding','','[]','中分豈是無遺策，百戰空勞不逝騅。',32,'御定全唐詩/json/557.json','["中分豈是無遺策，百戰空勞不逝騅。", "大業固非人事及，烏江亭長又何知。"]'),
('yuding-12','新安故關','孟遲','唐','御定全唐诗','yuding','','[]','漢帝英雄重武材，崇山險處鑿門開。',32,'御定全唐詩/json/557.json','["漢帝英雄重武材，崇山險處鑿門開。", "如今更有將軍否，移取潼關向北來。"]'),
('yuding-13','廣陵城','孟遲','唐','御定全唐诗','yuding','','[]','紅繞高臺綠繞城，城邊春草傍牆生。',32,'御定全唐詩/json/557.json','["紅繞高臺綠繞城，城邊春草傍牆生。", "隋家不向此中盡，汴水應無東去聲。"]'),
('yuding-14','過驪山','孟遲','唐','御定全唐诗','yuding','','[]','冷日微煙渭水愁，華清宮樹不勝秋。',32,'御定全唐詩/json/557.json','["冷日微煙渭水愁，華清宮樹不勝秋。", "霓裳一曲千門鎖，白盡梨園弟子頭。"]'),
('yuding-15','吳故宮','孟遲','唐','御定全唐诗','yuding','','[]','越女歌長君且聽，芙蓉香滿水邊城。',32,'御定全唐詩/json/557.json','["越女歌長君且聽，芙蓉香滿水邊城。", "豈知一日終非主，猶自如今有怨聲。"]'),
('yuding-16','蘭昌宮','孟遲','唐','御定全唐诗','yuding','','[]','宮門兩片掩埃塵，牆上無花草不春。',32,'御定全唐詩/json/557.json','["宮門兩片掩埃塵，牆上無花草不春。", "誰見當時禁中事，阿嬌解佩與何人。"]'),
('yuding-17','宮人斜','孟遲','唐','御定全唐诗','yuding','','[]','雲慘煙愁苑路斜，路傍丘塚盡宮娃。',32,'御定全唐詩/json/557.json','["雲慘煙愁苑路斜，路傍丘塚盡宮娃。", "茂陵不是同歸處，空寄香魂著野花。"]'),
('yuding-18','句','孟遲','唐','御定全唐诗','yuding','','[]','天地有時饒一擲。江山無主任平分。',16,'御定全唐詩/json/557.json','["天地有時饒一擲。江山無主任平分。"]'),
('yuding-19','和于興宗登越王樓詩','王鐸','唐','御定全唐诗','yuding','','[]','謝脁題詩處，危樓壓郡城。雨餘江水碧，雲斷雪山明。',48,'御定全唐詩/json/557.json','["謝脁題詩處，危樓壓郡城。雨餘江水碧，雲斷雪山明。", "錦繡來仙境，風光入帝京。恨無青玉案，何以報高情。"]'),
('yuding-20','謁梓潼張惡子廟','王鐸','唐','御定全唐诗','yuding','','[]','盛唐聖主解青萍，欲振新封濟順名。夜雨龍拋三尺匣，',40,'御定全唐詩/json/557.json','["盛唐聖主解青萍，欲振新封濟順名。夜雨龍拋三尺匣，", "惟報關東諸將相，柱天功業賴陰兵。"]'),
('yuding-21','罷都統守鎮滑州作','王鐸','唐','御定全唐诗','yuding','','[]','用軍何事敢遷延，恩重才輕分使然。黜詔已聞來闕下，',48,'御定全唐詩/json/557.json','["用軍何事敢遷延，恩重才輕分使然。黜詔已聞來闕下，", "正會星辰扶北極，卻驅戈甲鎮南燕。三塵上相逢明主，"]'),
('yuding-22','句','王鐸','唐','御定全唐诗','yuding','','[]','華表尚迷丁令鶴，竹坡猶認葛溪龍。。',17,'御定全唐詩/json/557.json','["華表尚迷丁令鶴，竹坡猶認葛溪龍。。"]'),
('yuding-23','中秋月直禁苑','鄭畋','唐','御定全唐诗','yuding','','[]','禁署方懷忝，綸闈已再加。暫來西掖路，還整上清槎。',48,'御定全唐詩/json/557.json','["禁署方懷忝，綸闈已再加。暫來西掖路，還整上清槎。", "恍惚歸丹地，深嚴宿絳霞。幽襟聊自適，閑弄紫薇花。"]'),
('yuding-24','麥穗兩岐','鄭畋','唐','御定全唐诗','yuding','','[]','聖慮憂千畝，嘉苗薦兩岐。如雲方表盛，成穗忽標奇。',72,'御定全唐詩/json/557.json','["聖慮憂千畝，嘉苗薦兩岐。如雲方表盛，成穗忽標奇。", "瑞露縱橫滴，祥風左右吹。謳歌連上苑，化日遍平陂。", "史冊書堪重，丹青畫更宜。願依連理樹，俱作萬年枝。"]'),
('yuding-25','五月一日紫宸候對時屬禁直穿內而行因書六韻','鄭畋','唐','御定全唐诗','yuding','','[]','朱夏五更後，步廊三裏餘。有人從翰苑，穿入內中書。',72,'御定全唐詩/json/557.json','["朱夏五更後，步廊三裏餘。有人從翰苑，穿入內中書。", "漏響飄銀箭，燈光照玉除。禁扉猶鎖鑰，宮妓已妝梳。", "紫府游應似，鈞天夢不如。塵埃九重外，誰信在清虛。"]'),
('yuding-26','題緱山王子晉廟','鄭畋','唐','御定全唐诗','yuding','','[]','有昔靈王子，吹笙溯泬。六宮攀不住，三島去相招。',264,'御定全唐詩/json/557.json','["有昔靈王子，吹笙溯泬。六宮攀不住，三島去相招。", "亡國原陵古，賓天歲月遙。無蹊窺海曲，有廟訪山椒。", "石帳龍蛇拱，雲櫳彩翠銷。露壇裝琬琰，真像寫松喬。", "珠館青童宴，琳宮阿母朝。氣輿仙女侍，天馬吏兵調。", "湘妓紅絲瑟，秦郎白管簫。西城要綽約，南嶽命嬌嬈。", "句曲觴金洞，天臺嘯石橋。晚花珠弄蕊，春茹玉生苗。", "二景神光秘，三元寶籙饒。霧垂鴉翅發，冰束虎章腰。", "鶴馭爭銜箭，龍妃合獻綃。衣從星渚浣，丹就日宮燒。", "物外花嘗滿，人間葉自凋。望台悲漢戾，閱水笑梁昭。", "古殿香殘灺，荒階柳長條。幾曾期七日，無複降重霄。", "嵩嶺連天漢，伊瀾入海潮。何由得真訣，使我佩環飄。"]'),
('yuding-27','初秋寓直三首','鄭畋','唐','御定全唐诗','yuding','','[]','曉星獨掛結麟樓，三殿風高藥樹秋。',96,'御定全唐詩/json/557.json','["曉星獨掛結麟樓，三殿風高藥樹秋。", "玉笛數聲飄不住，問人依約在東頭。", "宿鳥翩翩落照微，石台樓閣鎖重扉。", "步廊無限金羈響，應是諸司扈從歸。", "幽閣焚香萬慮凝，下簾胎息過禪僧。", "玉堂分照無人後，消盡金盆一碗冰。"]'),
('yuding-28','夜景又作','鄭畋','唐','御定全唐诗','yuding','','[]','鈴絛無響閉珠宮，小閣涼添玉蕊風。',32,'御定全唐詩/json/557.json','["鈴絛無響閉珠宮，小閣涼添玉蕊風。", "枕簟滿床明月到，自疑身在五雲中。"]'),
('yuding-29','杪秋夜直','鄭畋','唐','御定全唐诗','yuding','','[]','蕊宮裁詔與宵分，雖在青雲憶白雲。',32,'御定全唐詩/json/557.json','["蕊宮裁詔與宵分，雖在青雲憶白雲。", "待報君恩了歸去，山翁何急草移文。"]'),
('yuding-30','禁直寄崔員外','鄭畋','唐','御定全唐诗','yuding','','[]','銀台樓北蕊珠宮，夐與人間路不同。',32,'御定全唐詩/json/557.json','["銀台樓北蕊珠宮，夐與人間路不同。", "在省五更春睡侶，早來分夢玉堂中。"]'),
('yuding-31','聞號','鄭畋','唐','御定全唐诗','yuding','','[]','陛兵偏近羽林營，夜靜仍傳禁號聲。',32,'御定全唐詩/json/557.json','["陛兵偏近羽林營，夜靜仍傳禁號聲。", "應笑執金雙闕下，近南猶隔兩重城。"]'),
('yuding-32','禁直和人飲酒','鄭畋','唐','御定全唐诗','yuding','','[]','卉醴陀花物外香，清濃標格勝椒漿。',32,'御定全唐詩/json/557.json','["卉醴陀花物外香，清濃標格勝椒漿。", "我來尚有鈞天會，猶得金尊半日嘗。"]'),
('yuding-33','下直早出','鄭畋','唐','御定全唐诗','yuding','','[]','諸司人盡馬蹄稀，紫帕雲竿九釘歸。',32,'御定全唐詩/json/557.json','["諸司人盡馬蹄稀，紫帕雲竿九釘歸。", "偏覺石台清貴處，榜懸金字射晴暉。"]'),
('yuding-34','金鑾坡上南望','鄭畋','唐','御定全唐诗','yuding','','[]','玉晨鐘韻上清虛，畫戟祥煙拱帝居。',32,'御定全唐詩/json/557.json','["玉晨鐘韻上清虛，畫戟祥煙拱帝居。", "極眼向南無限地，綠煙深處認中書。"]'),
('yuding-35','酬隱珪舍人寄紅燭','鄭畋','唐','御定全唐诗','yuding','','[]','蜜炬殷紅畫不如，且將歸去照吾廬。',32,'御定全唐詩/json/557.json','["蜜炬殷紅畫不如，且將歸去照吾廬。", "今來並得三般事，靈運詩篇逸少書。"]'),
('yuding-36','馬嵬坡','鄭畋','唐','御定全唐诗','yuding','','[]','玄宗回馬楊妃死，雲雨雖亡日月新。',32,'御定全唐詩/json/557.json','["玄宗回馬楊妃死，雲雨雖亡日月新。", "終是聖明天子事，景陽宮井又何人。"]'),
('yuding-37','句','鄭畋','唐','御定全唐诗','yuding','','[]','圓明青z3飯，光潤碧霞漿。。浴殿晴秋倘中謝，殘英猶可醉瓊杯。（《紫薇花》。',45,'御定全唐詩/json/557.json','["圓明青z3飯，光潤碧霞漿。。浴殿晴秋倘中謝，殘英猶可醉瓊杯。（《紫薇花》。", "見《海錄碎事》）"]'),
('yuding-38','題九華山','譚銖','唐','御定全唐诗','yuding','','[]','憶聞九華山，尚在童稚年。浮沉任名路，窺仰會無緣。',180,'御定全唐詩/json/557.json','["憶聞九華山，尚在童稚年。浮沉任名路，窺仰會無緣。", "罷職池陽時，複遭迎送牽。因茲契誠願，矚望枕席前。", "況值春正濃，氣色無不全。或如碧玉靜，或似青靄鮮。", "或接白雲堆，或映紅霞天。呈姿既不一，變態何啻千。", "巍峨本無動，崇峻性豈偏。外景自隱隱，潛虛固幽玄。", "我來暗凝情，務道志更堅。色與山異性，性並山亦然。", "境變山不動，性存形自遷。自遷不阻俗，自定不失賢。", "浮華與朱紫，安可迷心田。"]'),
('yuding-39','真娘墓','譚銖','唐','御定全唐诗','yuding','','[]','武丘山下塚累累，松柏蕭條盡可悲。',32,'御定全唐詩/json/557.json','["武丘山下塚累累，松柏蕭條盡可悲。", "何事世人偏重色，真娘墓上獨題詩。"]'),
('yuding-40','望九華山','盧嗣立','唐','御定全唐诗','yuding','','[]','九華深翠落軒楹，迥眺澄江氣象明。不遇陰霾孤岫隱，',40,'御定全唐詩/json/557.json','["九華深翠落軒楹，迥眺澄江氣象明。不遇陰霾孤岫隱，", "得路歸山期早訣，夜來潛已告精誠。"]'),
('yuding-41','應舉日寄兄弟','朱可名','唐','御定全唐诗','yuding','','[]','廢刈鏡湖田，上書紫閣前。愁人久委地，詩道未聞天。',48,'御定全唐詩/json/557.json','["廢刈鏡湖田，上書紫閣前。愁人久委地，詩道未聞天。", "不是燒金手，徒拋釣月船。多慚兄弟意，不敢問林泉。"]'),
('yuding-42','河出榮光','張良器','唐','御定全唐诗','yuding','','[]','引派昆山峻，朝宗海路長。千齡逢聖主，五色瑞榮光。',96,'御定全唐詩/json/557.json','["引派昆山峻，朝宗海路長。千齡逢聖主，五色瑞榮光。", "隱映浮中國，晶明助太陽。坤維連浩漫，天漢接微茫。", "丹闕清氛裏，函關紫氣旁。位尊常守伯，道泰每呈祥。", "習坎靈逾久，居卑德有常。龍門如可涉，忠信是舟梁。"]'),
('yuding-0','新雪八韻','薛能','唐','御定全唐诗','yuding','','[]','大雪滿初晨，開門萬象新。龍鍾雞未起，蕭索我何貧。',96,'御定全唐詩/json/558.json','["大雪滿初晨，開門萬象新。龍鍾雞未起，蕭索我何貧。", "耀若花前境，清如物外身。細飛斑戶牖，幹灑亂松筠。", "正色凝高嶺，隨流助要津。鼎消微是滓，車碾半和塵。", "茶興留詩客，瓜情想戍人。終篇本無字，誰別勝陽春。"]'),
('yuding-1','國學試風化下','薛能','唐','御定全唐诗','yuding','','[]','霽闕露穹崇，含生仰聖聰。英明高比日，聲教下如風。',72,'御定全唐詩/json/558.json','["霽闕露穹崇，含生仰聖聰。英明高比日，聲教下如風。", "靜發宸居內，低來品物中。南熏歌自溥，北極響皆通。", "蘋末看無狀，人間覺有功。因今委泥者，睹此忘途窮。"]'),
('yuding-2','升平詞十首','薛能','唐','御定全唐诗','yuding','','[]','瑞氣繞宮樓，皇居信上游。遠岡連聖祚，平地載神州。',480,'御定全唐詩/json/558.json','["瑞氣繞宮樓，皇居信上游。遠岡連聖祚，平地載神州。", "會合皆重譯，潺湲近八流。中興豈假問，據此自千秋。", "寥泬敞延英，朝班立位橫。宣傳無草動，拜舞有衣聲。", "鴛瓦霜消濕，蟲絲日照明。辛勤自不到，遙見似前程。", "處處是歡心，時康歲已深。不同三尺劍，應似五弦琴。", "壽笑山猶盡，明嫌日有陰。何當憐一物，亦遣斷愁吟。", "曙質絕埃氛，彤庭列禁軍。聖顏初對日，龍尾競緣雲。", "佩響交成韻，簾陰暖帶紋。逍遙豈有事，于此詠南熏。", "一物至周天，洪纖盡晏然。車書無異俗，甲子並豐年。", "奇技皆歸樸，征夫亦服田。君王故不有，台鼎合韋弦。", "日日聽歌謠，區中盡祝堯。蟲蝗初不害，夷狄近全銷。", "史筆惟書瑞，天臺絕見妖。因令匹夫志，轉欲事清朝。", "品物盡昭蘇，神功複帝謨。他時應有壽，當代且無虞。", "賜曆通遐俗，移關入半胡。鷦鷯一何幸，於此寄微軀。", "無戰複無私，堯時即此時。焚香臨極早，待月捲簾遲。", "端拱乾坤內，何言黈纊垂。君看聖明驗，只此是神龜。", "旭日上清穹，明堂坐聖聰。衣裳承瑞氣，冠冕蓋重瞳。", "花木經宵露，旌旗入仗風。何期於此地，見說是神工。", "五帝三皇主，蕭曹魏邴臣。文章惟返朴，戈甲盡生塵。", "諫紙應無用，朝綱自有倫。升平不可記，所見是閒人。"]'),
('yuding-3','送馮溫往河外','薛能','唐','御定全唐诗','yuding','','[]','琴劍事行裝，河關出北方。秦音盡河內，魏畫自黎陽。',48,'御定全唐詩/json/558.json','["琴劍事行裝，河關出北方。秦音盡河內，魏畫自黎陽。", "野日村苗熟，秋霜館葉黃。風沙問船處，應得立清漳。"]'),
('yuding-4','送從兄之太原副使','薛能','唐','御定全唐诗','yuding','','[]','少載琴書去，須知暫佐軍。初程見西嶽，盡室渡橫汾。',48,'御定全唐詩/json/558.json','["少載琴書去，須知暫佐軍。初程見西嶽，盡室渡橫汾。", "元日何州住，枯風宿館聞。都門送行處，青紫騎紛紛。"]'),
('yuding-5','送馬戴書記之太原','薛能','唐','御定全唐诗','yuding','','[]','一曲大河聲，全家幾日行。從容長約夜，差互忽離城。',48,'御定全唐詩/json/558.json','["一曲大河聲，全家幾日行。從容長約夜，差互忽離城。", "鎮北胡沙淺，途中霍嶽橫。相逢莫已訊，詩雅負雄名。"]'),
('yuding-6','送友人出塞','薛能','唐','御定全唐诗','yuding','','[]','榆關到不可，何況出榆關。春草臨岐斷，邊樓帶日閑。',48,'御定全唐詩/json/558.json','["榆關到不可，何況出榆關。春草臨岐斷，邊樓帶日閑。", "人歸穹帳外，鳥亂廢營間。此地堪愁想，霜前作意還。"]'),
('yuding-7','送李溟出塞','薛能','唐','御定全唐诗','yuding','','[]','邊城官尚惡，況乃是羈遊。別路應相憶，離亭更少留。',48,'御定全唐詩/json/558.json','["邊城官尚惡，況乃是羈遊。別路應相憶，離亭更少留。", "黃沙人外闊，飛雪馬前稠。甚險穹廬宿，無為過代州。"]'),
('yuding-8','寄終南隱者','薛能','唐','御定全唐诗','yuding','','[]','海日東南出，應開嶺上扉。掃壇花入篲，科竹露沾衣。',48,'御定全唐詩/json/558.json','["海日東南出，應開嶺上扉。掃壇花入篲，科竹露沾衣。", "飯後嫌身重，茶中見鳥歸。相思愛民者，難說與親違。"]'),
('yuding-9','贈隱者','薛能','唐','御定全唐诗','yuding','','[]','自得高閑性，平生向北棲。月潭雲影斷，山葉雨聲齊。',48,'御定全唐詩/json/558.json','["自得高閑性，平生向北棲。月潭雲影斷，山葉雨聲齊。", "庭樹人書匝，欄花鳥坐低。相留永不忘，經宿話丹梯。"]'),
('yuding-10','惜春','薛能','唐','御定全唐诗','yuding','','[]','花開亦花落，時節暗中遷。無計延春日，可能留少年。',48,'御定全唐詩/json/558.json','["花開亦花落，時節暗中遷。無計延春日，可能留少年。", "小叢初散蝶，高柳即聞蟬。繁豔歸何處，滿山啼杜鵑。"]'),
('yuding-11','送人自蘇州之長沙縣官','薛能','唐','御定全唐诗','yuding','','[]','驅馬複乘流，何時發虎丘。全家上南嶽，一尉事諸侯。',48,'御定全唐詩/json/558.json','["驅馬複乘流，何時發虎丘。全家上南嶽，一尉事諸侯。", "茶煮朝宗水，船停調角州。炎方好將息，卑濕舊堪憂。"]'),
('yuding-12','早春歸山中舊居','薛能','唐','御定全唐诗','yuding','','[]','茫茫驅匹馬，歸處是荒榛。猿跡破庭雪，鼠蹤生甑塵。',48,'御定全唐詩/json/558.json','["茫茫驅匹馬，歸處是荒榛。猿跡破庭雪，鼠蹤生甑塵。", "開門沖網斷，掃葉放苔勻。為惜詩情錯，應難致此身。"]'),
('yuding-13','麟中寓居寄蒲中友人','薛能','唐','御定全唐诗','yuding','','[]','蕭條秋雨地，獨院阻同群。一夜驚為客，多年不見君。',48,'御定全唐詩/json/558.json','["蕭條秋雨地，獨院阻同群。一夜驚為客，多年不見君。", "邊心生落日，鄉思羨歸雲。更在相思處，子規燈下聞。"]'),
('yuding-14','關中送別','薛能','唐','御定全唐诗','yuding','','[]','一行千裏外，幾事寸心間。才子貧堪歎，男兒別是閑。',48,'御定全唐詩/json/558.json','["一行千裏外，幾事寸心間。才子貧堪歎，男兒別是閑。", "黃河淹華岳，白日照潼關。若值鄉人問，終軍賤不還。"]'),
('yuding-15','中秋夜寄李溟','薛能','唐','御定全唐诗','yuding','','[]','滿魄斷埃氛，牽吟並舍聞。一年唯此夜，到晚願無雲。',48,'御定全唐詩/json/558.json','["滿魄斷埃氛，牽吟並舍聞。一年唯此夜，到晚願無雲。", "待賞從初出，看行過二分。嚴城亦已閉，悔不預期君。"]'),
('yuding-16','贈禪師','薛能','唐','御定全唐诗','yuding','','[]','夢想青山寺，前年住此中。夜堂吹竹雨，春地落花風。',48,'御定全唐詩/json/558.json','["夢想青山寺，前年住此中。夜堂吹竹雨，春地落花風。", "舊句師曾見，清齋我亦同。浮生蹇莫問，辛苦未成功。"]'),
('yuding-17','送禪僧','薛能','唐','御定全唐诗','yuding','','[]','寒空孤鳥度，落日一僧歸。近寺路聞梵，出郊風滿衣。',48,'御定全唐詩/json/558.json','["寒空孤鳥度，落日一僧歸。近寺路聞梵，出郊風滿衣。", "步搖瓶浪起，盂戛磬聲微。還坐棲禪所，荒山月照扉。"]'),
('yuding-18','贈隱者','薛能','唐','御定全唐诗','yuding','','[]','門前雖有徑，絕向世間行。薙草因逢藥，移花便得鶯。',48,'御定全唐詩/json/558.json','["門前雖有徑，絕向世間行。薙草因逢藥，移花便得鶯。", "甘貧原是道，苦學不為名。莫怪蒼髭晚，無機任世情。"]'),
('yuding-19','冬日送僧歸吳中舊居','薛能','唐','御定全唐诗','yuding','','[]','去掃冬林下，閑持未遍經。為山低鑿牖，容月廣開庭。',48,'御定全唐詩/json/558.json','["去掃冬林下，閑持未遍經。為山低鑿牖，容月廣開庭。", "舊業雲千里，生涯水一瓶。還應覓新句，看雪倚禪扃。"]'),
('yuding-20','恭禧皇太后挽歌詞三首','薛能','唐','御定全唐诗','yuding','','[]','八月曾殊選，三星固異儀。袝陵經灞滻，歸賵雜華夷。',144,'御定全唐詩/json/558.json','["八月曾殊選，三星固異儀。袝陵經灞滻，歸賵雜華夷。", "旌去題新諡，宮存鎖素幃。重泉應不恨，生見太平時。", "月落娥兼隱，宮空後豈還。銜哀窮地界，親蒞泣天顏。", "舊住留丹藥，新陵在碧山。國人傷莫及，應只詠關關。", "配聖三朝隔，靈儀萬姓哀。多年好黃老，舊日薦賢才。", "道著標彤管，宮閑閉綠苔。平生六衣在，曾著祀高禖。"]'),
('yuding-21','送胡澳下第歸蒲津','薛能','唐','御定全唐诗','yuding','','[]','無媒甘下飛，君子尚麻衣。歲月終榮在，家園近且歸。',48,'御定全唐詩/json/558.json','["無媒甘下飛，君子尚麻衣。歲月終榮在，家園近且歸。", "山光臨舜廟，河氣隔王畿。甚積湯原思，青青宿麥肥。"]'),
('yuding-22','春日閒居','薛能','唐','御定全唐诗','yuding','','[]','權門多見薄，吾道豈終行。散地徒憂國，良時不在城。',48,'御定全唐詩/json/558.json','["權門多見薄，吾道豈終行。散地徒憂國，良時不在城。", "花繁春正王，茶美夢初驚。賴有茲文在，猶堪暢此生。"]'),
('yuding-23','題逃戶','薛能','唐','御定全唐诗','yuding','','[]','幾界瞢農桑，凶年竟失鄉。朽關生濕菌，傾屋照斜陽。',48,'御定全唐詩/json/558.json','["幾界瞢農桑，凶年竟失鄉。朽關生濕菌，傾屋照斜陽。", "雨水淹殘臼，葵花壓倒牆。明時豈致此，應自負蒼蒼。"]'),
('yuding-24','郊居答客','薛能','唐','御定全唐诗','yuding','','[]','傍舍蟲聲滿，殘秋宿雨村。遠勞才子騎，光顧野人門。',48,'御定全唐詩/json/558.json','["傍舍蟲聲滿，殘秋宿雨村。遠勞才子騎，光顧野人門。", "敗葉盤空蔓，雕叢露暗根。相攜未盡語，川月照黃昏。"]'),
('yuding-25','早春歸山中舊居','薛能','唐','御定全唐诗','yuding','','[]','綠草閉閑院，悄然花正開。新年人未去，戊日燕還來。',48,'御定全唐詩/json/558.json','["綠草閉閑院，悄然花正開。新年人未去，戊日燕還來。", "雨地殘枯沫，燈窗積舊煤。歸田語不忘，樗散料非才。"]'),
('yuding-26','下第後春日長安寓居三首','薛能','唐','御定全唐诗','yuding','','[]','一榜盡精選，此身猶陸沉。自無功讜分，敢抱怨尤心。',144,'御定全唐詩/json/558.json','["一榜盡精選，此身猶陸沉。自無功讜分，敢抱怨尤心。", "暖陌開花氣，春居閉日陰。相知豈不有，知淺未知深。", "暫屈固何恨，所憂無此時。來年空仰望，臨日又參差。", "勞力且成病，壯心能不衰。猶將琢磨意，更欲候宗師。", "關東歸不得，豈是愛他鄉。草碧餘花落，春閑白日長。", "全家期聖澤，半路敢農桑。獨立應無侶，浮生欲自傷。"]'),
('yuding-27','春早選寓長安二首','薛能','唐','御定全唐诗','yuding','','[]','疏拙自沉昏，長安豈是村。春非閑客事，花在五侯門。',96,'御定全唐詩/json/558.json','["疏拙自沉昏，長安豈是村。春非閑客事，花在五侯門。", "道僻惟憂禍，詩深不敢論。揚雄若有薦，君聖合承恩。", "舊論已浮海，此心猶滯秦。上僚如報國，公道豈無人。", "岩隱懸溪瀑，城居入榻塵。漁舟即擬去，不待晚年身。"]'),
('yuding-28','送進士許棠下第東歸','薛能','唐','御定全唐诗','yuding','','[]','長安那不住，西笑又東行。若以貧無計，何因事有成。',48,'御定全唐詩/json/558.json','["長安那不住，西笑又東行。若以貧無計，何因事有成。", "雲峰天外出，江色草中明。謾忝相於分，吾言世甚輕。"]'),
('yuding-29','詠島','薛能','唐','御定全唐诗','yuding','','[]','孤島如江上，詩家猶閉門。一池分倒影，空舸系荒根。',48,'御定全唐詩/json/558.json','["孤島如江上，詩家猶閉門。一池分倒影，空舸系荒根。", "煙濕高吟石，雲生偶坐痕。登臨有新句，公退與誰論。"]'),
('yuding-30','冬日寫懷','薛能','唐','御定全唐诗','yuding','','[]','幕府盡平蠻，客留戎閫間。急流霜夾水，輕靄日連山。',48,'御定全唐詩/json/558.json','["幕府盡平蠻，客留戎閫間。急流霜夾水，輕靄日連山。", "設醴徒慚楚，為郎未姓顏。斯文苦不勝，會擬老民閑。"]'),
('yuding-31','和楊中丞早春即事','薛能','唐','御定全唐诗','yuding','','[]','貴宅登臨地，春來見物華。遠江橋外色，繁杏竹邊花。',48,'御定全唐詩/json/558.json','["貴宅登臨地，春來見物華。遠江橋外色，繁杏竹邊花。", "戍客烽樓迥，文君酒幔斜。新題好不極，珠府未窮奢。"]'),
('yuding-32','聞官軍破吉浪戎小而固慮史氏遺忽因記為二章','薛能','唐','御定全唐诗','yuding','','[]','一戰便抽兵，蠻孤吉浪平。通連無舊穴，要害有新城。',96,'御定全唐詩/json/558.json','["一戰便抽兵，蠻孤吉浪平。通連無舊穴，要害有新城。", "晝卒烽前寢，春農界上耕。高樓一擬望，新雨劍南清。", "瀘水斷囂氛，妖巢已自焚。漢江無敵國，蠻物在回軍。", "越巂通游國，苴咩閉聚蚊。空餘羅鳳曲，哀思滿邊雲。"]'),
('yuding-33','寒食有懷','薛能','唐','御定全唐诗','yuding','','[]','流落傷寒食，登臨望歲華。村球高過索，墳樹綠和花。',48,'御定全唐詩/json/558.json','["流落傷寒食，登臨望歲華。村球高過索，墳樹綠和花。", "晉聚應搜火，秦喧定走車。誰知恨榆柳，風景似吾家。"]'),
('yuding-34','綿樓','薛能','唐','御定全唐诗','yuding','','[]','溪邊人浣紗，樓下海棠花。極望雖懷土，多情擬置家。',48,'御定全唐詩/json/558.json','["溪邊人浣紗，樓下海棠花。極望雖懷土，多情擬置家。", "前山應象外，此地已天涯。未有銷憂賦，梁王禮欲奢。"]'),
('yuding-35','雕堂','薛能','唐','御定全唐诗','yuding','','[]','丈室久多病，小園晴獨遊。鳴蛩孤燭雨，啅雀一籬秋。',48,'御定全唐詩/json/558.json','["丈室久多病，小園晴獨遊。鳴蛩孤燭雨，啅雀一籬秋。", "聖主恩難謝，生靈志亦憂。他年誰識我，心跡在徐州。"]'),
('yuding-36','贈歌人','薛能','唐','御定全唐诗','yuding','','[]','溫燠坐相侵，羅襦一水沉。拜深知有意，令背不無心。',48,'御定全唐詩/json/558.json','["溫燠坐相侵，羅襦一水沉。拜深知有意，令背不無心。", "近住應名玉，前生約姓陰。東山期已定，相許便抽簪。"]'),
('yuding-37','柘枝詞三首','薛能','唐','御定全唐诗','yuding','','[]','同營三十萬，震鼓伐西羌。戰血粘秋草，征塵攪夕陽。',108,'御定全唐詩/json/558.json','["同營三十萬，震鼓伐西羌。戰血粘秋草，征塵攪夕陽。", "歸來人不識，帝裏獨戎裝。", "懸軍征拓羯，內地隔蕭關。日色昆侖上，風聲朔漠間。", "何當千萬騎，颯颯貳師還。", "意氣成功日，春風起絮天。樓臺新邸第，歌舞小嬋娟。", "急破催搖曳，羅衫半脫肩。"]'),
('yuding-38','詠柳花','薛能','唐','御定全唐诗','yuding','','[]','浮生失意頻，起絮又飄淪。發自誰家樹，飛來獨院春。',72,'御定全唐詩/json/558.json','["浮生失意頻，起絮又飄淪。發自誰家樹，飛來獨院春。", "朝容縈斷砌，晴影過諸鄰。亂掩宮中蝶，繁沖陌上人。", "隨波應到海，沾雨或依塵。會向慈恩日，輕輕對此身。"]'),
('yuding-39','一葉落','薛能','唐','御定全唐诗','yuding','','[]','輕葉獨悠悠，天高片影流。隨風來此地，何樹落先秋。',72,'御定全唐詩/json/558.json','["輕葉獨悠悠，天高片影流。隨風來此地，何樹落先秋。", "變色黃應近，辭林綠尚稠。無雙浮水面，孤絕落關頭。", "乍減誠難覺，將凋勢未休。客心空自比，誰肯問新愁。"]'),
('yuding-40','行路難','薛能','唐','御定全唐诗','yuding','','[]','何處力堪殫，人心險萬端。藏山難測度，暗水自波瀾。',72,'御定全唐詩/json/558.json','["何處力堪殫，人心險萬端。藏山難測度，暗水自波瀾。", "對面如千里，回腸似七盤。已經吳阪困，欲向雁門難。", "南北誠須泣，高深不可幹。無因善行止，車轍得平安。"]'),
('yuding-41','蔡州蔣亭','薛能','唐','御定全唐诗','yuding','','[]','草徑徹林間，過橋如入山。蔡侯添水榭，蔣氏本柴關。',72,'御定全唐詩/json/558.json','["草徑徹林間，過橋如入山。蔡侯添水榭，蔣氏本柴關。", "靜泛窮幽趣，驚飛濕醉顏。恨無優俸買，來得暫時閑。", "步與招提接，舟臨夕照還。春風應不到，前想負花灣。"]'),
('yuding-42','戲題','薛能','唐','御定全唐诗','yuding','','[]','閃閃動鳴璫，初來燭影傍。擁頭珠翠重，縈步綺羅長。',72,'御定全唐詩/json/558.json','["閃閃動鳴璫，初來燭影傍。擁頭珠翠重，縈步綺羅長。", "靜發歌如磬，連飄氣覺香。不言微有笑，多媚總無妝。", "坐缺初離席，簾垂卻入房。思惟不是夢，此會勝高唐。"]'),
('yuding-43','酬曹侍禦見寄','薛能','唐','御定全唐诗','yuding','','[]','儒道苦不勝，邇來惟慕禪。觸途非巧者，於世分沉然。',120,'御定全唐詩/json/558.json','["儒道苦不勝，邇來惟慕禪。觸途非巧者，於世分沉然。", "要地羞難入，閒居鈍更便。清和挑菜食，悶寂閉花眠。", "累遣期拋俸，機忘怕與權。妨春愁筦榷，響夜憶林泉。", "匪石從遭刖，珠膏枉被煎。討論唯子厚，藏退合吾先。", "舊制群英伏，來章六義全。休旬一擬和，鄉思亂情田。"]'),
('yuding-44','送趙道士歸天目舊山','薛能','唐','御定全唐诗','yuding','','[]','愚朴尚公平，此心鄰道情。有緣終自鄙，何計逐師行。',120,'御定全唐詩/json/558.json','["愚朴尚公平，此心鄰道情。有緣終自鄙，何計逐師行。", "日者聞高躅，時人蓋強名。口無滋味入，身有羽儀生。", "奏乞還鄉遠，詩曾對禦成。土毛珍到越，塵發倦離京。", "符叱風雷惡，朝修月露清。觀臨天目頂，家住海潮聲。", "道引圖看足，參同注解精。休糧一擬問，窗草俟回程。"]'),
('yuding-45','除夜作','薛能','唐','御定全唐诗','yuding','','[]','和吹度穹旻，虛徐接建寅。不辭加一歲，唯喜到三春。',120,'御定全唐詩/json/558.json','["和吹度穹旻，虛徐接建寅。不辭加一歲，唯喜到三春。", "燎照雲煙好，幡懸井邑新。禎祥應北極，調燮驗平津。", "樹欲含遲日，山將退舊塵。蘭萎殘此夜，竹爆和諸鄰。", "祝壽思明聖，驅儺看鬼神。團圓多少輩，眠寢獨勞筋。", "茜旆猶雙節，雕盤又五辛。何當平賊後，歸作自由身。"]'),
('yuding-46','桃花','薛能','唐','御定全唐诗','yuding','','[]','香色自天種，千年豈易逢。開齊全未落，繁極欲相重。',144,'御定全唐詩/json/558.json','["香色自天種，千年豈易逢。開齊全未落，繁極欲相重。", "冷濕朝如淡，晴幹午更濃。風光新社燕，時節舊春農。", "籬落欹臨竹，亭台盛間松。亂緣堪羨蟻，深入不如蜂。", "有影宜暄煦，無言自冶容。洞連非俗世，溪靜接仙蹤。", "子熟河應變，根盤土已封。西王潛愛惜，東朔盜過從。", "醉席眠英好，題詩戀景慵。芳菲聊一望，何必在臨邛。"]'),
('yuding-47','黃河','薛能','唐','御定全唐诗','yuding','','[]','何處發昆侖，連幹複浸坤。波渾經雁塞，聲振自龍門。',168,'御定全唐詩/json/558.json','["何處發昆侖，連幹複浸坤。波渾經雁塞，聲振自龍門。", "岸裂新沖勢，灘餘舊落痕。橫溝通海上，遠色盡山根。", "勇逗三峰坼，雄標四瀆尊。灣中秋景樹，闊外夕陽村。", "沫亂知魚呴，槎來見鳥蹲。飛沙當白日，凝霧接黃昏。", "潤可資農畝，清能表帝恩。雨吟堪極目，風度想驚魂。", "顯瑞龜曾出，陰靈伯固存。盤渦寒漸急，淺瀨暑微溫。", "九曲終柔勝，常流可暗吞。人間無博望，誰複到窮源。"]'),
('yuding-48','華岳','薛能','唐','御定全唐诗','yuding','','[]','簇簇複亭亭，三峰卓杳冥。每思窮本末，應合記圖經。',168,'御定全唐詩/json/558.json','["簇簇複亭亭，三峰卓杳冥。每思窮本末，應合記圖經。", "發地連宮觀，沖天接井星。河微臨巨勢，秦重載奇形。", "太古朝群後，中央擘巨靈。鄰州猶映檻，幾縣恰當庭。", "鶴毳壇風亂，龍漦洞水腥。望遙通北極，上徹見東溟。", "客玩晴難偶，農祈雨必零。度關無暑氣，過路得愁醒。", "羽客時應見，霜猿夜可聽。頂懸飛瀑峻，崦合白雲青。", "混石猜良玉，尋苗得茯苓。從官知側近，悉俸致岩扃。"]'),
('yuding-49','秋雨','薛能','唐','御定全唐诗','yuding','','[]','宿雨覺才初，亭林忽複徐。簇聲諸樹密，懸滴四簷疏。',168,'御定全唐詩/json/558.json','["宿雨覺才初，亭林忽複徐。簇聲諸樹密，懸滴四簷疏。", "省漏疑方丈，愁炊問鬥儲。步難多入屐，窗淺欲飄書。", "動蠖蒼苔靜，藏蠶落葉虛。吹交來翕習，雷慢歇躊躇。", "滯已妨行路，晴應好荷鋤。醉樓思蜀客，鯹市想淮魚。", "徑草因緣合，欄花自此除。有形皆霢霂，無地不汙瀦。", "境晦宜甘寢，風清□退居。我魂驚曉簟，鄰話喜秋蔬。", "既用功成歲，旋應慘變舒。倉箱足可恃，歸去傲吾廬。"]'),
('yuding-50','春色滿皇州','薛能','唐','御定全唐诗','yuding','','[]','藹藹複悠悠，春歸十二樓。最明雲裏闕，先滿日邊州。',72,'御定全唐詩/json/558.json','["藹藹複悠悠，春歸十二樓。最明雲裏闕，先滿日邊州。", "色媚青門外，光搖紫陌頭。上林榮舊樹，太液鏡新流。", "暖帶祥煙起，清添瑞景浮。陽和如啟蟄，從此事芳遊。"]'),
('yuding-51','寄唁張喬喻坦之','薛能','唐','御定全唐诗','yuding','','[]','何事盡參差，惜哉吾子詩。日令銷此道，天亦負明時。',48,'御定全唐詩/json/558.json','["何事盡參差，惜哉吾子詩。日令銷此道，天亦負明時。", "有路當重振，無門即不知。何當見堯日，相與啜澆漓。"]'),
('yuding-52','贈僧','薛能','唐','御定全唐诗','yuding','','[]','盡日行方到，何年獨此林。客歸惟鶴伴，人少似師心。',54,'御定全唐詩/json/558.json','["盡日行方到，何年獨此林。客歸惟鶴伴，人少似師心。", "坐石落松子，禪床搖竹陰。山靈怕驚定，不遣夜猿吟。", "知古齋主精校"]'),
('yuding-0','春日旅舍書懷','薛能','唐','御定全唐诗','yuding','','[]','出去歸來旅食人，麻衣長帶幾坊塵。開門草色朝無客，',40,'御定全唐詩/json/559.json','["出去歸來旅食人，麻衣長帶幾坊塵。開門草色朝無客，", "蹉跎冠蓋誰相念，二十年中盡苦辛。"]'),
('yuding-1','秋日將離滑台酬所知二首','薛能','唐','御定全唐诗','yuding','','[]','身起中宵骨亦驚，一分年少已無成。松吹竹簟朝眠冷，',80,'御定全唐詩/json/559.json','["身起中宵骨亦驚，一分年少已無成。松吹竹簟朝眠冷，", "相知莫話詩心苦，未似前賢取得名。", "燈澀秋光靜不眠，葉聲身影客窗前。閑園露濕鳴蛩夜，", "明朝欲別忘形處，愁把離杯聽管弦。"]'),
('yuding-2','下第後夷門乘舟至永城驛題','薛能','唐','御定全唐诗','yuding','','[]','秋賦春還計盡違，自知身是拙求知。唯思曠海為休處，',40,'御定全唐詩/json/559.json','["秋賦春還計盡違，自知身是拙求知。唯思曠海為休處，", "從來此恨皆前達，敢負吾君作楚辭。"]'),
('yuding-3','秋夜旅舍寓懷','薛能','唐','御定全唐诗','yuding','','[]','庭鎖荒蕪獨夜吟，西風吹動故山心。三秋木落半年客，',40,'御定全唐詩/json/559.json','["庭鎖荒蕪獨夜吟，西風吹動故山心。三秋木落半年客，", "平生只有松堪對，露浥霜欺不受侵。"]'),
('yuding-4','洛下寓懷','薛能','唐','御定全唐诗','yuding','','[]','胡為遭遇孰為官，朝野君親各自歡。敢向官途爭虎首，',40,'御定全唐詩/json/559.json','["胡為遭遇孰為官，朝野君親各自歡。敢向官途爭虎首，", "唯有報恩心未剖，退居猶欲佩芄蘭。"]'),
('yuding-5','題平湖','薛能','唐','御定全唐诗','yuding','','[]','平湖湖畔雨晴新，南北東西不隔塵。映野煙波浮動日，',40,'御定全唐詩/json/559.json','["平湖湖畔雨晴新，南北東西不隔塵。映野煙波浮動日，", "那得載來都未保，此心離此甚情親。"]'),
('yuding-6','平陽寓懷','薛能','唐','御定全唐诗','yuding','','[]','晉國風流阻洳川，家家弦管路岐邊。曾為郡職隨分竹，',40,'御定全唐詩/json/559.json','["晉國風流阻洳川，家家弦管路岐邊。曾為郡職隨分竹，", "牆花此日休回避，不是當時惡少年。"]'),
('yuding-7','留題汾上舊居','薛能','唐','御定全唐诗','yuding','','[]','鄉園一別五年歸，回首人間總禍機。尚勝鄰翁常寂寞，',40,'御定全唐詩/json/559.json','["鄉園一別五年歸，回首人間總禍機。尚勝鄰翁常寂寞，", "難說累牽還卻去，可憐榆柳尚依依。"]'),
('yuding-8','懷汾上舊居','薛能','唐','御定全唐诗','yuding','','[]','素汾千載傍吾家，常憶衡門對浣紗。好事喜逢投宿客，',40,'御定全唐詩/json/559.json','["素汾千載傍吾家，常憶衡門對浣紗。好事喜逢投宿客，", "投暗作珠何所用，被人專擬害靈蛇。"]'),
('yuding-9','送同儒大德歸柏梯寺','薛能','唐','御定全唐诗','yuding','','[]','柏梯還擬謝微官，遙擬千峰送法蘭。行徑未曾青石斷，',40,'御定全唐詩/json/559.json','["柏梯還擬謝微官，遙擬千峰送法蘭。行徑未曾青石斷，", "薇蕨縱多師莫踏，我心猶欲盡圖看。"]'),
('yuding-10','春日使府寓懷二首','薛能','唐','御定全唐诗','yuding','','[]','一想流年百事驚，已拋漁父戴塵纓。青春背我堂堂去，',80,'御定全唐詩/json/559.json','["一想流年百事驚，已拋漁父戴塵纓。青春背我堂堂去，", "誰憐合負清朝力，獨把風騷破鄭聲。", "平生無解亦無操，永日書生坐獨勞。唯覺宦情如水薄，", "何事故溪歸未得，幾拋清淺泛紅桃。"]'),
('yuding-11','許州題德星亭','薛能','唐','御定全唐诗','yuding','','[]','瀵水南流東有堤，堤邊亭是武陵溪。槎松配石堪僧坐，',40,'御定全唐詩/json/559.json','["瀵水南流東有堤，堤邊亭是武陵溪。槎松配石堪僧坐，", "頻來不似軍從事，只戴紗巾曳杖藜。"]'),
('yuding-12','送人歸上党','薛能','唐','御定全唐诗','yuding','','[]','燕台基壞穴狐蛇，計拙因循歲月賒。兵革未銷王在鎬，',40,'御定全唐詩/json/559.json','["燕台基壞穴狐蛇，計拙因循歲月賒。兵革未銷王在鎬，", "若到長平戰場地，為求遺鏃辟魔邪。"]'),
('yuding-13','春日重游平湖','薛能','唐','御定全唐诗','yuding','','[]','湖上春風發管弦，須臨三十此離筵。離人忽有重來日，',40,'御定全唐詩/json/559.json','["湖上春風發管弦，須臨三十此離筵。離人忽有重來日，", "啼鶯莫惜蹉跎恨，閒事聽吟一兩篇。"]'),
('yuding-14','並州','薛能','唐','御定全唐诗','yuding','','[]','少年流落在並州，裘脫文君取次遊。攜挈共過芳草渡，',40,'御定全唐詩/json/559.json','["少年流落在並州，裘脫文君取次遊。攜挈共過芳草渡，", "坊號偃松人在否，餅爐南畔曲西頭。"]'),
('yuding-15','相國隴西公南征，能以留務獨宿府城作','薛能','唐','御定全唐诗','yuding','','[]','吾君賢相事南征，獨宿軍廚負請纓。燈室臥孤如怨別，',40,'御定全唐詩/json/559.json','["吾君賢相事南征，獨宿軍廚負請纓。燈室臥孤如怨別，", "殊憶好僧招不及，夜來倉卒鎖嚴城。"]'),
('yuding-16','早春書事','薛能','唐','御定全唐诗','yuding','','[]','百蠻降伏委三秦，錦裏風回歲已新。渠濫水泉花巷濕，',40,'御定全唐詩/json/559.json','["百蠻降伏委三秦，錦裏風回歲已新。渠濫水泉花巷濕，", "焚卻蜀書宜不讀，武侯無可律餘身。"]'),
('yuding-17','春日書懷','薛能','唐','御定全唐诗','yuding','','[]','伯牙琴絕豈求知，往往情牽自有詩。壟月正當寒食夜，',40,'御定全唐詩/json/559.json','["伯牙琴絕豈求知，往往情牽自有詩。壟月正當寒食夜，", "多病不任衣更薄，東風臺上莫相吹。"]'),
('yuding-18','投杜舍人','薛能','唐','御定全唐诗','yuding','','[]','床上新詩詔草和，欄邊清酒落花多。閑消白日舍人宿，',40,'御定全唐詩/json/559.json','["床上新詩詔草和，欄邊清酒落花多。閑消白日舍人宿，", "風騷委地苦無主，此事聖君終若何。"]'),
('yuding-19','獻僕射相公','薛能','唐','御定全唐诗','yuding','','[]','清如冰雪重如山，百辟嚴趨禮絕攀。強虜外聞應喪膽，',40,'御定全唐詩/json/559.json','["清如冰雪重如山，百辟嚴趨禮絕攀。強虜外聞應喪膽，", "致卻垂衣更何事，幾多詩句詠關關。"]'),
('yuding-20','上鹽鐵尚書','薛能','唐','御定全唐诗','yuding','','[]','南宮環雉隔囂塵，況值清齋宿大臣。城絕鼓鐘更點後，',40,'御定全唐詩/json/559.json','["南宮環雉隔囂塵，況值清齋宿大臣。城絕鼓鐘更點後，", "聞說務閒心更靜，此時憂國合求人。"]'),
('yuding-21','漢南春望','薛能','唐','御定全唐诗','yuding','','[]','獨尋春色上高臺，三月皇州駕未回。幾處松筠燒後死，',40,'御定全唐詩/json/559.json','["獨尋春色上高臺，三月皇州駕未回。幾處松筠燒後死，", "自古浮雲蔽白日，洗天風雨幾時來。"]'),
('yuding-22','晚春','薛能','唐','御定全唐诗','yuding','','[]','惡憐風景極交親，每恨年年作瘦人。臥晚不曾拋好夜，',40,'御定全唐詩/json/559.json','["惡憐風景極交親，每恨年年作瘦人。臥晚不曾拋好夜，", "無限後期知有在，只愁煩作總戎身。"]'),
('yuding-23','將赴鎮過太康縣有題','薛能','唐','御定全唐诗','yuding','','[]','才入東郊便太康，自聽何暮豈龔黃。晴村透日桑榆影，',40,'御定全唐詩/json/559.json','["才入東郊便太康，自聽何暮豈龔黃。晴村透日桑榆影，", "時人欲識征東將，看取欃槍落太荒。"]'),
('yuding-24','彭門解嘲二首','薛能','唐','御定全唐诗','yuding','','[]','嗚嗚吹角貳師營，落日身閑笑傲行。盡覺文章尊萬事，',80,'御定全唐詩/json/559.json','["嗚嗚吹角貳師營，落日身閑笑傲行。盡覺文章尊萬事，", "頻上水樓誰會我，泗濱浮磬是同聲。", "傷禽棲後意猶驚，偶向黐竿脫此生。身外不思簪組事，", "秦客莫嘲瓜戍遠，水風瀟灑是彭城。"]'),
('yuding-25','清河泛舟','薛能','唐','御定全唐诗','yuding','','[]','都人層立似山丘，坐嘯將軍擁棹游。繞郭煙波浮泗水，',40,'御定全唐詩/json/559.json','["都人層立似山丘，坐嘯將軍擁棹游。繞郭煙波浮泗水，", "儒將不須誇郤縠，未聞詩句解風流。"]'),
('yuding-26','新竹','薛能','唐','御定全唐诗','yuding','','[]','柳營茅土倦粗材，因向山家乞翠栽。清露便教終夜滴，',40,'御定全唐詩/json/559.json','["柳營茅土倦粗材，因向山家乞翠栽。清露便教終夜滴，", "他日會應威鳳至，莫辭公府受塵埃。"]'),
('yuding-27','晚春','薛能','唐','御定全唐诗','yuding','','[]','征東留滯一年年，又向軍前遇火前。畫出鷁舟宜祓禊，',40,'御定全唐詩/json/559.json','["征東留滯一年年，又向軍前遇火前。畫出鷁舟宜祓禊，", "賴指清和櫻筍熟，不然愁殺暮春天。"]'),
('yuding-28','題彭祖樓','薛能','唐','御定全唐诗','yuding','','[]','新晴天狀濕融融，徐國灘聲上下洪。極目澄鮮無限景，',40,'御定全唐詩/json/559.json','["新晴天狀濕融融，徐國灘聲上下洪。極目澄鮮無限景，", "誰致此樓潛惠我，萬家殘照在河東。"]'),
('yuding-29','漢廟祈雨回陽春亭有懷','薛能','唐','御定全唐诗','yuding','','[]','南榮軒檻接城闉，適罷祈農此訪春。九九已從南至盡，',40,'御定全唐詩/json/559.json','["南榮軒檻接城闉，適罷祈農此訪春。九九已從南至盡，", "欲召羅敷傾一盞，乘閑言語不容人。"]'),
('yuding-30','送李倍秀才','薛能','唐','御定全唐诗','yuding','','[]','南朝才子尚途窮，畢竟應須問葉公。書劍伴身離泗上，',40,'御定全唐詩/json/559.json','["南朝才子尚途窮，畢竟應須問葉公。書劍伴身離泗上，", "相顧日偏留不得，夜深聊欲一杯同。"]'),
('yuding-31','重遊德星亭感事','薛能','唐','御定全唐诗','yuding','','[]','潁水川中枕水台，當時離別此重來。舟沉土岸生新草，',40,'御定全唐詩/json/559.json','["潁水川中枕水台，當時離別此重來。舟沉土岸生新草，", "殘陽照樹明於旭，猶向池邊把酒杯。"]'),
('yuding-32','許州題觀察判官廳','薛能','唐','御定全唐诗','yuding','','[]','三載從戎類系匏，重游全許尚分茅。劉郎別後無遺履，',40,'御定全唐詩/json/559.json','["三載從戎類系匏，重游全許尚分茅。劉郎別後無遺履，", "纖腰弟子知千恨，笑與揚雄作解嘲。"]'),
('yuding-33','閑題','薛能','唐','御定全唐诗','yuding','','[]','八年藩翰似僑居，只此誰知報玉除。舊將已成三僕射，',40,'御定全唐詩/json/559.json','["八年藩翰似僑居，只此誰知報玉除。舊將已成三僕射，", "為問春風誰是主，空催弱柳擬何如。"]'),
('yuding-34','送福建李大夫','薛能','唐','御定全唐诗','yuding','','[]','洛州良牧帥甌閩，曾是西垣作諫臣。紅旆已勝前尹正，',40,'御定全唐詩/json/559.json','["洛州良牧帥甌閩，曾是西垣作諫臣。紅旆已勝前尹正，", "行過小藩應大笑，只知誇近不知貧。"]'),
('yuding-35','送李倍巡官歸永樂舊居','薛能','唐','御定全唐诗','yuding','','[]','羨君歸去五峰前，往往星河實見仙。麥壟夏枯成廢地，',40,'御定全唐詩/json/559.json','["羨君歸去五峰前，往往星河實見仙。麥壟夏枯成廢地，", "曾約道門終老住，步虛聲裏寄閑眠。"]'),
('yuding-36','贈歌者','薛能','唐','御定全唐诗','yuding','','[]','一字新聲一顆珠，轉喉疑是擊珊瑚。聽時坐部音中有，',40,'御定全唐詩/json/559.json','["一字新聲一顆珠，轉喉疑是擊珊瑚。聽時坐部音中有，", "誰人得向青樓宿，便是仙郎不是夫。"]'),
('yuding-37','舞者','薛能','唐','御定全唐诗','yuding','','[]','綠毛釵動小相思，一唱南軒日午時。慢靸輕裾行欲近，',40,'御定全唐詩/json/559.json','["綠毛釵動小相思，一唱南軒日午時。慢靸輕裾行欲近，", "為問傾城年幾許，更勝瓊樹是瓊枝。"]'),
('yuding-38','天際識歸舟','薛能','唐','御定全唐诗','yuding','','[]','斜日滿江樓，天涯照背流。同人在何處，遠目認孤舟。',72,'御定全唐詩/json/559.json','["斜日滿江樓，天涯照背流。同人在何處，遠目認孤舟。", "帆省當時席，歌聲舊日謳。人浮津濟晚，棹倚泬寥秋。", "晴闊忻全見，歸遲怪久遊。離居意無限，貪此望難休。"]'),
('yuding-39','和曹侍禦除夜有懷','薛能','唐','御定全唐诗','yuding','','[]','有病無媒客，多慵亦太疏。自憐成叔夜，誰與薦相如。',120,'御定全唐詩/json/559.json','["有病無媒客，多慵亦太疏。自憐成叔夜，誰與薦相如。", "嗜退思年老，諳空笑歲除。跡閑過寺宿，頭暖近階梳。", "春立窮冬後，陽生舊物初。葉多庭不掃，根在徑新鋤。", "田事終歸彼，心情倦老於。斫材須見像，藏劍豈為魚。", "效淺慚尹祿，恩多負辟書。酬知必擬共，勿使浪躊躇。"]'),
('yuding-40','華清宮和杜舍人','薛能','唐','御定全唐诗','yuding','','[]','五十年天子，離宮仰峻牆。登封時正泰，禦宇日何長。',360,'御定全唐詩/json/559.json','["五十年天子，離宮仰峻牆。登封時正泰，禦宇日何長。", "上位先名實，中興事憲章。起戎輕甲胄，餘地複河湟。", "道降玄元祖，儒封孔子王。因緣百司署，聚會一人湯。", "渭水波搖綠，秦山草半黃。馬馴金勒細，鷹健玉鈴鏘。", "下箭朱方滿，鳴鞭皓腕攘。畋思獲呂望，諫只避周昌。", "兔跡貪前逐，梟心不早防。幾添鸚鵡勸，先賜荔枝嘗。", "月鎖千門靜，天吹一笛涼。細音搖羽佩，輕步宛霓裳。", "禍亂基潛結，升平意遽忘。衣冠逃犬虜，鼙鼓動漁陽。", "外戚心殊迫，中原事可量。血埋妃子豔，刃斷祿兒腸。", "近侍煙塵隔，前蹤輦路荒。益知迷寵佞，遺恨喪賢良。", "北闕尊明主，南宮遜上皇。禁清餘鳳吹，池冷睡龍光。", "祝壽山猶在，流年水共傷。杜鵑魂厭蜀，蝴蝶夢悲莊。", "雀卵遺雕栱，蟲絲罥畫梁。紫苔侵壁潤，紅樹閉門芳。", "守吏齊鴛瓦，耕民得翠璫。登年昔酺樂，講武舊兵場。", "暮草深岩翠，幽花墜徑香。不堪垂白叟，行折禦溝楊。"]'),
('yuding-41','送浙東王大夫','薛能','唐','御定全唐诗','yuding','','[]','天爵擅忠貞，皇恩複寵榮。遠源過晉史，甲族本緱笙。',264,'御定全唐詩/json/559.json','["天爵擅忠貞，皇恩複寵榮。遠源過晉史，甲族本緱笙。", "亞相兼尤美，周行歷盡清。制除天近曉，衙謝草初生。", "賓客招閑地，戎裝擁上京。九街鳴玉勒，一宅照紅旌。", "細雨當離席，遙花顯去程。佩刀畿甸色，歌吹館橋聲。", "騕褭從秦賜，艅艎到汴迎。步沙逢霽月，宿岸致嚴更。", "渤澥流東鄙，天臺壓屬城。眾談稱重鎮，公意念疲甿。", "井邑曾多難，瘡痍此未平。察應均賦斂，逃必複桑耕。", "隼重權兼帥，鼉雄設有兵。越台隨厚俸，剡硾得尤名。", "夜蠟州中宴，春風部外行。香奩扃鳳詔，朱篆動龍坑。", "報後功何患，投虛論素精。征還真指掌，感激自關情。", "舊業懷昏作，微班負旦評。空餘騷雅事，千古傲劉楨。"]'),
('yuding-42','送李殷游京西','薛能','唐','御定全唐诗','yuding','','[]','立馬送君地，黯然愁到身。萬途皆有匠，六義獨無人。',120,'御定全唐詩/json/559.json','["立馬送君地，黯然愁到身。萬途皆有匠，六義獨無人。", "莫怪敢言此，已能甘世貧。時來貴亦在，事是掩何因。", "投刺皆羈旅，游邊更苦辛。岐山終蜀境，涇水複蠻塵。", "埋沒餐須強，炎蒸醉莫頻。俗徒欺合得，吾道死終新。", "展分先難許，論詩永共親。歸京稍作意，充斥犯西鄰。"]'),
('yuding-43','長安送友人之黔南','薛能','唐','御定全唐诗','yuding','','[]','衡嶽猶雲過，君家獨幾千。心從賤遊話，分向禁城偏。',96,'御定全唐詩/json/559.json','["衡嶽猶雲過，君家獨幾千。心從賤遊話，分向禁城偏。", "陸路終何處，三湘在素船。琴書去迢遞，星路照潺湲。", "台鏡簪秋晚，盤蔬飯雨天。同文到鄉盡，殊國共行連。", "後會應多日，歸程自一年。貧交永無忘，孤進合相憐。"]'),
('yuding-44','寄李頻','薛能','唐','御定全唐诗','yuding','','[]','長安千萬蹊，迷者自多迷。直性身難達，良時日易低。',48,'御定全唐詩/json/559.json','["長安千萬蹊，迷者自多迷。直性身難達，良時日易低。", "環簷消舊雪，晴氣滿春泥。那得同君去，逢峰苦愛齊。"]'),
('yuding-45','贈苗端公二首','薛能','唐','御定全唐诗','yuding','','[]','繁總近何如，君才必有餘。身歡步兵酒，吏寫魯連書。',96,'御定全唐詩/json/559.json','["繁總近何如，君才必有餘。身歡步兵酒，吏寫魯連書。", "坐默聞鼙吹，庭班見雪初。沉碑若果去，一為訪鄰居。", "至老不相疏，斯言不是虛。兩心宜一體，同舍又鄰居。", "曉角秋砧外，清雲白月初。從軍何有用，未造魯連書。"]'),
('yuding-46','寄河南鄭侍郎','薛能','唐','御定全唐诗','yuding','','[]','三峽與三壕，門闌夢去勞。細冰和洛水，初雪灑嵩高。',48,'御定全唐詩/json/559.json','["三峽與三壕，門闌夢去勞。細冰和洛水，初雪灑嵩高。", "大雅何由接，微榮亦已逃。寒窗不可寐，風地葉蕭騷。"]'),
('yuding-47','蒙恩除侍御史行次華州寄蔣相','薛能','唐','御定全唐诗','yuding','','[]','林下天書起遁逃，不堪移疾入塵勞。黃河近岸陰風急，',40,'御定全唐詩/json/559.json','["林下天書起遁逃，不堪移疾入塵勞。黃河近岸陰風急，", "荀家位極兼禪理，應笑埋輪著所操。"]'),
('yuding-48','寄唐州楊郎中','薛能','唐','御定全唐诗','yuding','','[]','關睢憔悴一儒生，忽把魚須事聖明。貧得俸錢還乍喜，',40,'御定全唐詩/json/559.json','["關睢憔悴一儒生，忽把魚須事聖明。貧得俸錢還乍喜，", "班列道孤君不見，曲江春暖共僧行。"]'),
('yuding-49','塞上蒙汝州任中丞寄書','薛能','唐','御定全唐诗','yuding','','[]','三省推賢兩掖才，關東深許稍遲回。舟浮汝水通淮去，',40,'御定全唐詩/json/559.json','["三省推賢兩掖才，關東深許稍遲回。舟浮汝水通淮去，", "西樓一望知無極，更與何人把酒杯。"]'),
('yuding-50','題鹽鐵李尚書滻州別業','薛能','唐','御定全唐诗','yuding','','[]','鹿原陰面滻州湄，坐覺林泉逼夢思。閑景院開花落後，',40,'御定全唐詩/json/559.json','["鹿原陰面滻州湄，坐覺林泉逼夢思。閑景院開花落後，", "備足好中還有闕，許昌軍裏李陵詩。"]'),
('yuding-0','送劉駕歸京','薛能','唐','御定全唐诗','yuding','','[]','相逢聽一吟，惟我不降心。在世憂何事，前生得至音。',48,'御定全唐詩/json/560.json','["相逢聽一吟，惟我不降心。在世憂何事，前生得至音。", "蒲多南去遠，汾盡北遊深。為宿關亭日，蒼蒼曉欲臨。"]'),
('yuding-1','夏日寺中有懷','薛能','唐','御定全唐诗','yuding','','[]','亭午四鄰睡，院中唯鳥鳴。當門塞鴻去，欹枕世人情。',48,'御定全唐詩/json/560.json','["亭午四鄰睡，院中唯鳥鳴。當門塞鴻去，欹枕世人情。", "地燥蒼苔裂，天涼晚月生。歸家豈不願，辛苦未知名。"]'),
('yuding-2','夏日蒲津寺居二首','薛能','唐','御定全唐诗','yuding','','[]','日日閑車馬，誰來訪此身。一門兼鶴靜，四院與僧鄰。',96,'御定全唐詩/json/560.json','["日日閑車馬，誰來訪此身。一門兼鶴靜，四院與僧鄰。", "雨室牆穿溜，風窗筆染塵。空餘氣長在，天子用平人。", "故國有如夢，省來長遠遊。清晨起閑院，疏雨似深秋。", "宿寢書棱疊，行吟杖跡稠。天晴豈能出，春暖未更裘。"]'),
('yuding-3','北都題崇福寺','薛能','唐','御定全唐诗','yuding','','[]','此地潛龍寺，何基即帝台。細花庭樹蔭，清氣殿門開。',48,'御定全唐詩/json/560.json','["此地潛龍寺，何基即帝台。細花庭樹蔭，清氣殿門開。", "長老多相識，旬休暫一來。空空亦擬解，幹進幸無媒。"]'),
('yuding-4','題龍興寺','薛能','唐','御定全唐诗','yuding','','[]','高戶列禪房，松門到上方。像開祇樹嶺，人施蜀城香。',48,'御定全唐詩/json/560.json','["高戶列禪房，松門到上方。像開祇樹嶺，人施蜀城香。", "地遍磷磷石，江移孑孑檣。林僧語不盡，身役事梁王。"]'),
('yuding-5','題大雲寺西閣','薛能','唐','御定全唐诗','yuding','','[]','閣臨偏險寺當山，獨坐西城笑滿顏。四野有歌行路樂，',40,'御定全唐詩/json/560.json','["閣臨偏險寺當山，獨坐西城笑滿顏。四野有歌行路樂，", "方擬殺身酬聖主，敢於高處戀鄉關。"]'),
('yuding-6','舟行至平羌','薛能','唐','御定全唐诗','yuding','','[]','貔虎直沙壖，嚴更護早眠。簇霜孤驛樹，落日下江船。',48,'御定全唐詩/json/560.json','["貔虎直沙壖，嚴更護早眠。簇霜孤驛樹，落日下江船。", "暫去非吳起，終休愛魯連。平羌無一術，候吏莫加籩。"]'),
('yuding-7','題開元寺閣','薛能','唐','御定全唐诗','yuding','','[]','一閣見一郡，亂流仍亂山。未能終日住，尤愛暫時閑。',48,'御定全唐詩/json/560.json','["一閣見一郡，亂流仍亂山。未能終日住，尤愛暫時閑。", "唱棹吳門去，啼林杜宇還。高僧不可羨，西景掩禪關。"]'),
('yuding-8','淩雲寺','薛能','唐','御定全唐诗','yuding','','[]','像閣與山齊，何人致石梯。萬煙生聚落，一崦露招提。',48,'御定全唐詩/json/560.json','["像閣與山齊，何人致石梯。萬煙生聚落，一崦露招提。", "齋月人來上，殘陽鴿去棲。從邊亦已極，烽火是沈黎。"]'),
('yuding-9','石堂溪','薛能','唐','御定全唐诗','yuding','','[]','三面接漁樵，前門向郡橋。岸沙崩橘樹，山徑入茶苗。',48,'御定全唐詩/json/560.json','["三面接漁樵，前門向郡橋。岸沙崩橘樹，山徑入茶苗。", "夜擁軍煙合，春浮妓舸邀。此心無與醉，花影莫相燒。"]'),
('yuding-10','荔枝樓','薛能','唐','御定全唐诗','yuding','','[]','高檻起邊愁，荔枝誰致樓。會須教匠坼，不欲見蠻陬。',48,'御定全唐詩/json/560.json','["高檻起邊愁，荔枝誰致樓。會須教匠坼，不欲見蠻陬。", "樹痹無春影，天連覺漢流。仲宣如可擬，即此是荊州。"]'),
('yuding-11','聖岡','薛能','唐','御定全唐诗','yuding','','[]','古跡是何王，平身入石房。遠村通後徑，一郡隔前岡。',48,'御定全唐詩/json/560.json','["古跡是何王，平身入石房。遠村通後徑，一郡隔前岡。", "晝靜唯禪客，春來有女郎。獨醒回不得，無事可焚香。"]'),
('yuding-12','蜀州鄭史君寄鳥觜茶，因以贈答八韻','薛能','唐','御定全唐诗','yuding','','[]','鳥觜擷渾牙，精靈勝鏌鋣。烹嘗方帶酒，滋味更無茶。',96,'御定全唐詩/json/560.json','["鳥觜擷渾牙，精靈勝鏌鋣。烹嘗方帶酒，滋味更無茶。", "拒碾幹聲細，撐封利穎斜。銜蘆齊勁實，啄木聚菁華。", "鹽損添常誡，薑宜著更誇。得來拋道藥，攜去就僧家。", "旋覺前甌淺，還愁後信賒。千慚故人意，此惠敵丹砂。"]'),
('yuding-13','暇日寓懷寄朝中親友','薛能','唐','御定全唐诗','yuding','','[]','命與才違豈自由，我身何負我身愁。臨生白髮方監郡，',40,'御定全唐詩/json/560.json','["命與才違豈自由，我身何負我身愁。臨生白髮方監郡，", "閑吟一寄清朝侶，未必淮陰不拜侯。"]'),
('yuding-14','春日寓懷','薛能','唐','御定全唐诗','yuding','','[]','幽拙未謀身，無端患不均。盜憎猶念物，花盡不知春。',48,'御定全唐詩/json/560.json','["幽拙未謀身，無端患不均。盜憎猶念物，花盡不知春。", "井邑常多弊，江山豈有神。犍為何處在，一擬吊埋輪。"]'),
('yuding-15','監郡犍為舟中寓題寄同舍','薛能','唐','御定全唐诗','yuding','','[]','一寢閑身萬事空，任天教作假文翁。旗穿島樹孤舟上，',40,'御定全唐詩/json/560.json','["一寢閑身萬事空，任天教作假文翁。旗穿島樹孤舟上，", "佳期說盡君應笑，劉表尊前且不同。"]'),
('yuding-16','江柳','薛能','唐','御定全唐诗','yuding','','[]','條綠似垂纓，離筵日照輕。向人雖有態，傷我為無情。',48,'御定全唐詩/json/560.json','["條綠似垂纓，離筵日照輕。向人雖有態，傷我為無情。", "橋遠孤臨水，牆低半出營。天津曾此見，亦是愴行行。"]'),
('yuding-17','寄吉諫議','薛能','唐','御定全唐诗','yuding','','[]','將迎須學返抽身，合致蹉跎敢效顰。性靜擬歸無上士，',40,'御定全唐詩/json/560.json','["將迎須學返抽身，合致蹉跎敢效顰。性靜擬歸無上士，", "聞說舊交賢且達，欲彈章甫自羞貧。"]'),
('yuding-18','江上寄情','薛能','唐','御定全唐诗','yuding','','[]','天際歸舟浩蕩中，我關王澤道何窮。未為時彥徒經國，',40,'御定全唐詩/json/560.json','["天際歸舟浩蕩中，我關王澤道何窮。未為時彥徒經國，", "年來斷定知休處，一樹繁花一畝宮。"]'),
('yuding-19','平蓋觀','薛能','唐','御定全唐诗','yuding','','[]','巨柏與山高，玄門靜有猱。春風開野杏，落日照江濤。',48,'御定全唐詩/json/560.json','["巨柏與山高，玄門靜有猱。春風開野杏，落日照江濤。", "白璧心難說，青雲世未遭。天涯望不極，誰識詠離騷。"]'),
('yuding-20','春霽','薛能','唐','御定全唐诗','yuding','','[]','久客孤舟上，天涯漱曉津。野芳榿似柳，江霽雪和春。',48,'御定全唐詩/json/560.json','["久客孤舟上，天涯漱曉津。野芳榿似柳，江霽雪和春。", "吏叫能驚鷺，官粗實害身。何當窮蜀境，卻憶滯遊人。"]'),
('yuding-21','春居即事','薛能','唐','御定全唐诗','yuding','','[]','雲密露晨暉，西園獨掩扉。雨新臨斷火，春冷著單衣。',48,'御定全唐詩/json/560.json','["雲密露晨暉，西園獨掩扉。雨新臨斷火，春冷著單衣。", "榆莢奔風健，蘭芽負土肥。交親不是變，自作寄書稀。"]');
